UPDATE words SET example_en_2 = 'Can I talk to you after class?', example_ko_2 = '수업 후에 이야기할 수 있을까요?', example_en_3 = 'She will talk about her trip.', example_ko_3 = '그녀는 여행에 대해 이야기할 거예요.', example_en_4 = 'He loves to talk in front of people.', example_ko_4 = '그는 사람들 앞에서 말하는 걸 좋아해요.', example_en_5 = 'We will talk about the results now.', example_ko_5 = '지금 결과에 대해 이야기하겠습니다.' WHERE id = 'w_presentation_A1_01';
UPDATE words SET example_en_2 = 'Let me show you the next slide.', example_ko_2 = '다음 슬라이드를 보여드리겠습니다.', example_en_3 = 'Can you show me the chart again?', example_ko_3 = '차트를 다시 보여주실 수 있나요?', example_en_4 = 'I will show a short video now.', example_ko_4 = '이제 짧은 영상을 보여드리겠습니다.', example_en_5 = 'She showed us the final results.', example_ko_5 = '그녀가 우리에게 최종 결과를 보여줬어요.' WHERE id = 'w_presentation_A1_02';
UPDATE words SET example_en_2 = 'I will tell you more in a moment.', example_ko_2 = '잠시 후에 더 말씀드리겠습니다.', example_en_3 = 'Can you tell us your name?', example_ko_3 = '이름을 말씀해 주시겠어요?', example_en_4 = 'Tell me what you think.', example_ko_4 = '어떻게 생각하시는지 말씀해 주세요.', example_en_5 = 'He told the audience a short story.', example_ko_5 = '그는 청중에게 짧은 이야기를 해줬어요.' WHERE id = 'w_presentation_A1_03';
UPDATE words SET example_en_2 = 'We start every meeting with a review.', example_ko_2 = '우리는 모든 회의를 복습으로 시작해요.', example_en_3 = 'Please start your talk when ready.', example_ko_3 = '준비되시면 발표를 시작해 주세요.', example_en_4 = 'She started by introducing herself.', example_ko_4 = '그녀는 자기소개로 시작했어요.', example_en_5 = 'Let us start with the first slide.', example_ko_5 = '첫 번째 슬라이드부터 시작하겠습니다.' WHERE id = 'w_presentation_A1_04';
UPDATE words SET example_en_2 = 'We will end with a short Q&A.', example_ko_2 = '짧은 질의응답으로 마무리하겠습니다.', example_en_3 = 'The meeting ends at noon.', example_ko_3 = '회의는 정오에 끝나요.', example_en_4 = 'Please end your talk on time.', example_ko_4 = '발표를 제시간에 마무리해 주세요.', example_en_5 = 'How do you plan to end the session?', example_ko_5 = '세션을 어떻게 마무리할 계획인가요?' WHERE id = 'w_presentation_A1_05';
UPDATE words SET example_en_2 = 'First, I want to thank everyone here.', example_ko_2 = '먼저, 여기 계신 모든 분께 감사드리고 싶습니다.', example_en_3 = 'First, let us look at the problem.', example_ko_3 = '먼저 문제를 살펴보겠습니다.', example_en_4 = 'First, check the data carefully.', example_ko_4 = '먼저 데이터를 꼼꼼히 확인하세요.', example_en_5 = 'First, I will give a short overview.', example_ko_5 = '먼저 간단한 개요를 드리겠습니다.' WHERE id = 'w_presentation_A1_06';
UPDATE words SET example_en_2 = 'Next, we will look at the data.', example_ko_2 = '다음으로 데이터를 살펴보겠습니다.', example_en_3 = 'What should we do next?', example_ko_3 = '다음에 무엇을 해야 할까요?', example_en_4 = 'Next, please turn to page two.', example_ko_4 = '다음으로 2페이지로 넘어가 주세요.', example_en_5 = 'Next, I will explain the solution.', example_ko_5 = '다음으로 해결책을 설명하겠습니다.' WHERE id = 'w_presentation_A1_07';
UPDATE words SET example_en_2 = 'The last slide has the key takeaways.', example_ko_2 = '마지막 슬라이드에 핵심 내용이 있습니다.', example_en_3 = 'This is the last topic for today.', example_ko_3 = '오늘의 마지막 주제입니다.', example_en_4 = 'Last week''s data shows a big change.', example_ko_4 = '지난주 데이터가 큰 변화를 보여줍니다.', example_en_5 = 'This is my last point before questions.', example_ko_5 = '질문 전 제 마지막 요점입니다.' WHERE id = 'w_presentation_A1_08';
UPDATE words SET example_en_2 = 'This slide shows our sales numbers.', example_ko_2 = '이 슬라이드는 우리의 매출 수치를 보여줍니다.', example_en_3 = 'Can you move to the next slide?', example_ko_3 = '다음 슬라이드로 넘어가 주실 수 있나요?', example_en_4 = 'The slide has a chart and some text.', example_ko_4 = '슬라이드에 차트와 텍스트가 있습니다.', example_en_5 = 'Please keep each slide simple and clear.', example_ko_5 = '각 슬라이드를 간단하고 명확하게 유지해 주세요.' WHERE id = 'w_presentation_A1_09';
UPDATE words SET example_en_2 = 'I have three points to make today.', example_ko_2 = '오늘 말씀드릴 요점이 세 가지 있습니다.', example_en_3 = 'Can you explain that point again?', example_ko_3 = '그 요점을 다시 설명해 주실 수 있나요?', example_en_4 = 'That is a very good point.', example_ko_4 = '그것은 매우 좋은 요점입니다.', example_en_5 = 'The key point is on this slide.', example_ko_5 = '핵심 요점이 이 슬라이드에 있습니다.' WHERE id = 'w_presentation_A1_10';
UPDATE words SET example_en_2 = 'That is a good question, thank you.', example_ko_2 = '좋은 질문이에요, 감사합니다.', example_en_3 = 'She gave a good presentation today.', example_ko_3 = '그녀는 오늘 좋은 발표를 했어요.', example_en_4 = 'It is good to practice every day.', example_ko_4 = '매일 연습하는 것은 좋아요.', example_en_5 = 'Good morning, everyone. Let us begin.', example_ko_5 = '좋은 아침이에요, 여러분. 시작하겠습니다.' WHERE id = 'w_presentation_A1_11';
UPDATE words SET example_en_2 = 'Today I will talk about our new plan.', example_ko_2 = '오늘 우리의 새로운 계획에 대해 이야기하겠습니다.', example_en_3 = 'Today''s topic is very important.', example_ko_3 = '오늘의 주제는 매우 중요합니다.', example_en_4 = 'What did you learn today?', example_ko_4 = '오늘 무엇을 배웠나요?', example_en_5 = 'Today, let us focus on communication.', example_ko_5 = '오늘은 의사소통에 집중해 보겠습니다.' WHERE id = 'w_presentation_A1_12';
UPDATE words SET example_en_2 = 'Here are three reasons for this change.', example_ko_2 = '이 변화에 대한 세 가지 이유가 여기 있습니다.', example_en_3 = 'Please look here for more details.', example_ko_3 = '더 자세한 내용은 여기를 봐주세요.', example_en_4 = 'Here is our plan for next quarter.', example_ko_4 = '다음 분기 계획이 여기 있습니다.', example_en_5 = 'Here we can see the total numbers.', example_ko_5 = '여기서 총 수치를 볼 수 있습니다.' WHERE id = 'w_presentation_A1_13';
UPDATE words SET example_en_2 = 'Look at how the numbers changed.', example_ko_2 = '숫자가 어떻게 변했는지 보세요.', example_en_3 = 'Please look at the graph on the right.', example_ko_3 = '오른쪽 그래프를 봐주세요.', example_en_4 = 'Look at this example carefully.', example_ko_4 = '이 예시를 주의 깊게 보세요.', example_en_5 = 'Look at the trend over five years.', example_ko_5 = '5년간의 추세를 봐주세요.' WHERE id = 'w_presentation_A1_14';
UPDATE words SET example_en_2 = 'As you can see, sales went up.', example_ko_2 = '보시다시피 매출이 올랐습니다.', example_en_3 = 'I see. That makes sense now.', example_ko_3 = '이해했어요. 이제 말이 되네요.', example_en_4 = 'You can see the results on this slide.', example_ko_4 = '이 슬라이드에서 결과를 볼 수 있습니다.', example_en_5 = 'Do you see any pattern in this data?', example_ko_5 = '이 데이터에서 패턴이 보이나요?' WHERE id = 'w_presentation_A1_15';
UPDATE words SET example_en_2 = 'Do you know how many users we have?', example_ko_2 = '우리가 사용자를 얼마나 보유하고 있는지 아시나요?', example_en_3 = 'I know this topic very well.', example_ko_3 = '이 주제를 매우 잘 알고 있어요.', example_en_4 = 'Let me know if you have questions.', example_ko_4 = '질문이 있으시면 알려주세요.', example_en_5 = 'You may know this chart already.', example_ko_5 = '이 차트를 이미 알고 계실 수도 있어요.' WHERE id = 'w_presentation_A1_16';
UPDATE words SET example_en_2 = 'I hope this slide helps clarify things.', example_ko_2 = '이 슬라이드가 이해에 도움이 되길 바랍니다.', example_en_3 = 'These notes will help you study later.', example_ko_3 = '이 노트가 나중에 공부하는 데 도움이 될 거예요.', example_en_4 = 'Can I help you with the projector?', example_ko_4 = '프로젝터 도움이 필요하신가요?', example_en_5 = 'A simple example will help explain this.', example_ko_5 = '간단한 예시가 이것을 설명하는 데 도움이 될 거예요.' WHERE id = 'w_presentation_A1_17';
UPDATE words SET example_en_2 = 'I think the second option is better.', example_ko_2 = '두 번째 옵션이 더 낫다고 생각해요.', example_en_3 = 'What do you think about this idea?', example_ko_3 = '이 아이디어에 대해 어떻게 생각하세요?', example_en_4 = 'I think we need more data first.', example_ko_4 = '먼저 데이터가 더 필요하다고 생각해요.', example_en_5 = 'Think about what this means for us.', example_ko_5 = '이것이 우리에게 무엇을 의미하는지 생각해 보세요.' WHERE id = 'w_presentation_A1_18';
UPDATE words SET example_en_2 = 'This chart means we are growing fast.', example_ko_2 = '이 차트는 우리가 빠르게 성장하고 있다는 것을 의미해요.', example_en_3 = 'What does this graph mean exactly?', example_ko_3 = '이 그래프는 정확히 무엇을 의미하나요?', example_en_4 = 'I mean that the trend is positive.', example_ko_4 = '추세가 긍정적이라는 뜻이에요.', example_en_5 = 'That does not mean we should stop.', example_ko_5 = '그게 우리가 멈춰야 한다는 뜻은 아니에요.' WHERE id = 'w_presentation_A1_19';
UPDATE words SET example_en_2 = 'Are you ready for the next section?', example_ko_2 = '다음 섹션 준비가 되셨나요?', example_en_3 = 'She was ready with all the slides.', example_ko_3 = '그녀는 모든 슬라이드를 준비해 두었어요.', example_en_4 = 'Get ready — we start in two minutes.', example_ko_4 = '준비하세요 — 2분 후에 시작합니다.', example_en_5 = 'Is the projector ready to use?', example_ko_5 = '프로젝터가 사용 준비가 됐나요?' WHERE id = 'w_presentation_A1_20';
UPDATE words SET example_en_2 = 'The number on the left is last year''s total.', example_ko_2 = '왼쪽의 숫자는 작년 총계입니다.', example_en_3 = 'What does this number tell us?', example_ko_3 = '이 숫자는 우리에게 무엇을 말해주나요?', example_en_4 = 'Can you read the number on the screen?', example_ko_4 = '화면의 숫자를 읽어주실 수 있나요?', example_en_5 = 'The number of users doubled last year.', example_ko_5 = '작년에 사용자 수가 두 배로 늘었습니다.' WHERE id = 'w_presentation_A1_21';
UPDATE words SET example_en_2 = 'Please save your questions for the end.', example_ko_2 = '질문은 마지막까지 가지고 계세요.', example_en_3 = 'That is a great question — thank you.', example_ko_3 = '훌륭한 질문이에요 — 감사합니다.', example_en_4 = 'Does anyone have a question so far?', example_ko_4 = '지금까지 질문이 있으신 분 계신가요?', example_en_5 = 'I will answer every question at the end.', example_ko_5 = '모든 질문은 마지막에 답하겠습니다.' WHERE id = 'w_presentation_A1_22';
UPDATE words SET example_en_2 = 'This is a big opportunity for our team.', example_ko_2 = '이것은 우리 팀에 큰 기회입니다.', example_en_3 = 'The big challenge is time and cost.', example_ko_3 = '큰 과제는 시간과 비용입니다.', example_en_4 = 'We made a big improvement this year.', example_ko_4 = '올해 큰 개선이 이루어졌습니다.', example_en_5 = 'That is a big number — let me explain.', example_ko_5 = '큰 숫자네요 — 설명해 드리겠습니다.' WHERE id = 'w_presentation_A1_23';
UPDATE words SET example_en_2 = 'The first part is about the background.', example_ko_2 = '첫 번째 부분은 배경에 관한 것입니다.', example_en_3 = 'This part of the talk is very important.', example_ko_3 = '발표의 이 부분이 매우 중요합니다.', example_en_4 = 'Each part will take about ten minutes.', example_ko_4 = '각 부분은 약 10분 정도 소요됩니다.', example_en_5 = 'The best part of the project is the data.', example_ko_5 = '프로젝트에서 가장 좋은 부분은 데이터입니다.' WHERE id = 'w_presentation_A1_24';
UPDATE words SET example_en_2 = 'Our plan is to launch next quarter.', example_ko_2 = '우리의 계획은 다음 분기에 출시하는 것입니다.', example_en_3 = 'Do you have a plan for this problem?', example_ko_3 = '이 문제에 대한 계획이 있나요?', example_en_4 = 'Let me walk you through the plan.', example_ko_4 = '계획을 순서대로 안내해 드리겠습니다.', example_en_5 = 'The plan has four clear steps.', example_ko_5 = '계획에는 네 가지 명확한 단계가 있습니다.' WHERE id = 'w_presentation_A1_25';
UPDATE words SET example_en_2 = 'My idea is to change the schedule.', example_ko_2 = '제 아이디어는 일정을 바꾸는 것입니다.', example_en_3 = 'That is a great idea — let''s try it.', example_ko_3 = '훌륭한 아이디어네요 — 시도해 봐요.', example_en_4 = 'The core idea of this talk is simple.', example_ko_4 = '이 발표의 핵심 아이디어는 간단합니다.', example_en_5 = 'I got this idea from user feedback.', example_ko_5 = '이 아이디어는 사용자 피드백에서 얻었습니다.' WHERE id = 'w_presentation_A1_26';
UPDATE words SET example_en_2 = 'Step two is to collect the data.', example_ko_2 = '두 번째 단계는 데이터를 수집하는 것입니다.', example_en_3 = 'Follow these steps and you will succeed.', example_ko_3 = '이 단계들을 따르면 성공할 수 있어요.', example_en_4 = 'We are now on step three.', example_ko_4 = '우리는 지금 세 번째 단계에 있습니다.', example_en_5 = 'Each step is shown on this slide.', example_ko_5 = '각 단계가 이 슬라이드에 나와 있습니다.' WHERE id = 'w_presentation_A1_27';
UPDATE words SET example_en_2 = 'The key word here is "growth".', example_ko_2 = '여기서 핵심 단어는 "성장"입니다.', example_en_3 = 'I would like to say a few words about this.', example_ko_3 = '이에 대해 몇 말씀 드리고 싶습니다.', example_en_4 = 'In other words, the results are positive.', example_ko_4 = '다시 말해, 결과는 긍정적입니다.', example_en_5 = 'What word best describes this trend?', example_ko_5 = '이 추세를 가장 잘 설명하는 단어는 무엇인가요?' WHERE id = 'w_presentation_A1_28';
UPDATE words SET example_en_2 = 'I will keep this short — no extra time needed.', example_ko_2 = '짧게 하겠습니다 — 추가 시간이 필요 없어요.', example_en_3 = 'Is there enough time for a demo?', example_ko_3 = '데모를 할 시간이 충분한가요?', example_en_4 = 'Time management is key in a presentation.', example_ko_4 = '발표에서 시간 관리가 핵심입니다.', example_en_5 = 'We are running out of time — let me summarize.', example_ko_5 = '시간이 부족합니다 — 요약해 드리겠습니다.' WHERE id = 'w_presentation_A1_29';
UPDATE words SET example_en_2 = 'What is the name of this process?', example_ko_2 = '이 과정의 이름이 무엇인가요?', example_en_3 = 'My name is on the first slide.', example_ko_3 = '제 이름이 첫 번째 슬라이드에 있습니다.', example_en_4 = 'Let me write my name on the board.', example_ko_4 = '칠판에 제 이름을 쓰겠습니다.', example_en_5 = 'The name of our project is "Spark".', example_ko_5 = '우리 프로젝트의 이름은 "Spark"입니다.' WHERE id = 'w_presentation_A1_30';
UPDATE words SET example_en_2 = 'Right, that brings me to my next point.', example_ko_2 = '좋아요, 그것이 다음 요점으로 이어집니다.', example_en_3 = 'Right, let us continue with the plan.', example_ko_3 = '좋아요, 계획을 계속 진행하겠습니다.', example_en_4 = 'Is that right? Please correct me if not.', example_ko_4 = '맞나요? 아니라면 수정해 주세요.', example_en_5 = 'Right, I think we all understand now.', example_ko_5 = '좋아요, 이제 모두 이해하신 것 같습니다.' WHERE id = 'w_presentation_A1_31';
UPDATE words SET example_en_2 = 'Let me give you the context first.', example_ko_2 = '먼저 맥락을 말씀드리겠습니다.', example_en_3 = 'I will give you a few examples.', example_ko_3 = '몇 가지 예를 들어드리겠습니다.', example_en_4 = 'She will give the closing remarks.', example_ko_4 = '그녀가 마무리 발언을 할 것입니다.', example_en_5 = 'Can you give me a moment to check?', example_ko_5 = '확인할 시간을 조금 주시겠어요?' WHERE id = 'w_presentation_A1_32';
UPDATE words SET example_en_2 = 'This section covers our main findings.', example_ko_2 = '이 섹션은 우리의 주요 발견을 다룹니다.', example_en_3 = 'We will not cover everything today.', example_ko_3 = '오늘 모든 것을 다루지는 않을 거예요.', example_en_4 = 'The first part covers the background.', example_ko_4 = '첫 번째 부분은 배경을 다룹니다.', example_en_5 = 'I will cover the key points quickly.', example_ko_5 = '핵심 요점을 빠르게 다루겠습니다.' WHERE id = 'w_presentation_A1_33';
UPDATE words SET example_en_2 = 'This picture shows a clear trend.', example_ko_2 = '이 그림은 명확한 추세를 보여줍니다.', example_en_3 = 'Look at the picture on the right.', example_ko_3 = '오른쪽 그림을 봐주세요.', example_en_4 = 'The picture makes the idea very clear.', example_ko_4 = '그림이 아이디어를 매우 명확하게 만들어 줍니다.', example_en_5 = 'I chose this picture to illustrate the point.', example_ko_5 = '이 그림은 요점을 설명하기 위해 선택했습니다.' WHERE id = 'w_presentation_A1_34';
UPDATE words SET example_en_2 = 'This slide is about our target users.', example_ko_2 = '이 슬라이드는 우리의 목표 사용자에 대한 것입니다.', example_en_3 = 'Do you have any concerns about this?', example_ko_3 = '이에 대해 우려하시는 점이 있나요?', example_en_4 = 'Tell me more about your experience.', example_ko_4 = '경험에 대해 더 말씀해 주세요.', example_en_5 = 'This is about improving our process.', example_ko_5 = '이것은 우리 과정을 개선하는 것에 관한 것입니다.' WHERE id = 'w_presentation_A1_35';

