UPDATE words SET example_en_2 = 'We take a holistic view of user experience.', example_ko_2 = '우리는 사용자 경험을 전체론적 관점으로 봅니다.', example_en_3 = 'A holistic approach considers all stakeholders.', example_ko_3 = '전체론적 접근법은 모든 이해관계자를 고려합니다.', example_en_4 = 'Think holistically before proposing a solution.', example_ko_4 = '해결책을 제안하기 전에 전체적으로 생각하세요.', example_en_5 = 'The holistic model covers cost, time, and risk.', example_ko_5 = '전체론적 모델은 비용, 시간, 위험을 다룹니다.' WHERE id = 'w_presentation_B2_29';
