UPDATE words SET example_en_2 = 'The discrepancy is explained on slide nine.', example_ko_2 = '불일치는 9번 슬라이드에 설명되어 있습니다.', example_en_3 = 'Address the discrepancy before questions arise.', example_ko_3 = '질문이 나오기 전에 불일치를 해결하세요.', example_en_4 = 'There is a discrepancy between the two reports.', example_ko_4 = '두 보고서 사이에 불일치가 있습니다.', example_en_5 = 'Explain the discrepancy clearly and honestly.', example_ko_5 = '불일치를 명확하고 솔직하게 설명하세요.' WHERE id = 'w_presentation_B2_31';
UPDATE words SET example_en_2 = 'These are actionable steps you can take today.', example_ko_2 = '오늘 바로 실행할 수 있는 단계들입니다.', example_en_3 = 'End with actionable recommendations always.', example_ko_3 = '항상 바로 실행 가능한 권장 사항으로 마무리하세요.', example_en_4 = 'Keep your suggestions actionable and specific.', example_ko_4 = '제안을 실행 가능하고 구체적으로 유지하세요.', example_en_5 = 'Actionable insights drive real business change.', example_ko_5 = '실행 가능한 인사이트가 실제 비즈니스 변화를 이끕니다.' WHERE id = 'w_presentation_B2_32';
UPDATE words SET example_en_2 = 'Each iteration improved the design noticeably.', example_ko_2 = '각 이터레이션이 디자인을 눈에 띄게 개선했습니다.', example_en_3 = 'How many iterations did the project go through?', example_ko_3 = '프로젝트가 몇 번의 이터레이션을 거쳤나요?', example_en_4 = 'Show the progress across each iteration.', example_ko_4 = '각 이터레이션에 걸친 진전을 보여주세요.', example_en_5 = 'Iteration leads to a better final product.', example_ko_5 = '이터레이션이 더 나은 최종 제품으로 이어집니다.' WHERE id = 'w_presentation_B2_33';
UPDATE words SET example_en_2 = 'We need strategic alignment across all teams.', example_ko_2 = '모든 팀 전반의 전략적 정렬이 필요합니다.', example_en_3 = 'Check alignment before the final presentation.', example_ko_3 = '최종 발표 전에 정렬을 확인하세요.', example_en_4 = 'Alignment between teams leads to better results.', example_ko_4 = '팀 간 정렬이 더 나은 결과로 이어집니다.', example_en_5 = 'The alignment is clear from the shared goals.', example_ko_5 = '정렬은 공유된 목표에서 명확하게 드러납니다.' WHERE id = 'w_presentation_B2_34';
