UPDATE words SET example_en_2 = 'Her use of rhetoric was very effective.', example_ko_2 = '그녀의 수사법 활용이 매우 효과적이었어요.', example_en_3 = 'Political rhetoric often obscures the facts.', example_ko_3 = '정치적 수사법은 종종 사실을 모호하게 합니다.', example_en_4 = 'Study rhetoric to improve your public speaking.', example_ko_4 = '대중 연설을 향상시키기 위해 수사학을 공부하세요.', example_en_5 = 'The rhetoric was powerful and moved the audience.', example_ko_5 = '수사법이 강력해 청중을 감동시켰습니다.' WHERE id = 'w_presentation_C1_01';
UPDATE words SET example_en_2 = 'The discourse around AI is changing rapidly.', example_ko_2 = 'AI에 관한 담론이 빠르게 변화하고 있습니다.', example_en_3 = 'Academic discourse requires precise language.', example_ko_3 = '학문적 담론은 정확한 언어를 요구합니다.', example_en_4 = 'Public discourse shapes policy decisions.', example_ko_4 = '공공 담론이 정책 결정을 형성합니다.', example_en_5 = 'Contribute to the discourse with new evidence.', example_ko_5 = '새로운 증거로 담론에 기여하세요.' WHERE id = 'w_presentation_C1_02';
UPDATE words SET example_en_2 = 'She deconstructed the argument step by step.', example_ko_2 = '그녀는 논거를 단계별로 분해했어요.', example_en_3 = 'Deconstruct the problem before solving it.', example_ko_3 = '문제를 해결하기 전에 분해해서 분석하세요.', example_en_4 = 'He deconstructed the myth with clear evidence.', example_ko_4 = '그는 명확한 증거로 신화를 분해했어요.', example_en_5 = 'Deconstruct complex ideas to make them clear.', example_ko_5 = '복잡한 아이디어를 명확하게 만들기 위해 분해하세요.' WHERE id = 'w_presentation_C1_03';
UPDATE words SET example_en_2 = 'This technology represents a new paradigm.', example_ko_2 = '이 기술은 새로운 패러다임을 나타냅니다.', example_en_3 = 'A paradigm shift is happening in our industry.', example_ko_3 = '우리 업계에서 패러다임 전환이 일어나고 있습니다.', example_en_4 = 'Question the dominant paradigm in your field.', example_ko_4 = '자신의 분야에서 지배적인 패러다임에 의문을 제기하세요.', example_en_5 = 'AI is the new paradigm for data analysis.', example_ko_5 = 'AI는 데이터 분석의 새로운 패러다임입니다.' WHERE id = 'w_presentation_C1_04';
UPDATE words SET example_en_2 = 'Our framework guides every design decision.', example_ko_2 = '우리의 프레임워크가 모든 설계 결정을 안내합니다.', example_en_3 = 'Use a clear framework to organize your talk.', example_ko_3 = '발표를 구성하기 위해 명확한 프레임워크를 사용하세요.', example_en_4 = 'The framework has four interconnected parts.', example_ko_4 = '프레임워크는 네 개의 상호 연결된 부분으로 이루어져 있습니다.', example_en_5 = 'She presented the framework with great clarity.', example_ko_5 = '그녀는 프레임워크를 매우 명확하게 발표했어요.' WHERE id = 'w_presentation_C1_05';
UPDATE words SET example_en_2 = 'Our value proposition is clear and compelling.', example_ko_2 = '우리의 가치 명제는 명확하고 설득력 있습니다.', example_en_3 = 'State your core proposition in the first slide.', example_ko_3 = '첫 번째 슬라이드에 핵심 명제를 진술하세요.', example_en_4 = 'The proposition was accepted by the committee.', example_ko_4 = '명제가 위원회에서 받아들여졌습니다.', example_en_5 = 'Test your proposition against real data.', example_ko_5 = '실제 데이터로 명제를 검증하세요.' WHERE id = 'w_presentation_C1_06';
UPDATE words SET example_en_2 = 'Our conclusions rest on empirical evidence.', example_ko_2 = '우리의 결론은 실증적 증거에 기반합니다.', example_en_3 = 'Empirical data is more reliable than opinion.', example_ko_3 = '실증적 데이터는 의견보다 신뢰할 수 있습니다.', example_en_4 = 'The empirical findings are presented clearly.', example_ko_4 = '실증적 발견이 명확하게 제시되었습니다.', example_en_5 = 'Always ground your argument in empirical facts.', example_ko_5 = '항상 논거를 실증적 사실에 근거하세요.' WHERE id = 'w_presentation_C1_07';
UPDATE words SET example_en_2 = 'An analytical mind is essential for research.', example_ko_2 = '분석적인 사고방식이 연구에 필수적입니다.', example_en_3 = 'Take an analytical look at the user data.', example_ko_3 = '사용자 데이터를 분석적으로 살펴보세요.', example_en_4 = 'Her analytical framework impressed the panel.', example_ko_4 = '그녀의 분석적 프레임워크가 패널에 깊은 인상을 줬어요.', example_en_5 = 'Strong analytical skills make better presentations.', example_ko_5 = '강력한 분석 능력이 더 나은 발표를 만듭니다.' WHERE id = 'w_presentation_C1_08';
UPDATE words SET example_en_2 = 'We synthesize findings from five studies.', example_ko_2 = '다섯 개의 연구에서 발견을 종합합니다.', example_en_3 = 'Synthesize the information into a clear message.', example_ko_3 = '정보를 명확한 메시지로 종합하세요.', example_en_4 = 'She synthesized ideas from multiple disciplines.', example_ko_4 = '그녀는 여러 분야의 아이디어를 종합했어요.', example_en_5 = 'Synthesize your research before writing the talk.', example_ko_5 = '발표를 작성하기 전에 연구를 종합하세요.' WHERE id = 'w_presentation_C1_09';
UPDATE words SET example_en_2 = 'What can we infer from this pattern?', example_ko_2 = '이 패턴에서 무엇을 추론할 수 있나요?', example_en_3 = 'Do not infer too much from a single data point.', example_ko_3 = '단일 데이터 포인트에서 너무 많이 추론하지 마세요.', example_en_4 = 'We can infer user intent from the behavior data.', example_ko_4 = '행동 데이터에서 사용자 의도를 추론할 수 있습니다.', example_en_5 = 'She inferred the cause from the observed effect.', example_ko_5 = '그녀는 관찰된 결과에서 원인을 추론했어요.' WHERE id = 'w_presentation_C1_10';
UPDATE words SET example_en_2 = 'Engagement correlates strongly with retention.', example_ko_2 = '참여도가 유지율과 강하게 상관관계가 있습니다.', example_en_3 = 'These two variables correlate in the data.', example_ko_3 = '이 두 변수는 데이터에서 상관관계가 있습니다.', example_en_4 = 'Satisfaction scores correlate with repeat visits.', example_ko_4 = '만족도 점수가 재방문과 상관관계가 있습니다.', example_en_5 = 'Show how the variables correlate on the graph.', example_ko_5 = '그래프에서 변수들이 어떻게 상관관계가 있는지 보여주세요.' WHERE id = 'w_presentation_C1_11';
UPDATE words SET example_en_2 = 'I will critique each approach fairly.', example_ko_2 = '각 접근법을 공정하게 비평하겠습니다.', example_en_3 = 'Critique the existing model before proposing a new one.', example_ko_3 = '새 모델을 제안하기 전에 기존 모델을 비평하세요.', example_en_4 = 'Her critique was sharp but constructive.', example_ko_4 = '그녀의 비평은 날카롭지만 건설적이었어요.', example_en_5 = 'A good presenter can critique their own work.', example_ko_5 = '좋은 발표자는 자신의 작업을 비평할 수 있습니다.' WHERE id = 'w_presentation_C1_12';
UPDATE words SET example_en_2 = 'We conceptualized the product as a journey.', example_ko_2 = '우리는 제품을 여정으로 개념화했습니다.', example_en_3 = 'Conceptualize the problem before designing a solution.', example_ko_3 = '솔루션을 설계하기 전에 문제를 개념화하세요.', example_en_4 = 'She conceptualized the data as a living system.', example_ko_4 = '그녀는 데이터를 살아있는 시스템으로 개념화했어요.', example_en_5 = 'Conceptualize the user need before building.', example_ko_5 = '만들기 전에 사용자 필요를 개념화하세요.' WHERE id = 'w_presentation_C1_13';
UPDATE words SET example_en_2 = 'The two models produced divergent outcomes.', example_ko_2 = '두 모델이 다른 결과를 만들어냈습니다.', example_en_3 = 'Divergent views can lead to better decisions.', example_ko_3 = '다른 견해가 더 나은 결정으로 이어질 수 있습니다.', example_en_4 = 'The data showed divergent trends by region.', example_ko_4 = '데이터가 지역별로 다른 추세를 보였습니다.', example_en_5 = 'Use divergent thinking to generate more ideas.', example_ko_5 = '더 많은 아이디어를 생성하기 위해 발산적 사고를 사용하세요.' WHERE id = 'w_presentation_C1_14';
UPDATE words SET example_en_2 = 'All the evidence shows convergent results.', example_ko_2 = '모든 증거가 수렴하는 결과를 보여줍니다.', example_en_3 = 'The convergent data strengthens the argument.', example_ko_3 = '수렴하는 데이터가 논거를 강화합니다.', example_en_4 = 'Look for convergent patterns across data sets.', example_ko_4 = '데이터 세트 전반에서 수렴하는 패턴을 찾으세요.', example_en_5 = 'Convergent findings give us high confidence.', example_ko_5 = '수렴하는 발견이 우리에게 높은 확신을 줍니다.' WHERE id = 'w_presentation_C1_15';
UPDATE words SET example_en_2 = 'Her nuanced reading of the data was impressive.', example_ko_2 = '데이터에 대한 그녀의 세밀한 해석이 인상적이었어요.', example_en_3 = 'Take a nuanced view instead of a simple one.', example_ko_3 = '단순한 관점 대신 세밀한 관점을 취하세요.', example_en_4 = 'The nuanced argument held up under questioning.', example_ko_4 = '세밀한 논거가 질문에도 굳건히 유지되었습니다.', example_en_5 = 'A nuanced presentation earns more respect.', example_ko_5 = '세밀한 발표가 더 많은 존경을 받습니다.' WHERE id = 'w_presentation_C1_16';
UPDATE words SET example_en_2 = 'The normative framework guides our analysis.', example_ko_2 = '규범적 프레임워크가 우리의 분석을 안내합니다.', example_en_3 = 'We move from descriptive to normative claims.', example_ko_3 = '기술적 주장에서 규범적 주장으로 이동합니다.', example_en_4 = 'Normative recommendations follow the findings.', example_ko_4 = '규범적 권장 사항이 발견에 뒤따릅니다.', example_en_5 = 'The normative case for change is compelling.', example_ko_5 = '변화를 위한 규범적 논거가 설득력 있습니다.' WHERE id = 'w_presentation_C1_17';
UPDATE words SET example_en_2 = 'We can extrapolate to the next five years.', example_ko_2 = '향후 5년으로 추정 연장할 수 있습니다.', example_en_3 = 'Be careful when you extrapolate from small samples.', example_ko_3 = '작은 표본에서 추정 연장할 때는 주의하세요.', example_en_4 = 'She extrapolated the trend convincingly.', example_ko_4 = '그녀는 추세를 설득력 있게 추정 연장했어요.', example_en_5 = 'Extrapolate only when the data trend is stable.', example_ko_5 = '데이터 추세가 안정적일 때만 추정 연장하세요.' WHERE id = 'w_presentation_C1_18';
UPDATE words SET example_en_2 = 'Our hypothesis was supported by the findings.', example_ko_2 = '가설이 발견으로 뒷받침되었습니다.', example_en_3 = 'State your hypothesis clearly at the start.', example_ko_3 = '시작 시 가설을 명확하게 진술하세요.', example_en_4 = 'The hypothesis was rejected based on the data.', example_ko_4 = '가설이 데이터를 기반으로 기각되었습니다.', example_en_5 = 'A strong hypothesis shapes the whole study.', example_ko_5 = '강력한 가설이 전체 연구를 형성합니다.' WHERE id = 'w_presentation_C1_19';
UPDATE words SET example_en_2 = 'We prepared a contingency for every major risk.', example_ko_2 = '모든 주요 위험에 대한 비상 계획을 준비했습니다.', example_en_3 = 'A contingency plan shows careful preparation.', example_ko_3 = '비상 계획은 신중한 준비를 보여줍니다.', example_en_4 = 'Include a contingency budget in the proposal.', example_ko_4 = '제안서에 예비 예산을 포함하세요.', example_en_5 = 'The contingency was activated during the crisis.', example_ko_5 = '비상 계획이 위기 동안 발동되었습니다.' WHERE id = 'w_presentation_C1_20';
UPDATE words SET example_en_2 = 'Let me delineate the scope of this research.', example_ko_2 = '이 연구의 범위를 명확히 구분해 드리겠습니다.', example_en_3 = 'Delineate roles and responsibilities clearly.', example_ko_3 = '역할과 책임을 명확하게 구분하세요.', example_en_4 = 'She delineated the timeline in detail.', example_ko_4 = '그녀는 타임라인을 자세히 명확히 구분했어요.', example_en_5 = 'Delineate the problem space before solving.', example_ko_5 = '해결하기 전에 문제 영역을 명확히 구분하세요.' WHERE id = 'w_presentation_C1_21';
UPDATE words SET example_en_2 = 'Causality is different from correlation.', example_ko_2 = '인과관계는 상관관계와 다릅니다.', example_en_3 = 'Establish causality with a controlled experiment.', example_ko_3 = '통제된 실험으로 인과관계를 확립하세요.', example_en_4 = 'The causality is not yet proven by this data.', example_ko_4 = '이 데이터로는 인과관계가 아직 증명되지 않았습니다.', example_en_5 = 'She explained the causality clearly and simply.', example_ko_5 = '그녀는 인과관계를 명확하고 간단하게 설명했어요.' WHERE id = 'w_presentation_C1_22';
UPDATE words SET example_en_2 = 'We will disseminate the report next week.', example_ko_2 = '다음 주에 보고서를 전파하겠습니다.', example_en_3 = 'How do you plan to disseminate these findings?', example_ko_3 = '이 발견들을 어떻게 전파할 계획인가요?', example_en_4 = 'Disseminate results to all relevant teams.', example_ko_4 = '모든 관련 팀에 결과를 전파하세요.', example_en_5 = 'The conference will help disseminate our research.', example_ko_5 = '컨퍼런스가 우리의 연구를 전파하는 데 도움이 될 것입니다.' WHERE id = 'w_presentation_C1_23';
UPDATE words SET example_en_2 = 'Avoid the false dichotomy of speed vs. quality.', example_ko_2 = '속도 대 품질의 거짓 이분법을 피하세요.', example_en_3 = 'The dichotomy is more complex than it seems.', example_ko_3 = '이분법은 보이는 것보다 더 복잡합니다.', example_en_4 = 'She challenged the data/intuition dichotomy.', example_ko_4 = '그녀는 데이터/직관 이분법에 도전했어요.', example_en_5 = 'The dichotomy between theory and practice is false.', example_ko_5 = '이론과 실천 사이의 이분법은 잘못된 것입니다.' WHERE id = 'w_presentation_C1_24';
UPDATE words SET example_en_2 = 'Interrogate the data before drawing conclusions.', example_ko_2 = '결론을 내리기 전에 데이터를 면밀히 검토하세요.', example_en_3 = 'We need to interrogate these assumptions.', example_ko_3 = '이 가정들을 면밀히 검토해야 합니다.', example_en_4 = 'She interrogated the methodology thoroughly.', example_ko_4 = '그녀는 방법론을 철저하게 검토했어요.', example_en_5 = 'Interrogate every claim before presenting.', example_ko_5 = '발표 전에 모든 주장을 면밀히 검토하세요.' WHERE id = 'w_presentation_C1_25';
UPDATE words SET example_en_2 = 'We should not over-generalize from one study.', example_ko_2 = '하나의 연구에서 과도하게 일반화해서는 안 됩니다.', example_en_3 = 'Generalize carefully and acknowledge limits.', example_ko_3 = '신중하게 일반화하고 한계를 인정하세요.', example_en_4 = 'It is tempting but dangerous to over-generalize.', example_ko_4 = '과도한 일반화는 매력적이지만 위험합니다.', example_en_5 = 'She generalized the findings to all markets.', example_ko_5 = '그녀는 발견을 모든 시장으로 일반화했어요.' WHERE id = 'w_presentation_C1_26';
UPDATE words SET example_en_2 = 'This case sets a precedent for future projects.', example_ko_2 = '이 사례가 향후 프로젝트의 선례를 세웁니다.', example_en_3 = 'Is there a precedent for this kind of result?', example_ko_3 = '이런 종류의 결과에 대한 선례가 있나요?', example_en_4 = 'We looked at precedents from other companies.', example_ko_4 = '다른 회사의 선례를 살펴봤습니다.', example_en_5 = 'The precedent supports our proposed approach.', example_ko_5 = '선례가 우리가 제안한 접근법을 뒷받침합니다.' WHERE id = 'w_presentation_C1_27';
UPDATE words SET example_en_2 = 'The quantitative findings are shown in the chart.', example_ko_2 = '정량적 발견이 차트에 나와 있습니다.', example_en_3 = 'Quantitative data tells us the what, not the why.', example_ko_3 = '정량적 데이터는 이유가 아닌 무엇을 알려줍니다.', example_en_4 = 'Use quantitative metrics to track progress.', example_ko_4 = '진행 상황을 추적하기 위해 정량적 지표를 사용하세요.', example_en_5 = 'Combine quantitative and qualitative methods.', example_ko_5 = '정량적 방법과 정성적 방법을 결합하세요.' WHERE id = 'w_presentation_C1_28';
UPDATE words SET example_en_2 = 'The qualitative data reveals user motivations.', example_ko_2 = '정성적 데이터가 사용자 동기를 드러냅니다.', example_en_3 = 'Qualitative interviews gave us deep insight.', example_ko_3 = '정성적 인터뷰가 깊은 인사이트를 주었습니다.', example_en_4 = 'Use qualitative evidence to add human context.', example_ko_4 = '인간적 맥락을 추가하기 위해 정성적 증거를 사용하세요.', example_en_5 = 'She presented qualitative themes from ten interviews.', example_ko_5 = '그녀는 10번의 인터뷰에서 정성적 주제를 발표했어요.' WHERE id = 'w_presentation_C1_29';
UPDATE words SET example_en_2 = 'We used an iterative process to refine the design.', example_ko_2 = '반복적인 과정으로 디자인을 개선했습니다.', example_en_3 = 'An iterative approach leads to better outcomes.', example_ko_3 = '반복적인 접근법이 더 나은 결과로 이어집니다.', example_en_4 = 'The iterative cycle ran for three months.', example_ko_4 = '반복적인 사이클이 세 달간 진행되었습니다.', example_en_5 = 'Show the iterative improvement across versions.', example_ko_5 = '버전별 반복적인 개선을 보여주세요.' WHERE id = 'w_presentation_C1_30';
UPDATE words SET example_en_2 = 'I posit that the root cause is poor onboarding.', example_ko_2 = '근본 원인이 열악한 온보딩이라고 주장합니다.', example_en_3 = 'She posited a bold but testable claim.', example_ko_3 = '그녀는 대담하지만 검증 가능한 주장을 제기했어요.', example_en_4 = 'Posit your central claim early in the talk.', example_ko_4 = '발표 초반에 핵심 주장을 제기하세요.', example_en_5 = 'I posit that simplicity drives higher adoption.', example_ko_5 = '단순성이 더 높은 채택을 이끈다고 주장합니다.' WHERE id = 'w_presentation_C1_31';
UPDATE words SET example_en_2 = 'We need substantive action, not just words.', example_ko_2 = '말뿐만 아니라 실질적인 행동이 필요합니다.', example_en_3 = 'She made a substantive contribution to the debate.', example_ko_3 = '그녀는 토론에 실질적인 기여를 했어요.', example_en_4 = 'The report contains several substantive findings.', example_ko_4 = '보고서에는 여러 실질적인 발견이 포함됩니다.', example_en_5 = 'Make a substantive point in every section.', example_ko_5 = '모든 섹션에서 실질적인 요점을 제시하세요.' WHERE id = 'w_presentation_C1_32';
UPDATE words SET example_en_2 = 'The granularity of the dataset is impressive.', example_ko_2 = '데이터셋의 세분화 수준이 인상적입니다.', example_en_3 = 'Increase the granularity for a deeper analysis.', example_ko_3 = '더 깊은 분석을 위해 세분화 수준을 높이세요.', example_en_4 = 'The granularity allows us to spot anomalies.', example_ko_4 = '세분화 수준이 이상 징후를 발견할 수 있게 해줍니다.', example_en_5 = 'Match the granularity to your audience''s needs.', example_ko_5 = '세분화 수준을 청중의 필요에 맞추세요.' WHERE id = 'w_presentation_C1_33';
UPDATE words SET example_en_2 = 'The first axiom is that users want simplicity.', example_ko_2 = '첫 번째 공리는 사용자가 단순함을 원한다는 것입니다.', example_en_3 = 'State your axioms before building the argument.', example_ko_3 = '논거를 구축하기 전에 공리를 진술하세요.', example_en_4 = 'Challenge the axiom and see what changes.', example_ko_4 = '공리에 도전하고 무엇이 바뀌는지 보세요.', example_en_5 = 'The axiom is widely accepted in the field.', example_ko_5 = '그 공리는 해당 분야에서 널리 받아들여집니다.' WHERE id = 'w_presentation_C1_34';
UPDATE words SET example_en_2 = 'Reframe the issue as a growth opportunity.', example_ko_2 = '문제를 성장 기회로 재구성하세요.', example_en_3 = 'She reframed the failure as a valuable lesson.', example_ko_3 = '그녀는 실패를 귀중한 교훈으로 재구성했어요.', example_en_4 = 'Reframe the question to change the conversation.', example_ko_4 = '질문을 재구성해 대화를 바꾸세요.', example_en_5 = 'Reframing the problem led to a better solution.', example_ko_5 = '문제를 재구성함으로써 더 나은 해결책이 나왔습니다.' WHERE id = 'w_presentation_C1_35';

