UPDATE words SET example_en_2 = 'The epistemological stance shapes the research design.', example_ko_2 = '인식론적 입장이 연구 설계를 형성합니다.', example_en_3 = 'She raised epistemological questions about validity.', example_ko_3 = '그녀는 타당성에 관한 인식론적 질문을 제기했어요.', example_en_4 = 'An epistemological framework underpins the study.', example_ko_4 = '인식론적 프레임워크가 연구의 기반을 이룹니다.', example_en_5 = 'Epistemological humility improves research quality.', example_ko_5 = '인식론적 겸손이 연구 품질을 향상시킵니다.' WHERE id = 'w_presentation_C2_01';
UPDATE words SET example_en_2 = 'A heuristic shortcut can be useful but risky.', example_ko_2 = '발견적 지름길은 유용하지만 위험할 수 있습니다.', example_en_3 = 'We applied a heuristic to classify the data.', example_ko_3 = '데이터를 분류하기 위해 발견적 방법을 적용했습니다.', example_en_4 = 'Heuristic reasoning speeds up decision-making.', example_ko_4 = '발견적 추론이 의사결정을 가속화합니다.', example_en_5 = 'The heuristic proved accurate in most cases.', example_ko_5 = '발견적 방법이 대부분의 경우 정확한 것으로 입증되었습니다.' WHERE id = 'w_presentation_C2_02';
UPDATE words SET example_en_2 = 'Ontological assumptions must be made explicit.', example_ko_2 = '존재론적 가정을 명시적으로 밝혀야 합니다.', example_en_3 = 'Her ontological framework shapes every claim.', example_ko_3 = '그녀의 존재론적 프레임워크가 모든 주장을 형성합니다.', example_en_4 = 'The ontological question is rarely asked.', example_ko_4 = '존재론적 질문은 거의 제기되지 않습니다.', example_en_5 = 'Clarify ontological assumptions in the methodology.', example_ko_5 = '방법론에서 존재론적 가정을 명확히 하세요.' WHERE id = 'w_presentation_C2_03';
UPDATE words SET example_en_2 = 'A phenomenological study captures lived experience.', example_ko_2 = '현상학적 연구는 살아있는 경험을 포착합니다.', example_en_3 = 'She used a phenomenological lens for the analysis.', example_ko_3 = '그녀는 분석에 현상학적 렌즈를 사용했어요.', example_en_4 = 'Phenomenological research requires deep interviews.', example_ko_4 = '현상학적 연구는 심층 인터뷰가 필요합니다.', example_en_5 = 'The phenomenological approach reveals user experience.', example_ko_5 = '현상학적 접근법이 사용자 경험을 드러냅니다.' WHERE id = 'w_presentation_C2_04';
UPDATE words SET example_en_2 = 'The dialectical tension drove creative innovation.', example_ko_2 = '변증법적 긴장이 창의적 혁신을 이끌었습니다.', example_en_3 = 'She presented both sides in a dialectical way.', example_ko_3 = '그녀는 양쪽 면을 변증법적으로 발표했어요.', example_en_4 = 'A dialectical argument considers opposing views.', example_ko_4 = '변증법적 논거는 반대 견해를 고려합니다.', example_en_5 = 'The dialectical method leads to deeper insight.', example_ko_5 = '변증법적 방법이 더 깊은 인사이트로 이어집니다.' WHERE id = 'w_presentation_C2_05';
UPDATE words SET example_en_2 = 'Theory without praxis is merely academic.', example_ko_2 = '실천이 없는 이론은 단순히 학문적입니다.', example_en_3 = 'Praxis bridges the gap between theory and action.', example_ko_3 = '실천이 이론과 행동 사이의 격차를 메웁니다.', example_en_4 = 'The conference focused on praxis over theory.', example_ko_4 = '컨퍼런스는 이론보다 실천에 초점을 맞췄습니다.', example_en_5 = 'Strong praxis makes research more impactful.', example_ko_5 = '강력한 실천이 연구를 더 영향력 있게 만듭니다.' WHERE id = 'w_presentation_C2_06';
UPDATE words SET example_en_2 = 'A hermeneutic reading reveals hidden meaning.', example_ko_2 = '해석학적 독해가 숨겨진 의미를 드러냅니다.', example_en_3 = 'The hermeneutic circle guides interpretation.', example_ko_3 = '해석학적 순환이 해석을 안내합니다.', example_en_4 = 'She applied a hermeneutic lens to the interview data.', example_ko_4 = '그녀는 인터뷰 데이터에 해석학적 렌즈를 적용했어요.', example_en_5 = 'Hermeneutic analysis requires depth and patience.', example_ko_5 = '해석학적 분석은 깊이와 인내가 필요합니다.' WHERE id = 'w_presentation_C2_07';
UPDATE words SET example_en_2 = 'The meta-analysis covered twenty primary studies.', example_ko_2 = '메타분석은 20개의 기본 연구를 다루었습니다.', example_en_3 = 'Conduct a meta-analysis to increase statistical power.', example_ko_3 = '통계적 검정력을 높이기 위해 메타분석을 수행하세요.', example_en_4 = 'The meta-analysis confirmed the main hypothesis.', example_ko_4 = '메타분석이 주요 가설을 확인했습니다.', example_en_5 = 'She presented meta-analysis results with forest plots.', example_ko_5 = '그녀는 메타분석 결과를 포레스트 플롯으로 발표했어요.' WHERE id = 'w_presentation_C2_08';
UPDATE words SET example_en_2 = 'A positivist assumes objective measurable truth.', example_ko_2 = '실증주의자는 객관적으로 측정 가능한 진실을 가정합니다.', example_en_3 = 'The study took a strictly positivist approach.', example_ko_3 = '연구는 엄격히 실증주의적 접근법을 취했습니다.', example_en_4 = 'Positivist research relies heavily on statistics.', example_ko_4 = '실증주의 연구는 통계에 크게 의존합니다.', example_en_5 = 'She questioned the positivist assumptions in the field.', example_ko_5 = '그녀는 해당 분야의 실증주의적 가정에 의문을 제기했어요.' WHERE id = 'w_presentation_C2_09';
UPDATE words SET example_en_2 = 'A constructivist approach values context deeply.', example_ko_2 = '구성주의 접근법은 맥락을 깊이 중시합니다.', example_en_3 = 'Constructivist researchers co-create knowledge.', example_ko_3 = '구성주의 연구자들은 지식을 공동 창조합니다.', example_en_4 = 'She used a constructivist framework for the study.', example_ko_4 = '그녀는 연구에 구성주의 프레임워크를 사용했어요.', example_en_5 = 'A constructivist lens enriches qualitative analysis.', example_ko_5 = '구성주의 렌즈가 정성적 분석을 풍부하게 합니다.' WHERE id = 'w_presentation_C2_10';
UPDATE words SET example_en_2 = 'Begin with an axiom the board already accepts.', example_ko_2 = '이사회가 이미 받아들이는 공리로 시작하세요.', example_en_3 = 'The axiom of user rationality is often questioned.', example_ko_3 = '사용자 합리성의 공리는 종종 의문시됩니다.', example_en_4 = 'Challenge the axiom to open a new discussion.', example_ko_4 = '새로운 토론을 열기 위해 공리에 도전하세요.', example_en_5 = 'State the axiom explicitly before building on it.', example_ko_5 = '공리를 기반으로 구축하기 전에 명시적으로 진술하세요.' WHERE id = 'w_presentation_C2_11';
UPDATE words SET example_en_2 = 'Reification of abstract models can mislead.', example_ko_2 = '추상적 모델의 실물화는 오도할 수 있습니다.', example_en_3 = 'Avoid reification when presenting complex ideas.', example_ko_3 = '복잡한 아이디어를 발표할 때 실물화를 피하세요.', example_en_4 = 'The reification of data obscured the real meaning.', example_ko_4 = '데이터의 실물화가 진짜 의미를 모호하게 했습니다.', example_en_5 = 'She warned against reification in her talk.', example_ko_5 = '그녀는 발표에서 실물화에 대해 경고했어요.' WHERE id = 'w_presentation_C2_12';
UPDATE words SET example_en_2 = 'High verisimilitude makes data more convincing.', example_ko_2 = '높은 사실성이 데이터를 더 설득력 있게 만듭니다.', example_en_3 = 'Verisimilitude is critical in qualitative research.', example_ko_3 = '사실성은 정성적 연구에서 매우 중요합니다.', example_en_4 = 'The story had verisimilitude that engaged the audience.', example_ko_4 = '이야기에 청중을 사로잡는 사실성이 있었습니다.', example_en_5 = 'Verisimilitude is achieved through detail and precision.', example_ko_5 = '사실성은 세부 사항과 정밀도를 통해 달성됩니다.' WHERE id = 'w_presentation_C2_13';
UPDATE words SET example_en_2 = 'The exegesis revealed unexpected patterns.', example_ko_2 = '주석이 예상치 못한 패턴을 드러냈습니다.', example_en_3 = 'A careful exegesis is needed before conclusions.', example_ko_3 = '결론 전에 신중한 주석 작업이 필요합니다.', example_en_4 = 'She provided a rigorous exegesis of the data.', example_ko_4 = '그녀는 데이터의 엄격한 주석을 제공했어요.', example_en_5 = 'Exegesis of the survey required expert knowledge.', example_ko_5 = '설문의 주석 작업에는 전문 지식이 필요했습니다.' WHERE id = 'w_presentation_C2_14';
UPDATE words SET example_en_2 = 'The syllogism was presented clearly on the slide.', example_ko_2 = '삼단논법이 슬라이드에 명확하게 제시되었습니다.', example_en_3 = 'A flawed syllogism will undermine your argument.', example_ko_3 = '결함 있는 삼단논법이 논거를 훼손할 것입니다.', example_en_4 = 'She used a classic syllogism to open her talk.', example_ko_4 = '그녀는 발표를 시작하기 위해 고전적 삼단논법을 사용했어요.', example_en_5 = 'The syllogism helped structure the core argument.', example_ko_5 = '삼단논법이 핵심 논거를 구성하는 데 도움이 되었습니다.' WHERE id = 'w_presentation_C2_15';
UPDATE words SET example_en_2 = 'Tautology weakens your presentation logic.', example_ko_2 = '동어반복이 발표 논리를 약화시킵니다.', example_en_3 = 'Remove tautology to make your writing sharper.', example_ko_3 = '글을 더 날카롭게 만들기 위해 동어반복을 제거하세요.', example_en_4 = 'She identified tautology in the draft and corrected it.', example_ko_4 = '그녀는 초안에서 동어반복을 발견하고 수정했어요.', example_en_5 = 'Tautological arguments fail to advance the claim.', example_ko_5 = '동어반복적 논거는 주장을 발전시키지 못합니다.' WHERE id = 'w_presentation_C2_16';
UPDATE words SET example_en_2 = 'The award was the apotheosis of her career.', example_ko_2 = '그 상은 그녀 경력의 절정이었어요.', example_en_3 = 'This slide is the apotheosis of the argument.', example_ko_3 = '이 슬라이드는 논거의 절정입니다.', example_en_4 = 'The final case study is the apotheosis of the talk.', example_ko_4 = '최종 사례 연구가 발표의 절정입니다.', example_en_5 = 'The apotheosis of the research is this single finding.', example_ko_5 = '연구의 절정은 이 단일 발견입니다.' WHERE id = 'w_presentation_C2_17';
UPDATE words SET example_en_2 = 'Her polemic challenged every assumption.', example_ko_2 = '그녀의 논박이 모든 가정에 도전했어요.', example_en_3 = 'A polemic can sharpen discourse if done well.', example_ko_3 = '논박이 잘 수행되면 담론을 날카롭게 할 수 있습니다.', example_en_4 = 'He wrote a polemic against outdated practices.', example_ko_4 = '그는 구식 관행에 반하는 논박을 썼어요.', example_en_5 = 'A polemic should be evidence-based, not personal.', example_ko_5 = '논박은 개인적이 아닌 증거에 기반해야 합니다.' WHERE id = 'w_presentation_C2_18';
UPDATE words SET example_en_2 = 'Triangulation of methods increases confidence.', example_ko_2 = '방법의 삼각검증이 확신을 높입니다.', example_en_3 = 'She used triangulation to validate the findings.', example_ko_3 = '그녀는 발견을 검증하기 위해 삼각검증을 사용했어요.', example_en_4 = 'Triangulation reduces the risk of bias.', example_ko_4 = '삼각검증이 편향의 위험을 줄입니다.', example_en_5 = 'Include triangulation in every mixed-methods study.', example_ko_5 = '모든 혼합 방법 연구에 삼각검증을 포함하세요.' WHERE id = 'w_presentation_C2_19';
UPDATE words SET example_en_2 = 'Abductive reasoning led us to the best explanation.', example_ko_2 = '귀추적 추론이 우리를 최선의 설명으로 이끌었습니다.', example_en_3 = 'She used abductive logic to form the hypothesis.', example_ko_3 = '그녀는 가설을 형성하기 위해 귀추적 논리를 사용했어요.', example_en_4 = 'Abductive reasoning is common in early-stage research.', example_ko_4 = '귀추적 추론은 초기 단계 연구에서 일반적입니다.', example_en_5 = 'The team used abductive reasoning to explain anomalies.', example_ko_5 = '팀은 이상 징후를 설명하기 위해 귀추적 추론을 사용했습니다.' WHERE id = 'w_presentation_C2_20';
UPDATE words SET example_en_2 = 'Intersubjectivity strengthens qualitative validity.', example_ko_2 = '상호주관성이 정성적 타당성을 강화합니다.', example_en_3 = 'She built intersubjectivity through member checking.', example_ko_3 = '그녀는 구성원 확인을 통해 상호주관성을 구축했어요.', example_en_4 = 'Intersubjectivity requires transparent reflexivity.', example_ko_4 = '상호주관성은 투명한 성찰성을 요구합니다.', example_en_5 = 'The team achieved intersubjectivity after three rounds.', example_ko_5 = '팀은 세 차례의 라운드 후에 상호주관성을 달성했습니다.' WHERE id = 'w_presentation_C2_21';
UPDATE words SET example_en_2 = 'Her heterodox model challenged the mainstream.', example_ko_2 = '그녀의 비정통적 모델이 주류에 도전했어요.', example_en_3 = 'A heterodox view can spark productive debate.', example_ko_3 = '비정통적 관점이 생산적인 토론을 불러일으킬 수 있습니다.', example_en_4 = 'The heterodox approach is gaining more acceptance.', example_ko_4 = '비정통적 접근법이 점점 더 많은 수용을 얻고 있습니다.', example_en_5 = 'She presented a heterodox reading of the data.', example_ko_5 = '그녀는 데이터의 비정통적 해석을 발표했어요.' WHERE id = 'w_presentation_C2_22';
UPDATE words SET example_en_2 = 'Semiotics shapes how visuals communicate meaning.', example_ko_2 = '기호학이 시각 자료가 의미를 전달하는 방식을 형성합니다.', example_en_3 = 'She applied semiotics to analyze the ad campaign.', example_ko_3 = '그녀는 광고 캠페인을 분석하기 위해 기호학을 적용했어요.', example_en_4 = 'Semiotics helps us understand non-verbal communication.', example_ko_4 = '기호학이 비언어적 의사소통을 이해하는 데 도움이 됩니다.', example_en_5 = 'Color semiotics varies significantly across cultures.', example_ko_5 = '색채 기호학은 문화에 따라 크게 다릅니다.' WHERE id = 'w_presentation_C2_23';
UPDATE words SET example_en_2 = 'Reflexivity requires acknowledging your own biases.', example_ko_2 = '성찰성은 자신의 편향을 인정하는 것을 요구합니다.', example_en_3 = 'She demonstrated reflexivity throughout the study.', example_ko_3 = '그녀는 연구 전반에 걸쳐 성찰성을 보여줬어요.', example_en_4 = 'Reflexivity improves the trustworthiness of findings.', example_ko_4 = '성찰성이 발견의 신뢰성을 향상시킵니다.', example_en_5 = 'Include a reflexivity statement in the methodology.', example_ko_5 = '방법론에 성찰성 진술을 포함하세요.' WHERE id = 'w_presentation_C2_24';
UPDATE words SET example_en_2 = 'The teleological argument assumes a final purpose.', example_ko_2 = '목적론적 논거는 최종 목적을 가정합니다.', example_en_3 = 'She presented a teleological view of progress.', example_ko_3 = '그녀는 진보에 대한 목적론적 관점을 발표했어요.', example_en_4 = 'A teleological framework guides long-term planning.', example_ko_4 = '목적론적 프레임워크가 장기 계획을 안내합니다.', example_en_5 = 'The teleological assumption was challenged in Q&A.', example_ko_5 = '목적론적 가정이 질의응답에서 도전받았습니다.' WHERE id = 'w_presentation_C2_25';
UPDATE words SET example_en_2 = 'Reductionism misses the emergent complexity.', example_ko_2 = '환원주의는 창발적 복잡성을 놓칩니다.', example_en_3 = 'She criticized the reductionism in the model.', example_ko_3 = '그녀는 모델의 환원주의를 비판했어요.', example_en_4 = 'Avoid reductionism when studying human behavior.', example_ko_4 = '인간 행동을 연구할 때 환원주의를 피하세요.', example_en_5 = 'Reductionism can simplify but also distort findings.', example_ko_5 = '환원주의는 단순화하지만 발견을 왜곡할 수도 있습니다.' WHERE id = 'w_presentation_C2_26';
UPDATE words SET example_en_2 = 'The hypothesis must have falsifiability to be scientific.', example_ko_2 = '가설은 과학적이려면 반증가능성을 가져야 합니다.', example_en_3 = 'She checked the falsifiability of each claim.', example_ko_3 = '그녀는 각 주장의 반증가능성을 확인했어요.', example_en_4 = 'Falsifiability is the foundation of good science.', example_ko_4 = '반증가능성이 좋은 과학의 기반입니다.', example_en_5 = 'Without falsifiability, the claim is not testable.', example_ko_5 = '반증가능성 없이는 주장을 검증할 수 없습니다.' WHERE id = 'w_presentation_C2_27';
UPDATE words SET example_en_2 = 'The methodology was a bricolage of approaches.', example_ko_2 = '방법론은 다양한 접근법의 브리콜라주였습니다.', example_en_3 = 'Creative bricolage led to a unique solution.', example_ko_3 = '창의적인 브리콜라주가 독특한 솔루션으로 이어졌습니다.', example_en_4 = 'She described the project as intellectual bricolage.', example_ko_4 = '그녀는 프로젝트를 지적 브리콜라주로 설명했어요.', example_en_5 = 'Bricolage is common in interdisciplinary research.', example_ko_5 = '브리콜라주는 학제간 연구에서 일반적입니다.' WHERE id = 'w_presentation_C2_28';
UPDATE words SET example_en_2 = 'This case study instantiates the core theory.', example_ko_2 = '이 사례 연구가 핵심 이론을 구현합니다.', example_en_3 = 'She instantiated the abstract concept with a story.', example_ko_3 = '그녀는 이야기로 추상적 개념을 구현했어요.', example_en_4 = 'The example instantiates the pattern perfectly.', example_ko_4 = '예시가 패턴을 완벽하게 구현합니다.', example_en_5 = 'Use data to instantiate your theoretical claims.', example_ko_5 = '데이터를 사용해 이론적 주장을 구현하세요.' WHERE id = 'w_presentation_C2_29';
UPDATE words SET example_en_2 = 'Only probative evidence was included in the study.', example_ko_2 = '연구에는 증명력 있는 증거만 포함되었습니다.', example_en_3 = 'The court found the testimony probative.', example_ko_3 = '법원은 증언이 증명력 있다고 판단했습니다.', example_en_4 = 'Present only probative evidence in the main talk.', example_ko_4 = '메인 발표에서는 증명력 있는 증거만 제시하세요.', example_en_5 = 'Probative value must outweigh prejudicial effect.', example_ko_5 = '증명력이 편견 효과를 능가해야 합니다.' WHERE id = 'w_presentation_C2_30';
UPDATE words SET example_en_2 = 'Avoid circumlocution to hold audience attention.', example_ko_2 = '청중의 주의를 유지하기 위해 우회적 표현을 피하세요.', example_en_3 = 'His circumlocution lost the audience quickly.', example_ko_3 = '그의 우회적 표현이 빠르게 청중을 잃었어요.', example_en_4 = 'Edit for circumlocution before the final draft.', example_ko_4 = '최종 초안 전에 우회적 표현을 편집하세요.', example_en_5 = 'She replaced circumlocution with clear statements.', example_ko_5 = '그녀는 우회적 표현을 명확한 진술로 교체했어요.' WHERE id = 'w_presentation_C2_31';
UPDATE words SET example_en_2 = 'Apophenia leads analysts to false conclusions.', example_ko_2 = '패턴 착각 현상이 분석가들을 잘못된 결론으로 이끕니다.', example_en_3 = 'She warned against apophenia in data analysis.', example_ko_3 = '그녀는 데이터 분석에서 패턴 착각 현상에 대해 경고했어요.', example_en_4 = 'Apophenia can make noise look like signal.', example_ko_4 = '패턴 착각 현상이 노이즈를 신호처럼 보이게 할 수 있습니다.', example_en_5 = 'Statistical testing helps guard against apophenia.', example_ko_5 = '통계적 검정이 패턴 착각 현상을 방지하는 데 도움이 됩니다.' WHERE id = 'w_presentation_C2_32';
UPDATE words SET example_en_2 = 'The dominant episteme shapes what counts as knowledge.', example_ko_2 = '지배적인 에피스테메가 지식으로 인정되는 것을 형성합니다.', example_en_3 = 'She traced the episteme through two centuries.', example_ko_3 = '그녀는 2세기에 걸쳐 에피스테메를 추적했어요.', example_en_4 = 'Every discipline operates within an episteme.', example_ko_4 = '모든 학문 분야는 에피스테메 안에서 작동합니다.', example_en_5 = 'Challenge the episteme to open new possibilities.', example_ko_5 = '새로운 가능성을 열기 위해 에피스테메에 도전하세요.' WHERE id = 'w_presentation_C2_33';
UPDATE words SET example_en_2 = 'The isomorphism revealed a deep structural parallel.', example_ko_2 = '동형성이 깊은 구조적 유사성을 드러냈습니다.', example_en_3 = 'There is a clear isomorphism between the two frameworks.', example_ko_3 = '두 프레임워크 사이에 명확한 동형성이 있습니다.', example_en_4 = 'She exploited the isomorphism to simplify the proof.', example_ko_4 = '그녀는 증명을 단순화하기 위해 동형성을 활용했어요.', example_en_5 = 'Isomorphism allows findings to transfer across domains.', example_ko_5 = '동형성이 발견이 여러 분야에 걸쳐 전이되도록 합니다.' WHERE id = 'w_presentation_C2_34';
UPDATE words SET example_en_2 = 'Polysemy in key terms can confuse the audience.', example_ko_2 = '핵심 용어의 다의성이 청중을 혼란스럽게 할 수 있습니다.', example_en_3 = 'She flagged the polysemy of "value" in the talk.', example_ko_3 = '그녀는 발표에서 "가치"의 다의성을 표시했어요.', example_en_4 = 'Address polysemy early to avoid misunderstanding.', example_ko_4 = '오해를 피하기 위해 초반에 다의성을 다루세요.', example_en_5 = 'Polysemy is a challenge in cross-cultural presentations.', example_ko_5 = '다의성은 다문화 발표에서 도전 과제입니다.' WHERE id = 'w_presentation_C2_35';

