UPDATE words SET example_en_2 = 'Sports analytics helps coaches make data-driven decisions.', example_ko_2 = '스포츠 분석학은 코치들이 데이터 기반의 결정을 내릴 수 있도록 도와줘요.', example_en_3 = 'The analytics team identified weaknesses in the opposition''s defence.', example_ko_3 = '분석팀은 상대 수비의 약점을 파악했어요.', example_en_4 = 'She studied analytics to improve her performance metrics.', example_ko_4 = '그녀는 경기력 지표를 향상시키기 위해 분석학을 공부했어요.', example_en_5 = 'Advanced analytics is now standard practice at elite clubs.', example_ko_5 = '첨단 분석학은 이제 엘리트 클럽에서 표준 방식이 됐어요.' WHERE id = 'w_sports_B2_01';
UPDATE words SET example_en_2 = 'Biomechanics analysis revealed a flaw in her throwing technique.', example_ko_2 = '생체역학 분석을 통해 그녀의 투구 기술에서 결함이 발견됐어요.', example_en_3 = 'He studied biomechanics to understand how to run more efficiently.', example_ko_3 = '그는 더 효율적으로 달리는 방법을 이해하기 위해 생체역학을 공부했어요.', example_en_4 = 'Biomechanics research has led to better-designed sports equipment.', example_ko_4 = '생체역학 연구는 더 잘 설계된 스포츠 장비로 이어졌어요.', example_en_5 = 'Coaches use biomechanics data to correct athletes'' movement patterns.', example_ko_5 = '코치들은 생체역학 데이터를 활용해 선수들의 움직임 패턴을 교정해요.' WHERE id = 'w_sports_B2_02';
UPDATE words SET example_en_2 = 'Several athletes were suspended after failing doping tests.', example_ko_2 = '여러 선수들이 도핑 검사에서 양성 반응이 나와 출전 정지를 당했어요.', example_en_3 = 'Doping undermines the integrity of fair competition.', example_ko_3 = '도핑은 공정한 경쟁의 완전성을 훼손해요.', example_en_4 = 'She spoke out against doping in her farewell address.', example_ko_4 = '그녀는 은퇴 연설에서 도핑에 반대하는 목소리를 높였어요.', example_en_5 = 'Anti-doping agencies conduct random testing throughout the season.', example_ko_5 = '도핑 방지 기관은 시즌 내내 무작위 검사를 실시해요.' WHERE id = 'w_sports_B2_03';
UPDATE words SET example_en_2 = 'She received physiotherapy for weeks after the ankle sprain.', example_ko_2 = '그녀는 발목 염좌 이후 몇 주간 물리치료를 받았어요.', example_en_3 = 'Physiotherapy is an essential part of sports injury rehabilitation.', example_ko_3 = '물리치료는 스포츠 부상 재활의 필수적인 부분이에요.', example_en_4 = 'He credits physiotherapy for his successful recovery.', example_ko_4 = '그는 성공적인 회복의 공을 물리치료에 돌려요.', example_en_5 = 'The physiotherapy team works closely with the coaching staff.', example_ko_5 = '물리치료팀은 코칭 스태프와 긴밀히 협력해요.' WHERE id = 'w_sports_B2_04';
UPDATE words SET example_en_2 = 'Periodization divides the training year into distinct phases.', example_ko_2 = '주기화는 훈련 연도를 뚜렷한 단계로 나눠요.', example_en_3 = 'She followed a strict periodization plan ahead of the Olympics.', example_ko_3 = '그녀는 올림픽을 앞두고 엄격한 주기화 계획을 따랐어요.', example_en_4 = 'Proper periodization reduces the risk of overtraining.', example_ko_4 = '적절한 주기화는 과훈련의 위험을 줄여요.', example_en_5 = 'His coach redesigned the periodization to include more recovery weeks.', example_ko_5 = '그의 코치는 더 많은 회복 주간을 포함하도록 주기화를 재설계했어요.' WHERE id = 'w_sports_B2_05';
UPDATE words SET example_en_2 = 'Agility drills improved her ability to change direction quickly.', example_ko_2 = '민첩성 훈련은 그녀가 방향을 빠르게 바꾸는 능력을 향상시켰어요.', example_en_3 = 'He showed great agility in avoiding the tackle.', example_ko_3 = '그는 태클을 피하면서 뛰어난 민첩성을 보여 줬어요.', example_en_4 = 'Agility is especially important in sports like basketball and tennis.', example_ko_4 = '민첩성은 농구나 테니스 같은 스포츠에서 특히 중요해요.', example_en_5 = 'The agility tests revealed areas she still needed to work on.', example_ko_5 = '민첩성 테스트는 그녀가 아직 개선해야 할 부분을 드러냈어요.' WHERE id = 'w_sports_B2_06';
UPDATE words SET example_en_2 = 'His stamina held up throughout the demanding race.', example_ko_2 = '그의 스태미나는 힘든 경주 내내 유지됐어요.', example_en_3 = 'Building stamina requires consistent training over many months.', example_ko_3 = '스태미나를 키우려면 몇 달간의 꾸준한 훈련이 필요해요.', example_en_4 = 'She focused on stamina work during the pre-season.', example_ko_4 = '그녀는 시즌 전 준비 기간에 스태미나 훈련에 집중했어요.', example_en_5 = 'Endurance sports demand a level of stamina that takes years to develop.', example_ko_5 = '지구력 스포츠는 키우는 데 수년이 걸리는 수준의 스태미나를 요구해요.' WHERE id = 'w_sports_B2_07';
UPDATE words SET example_en_2 = 'She sprinted the final hundred metres in under twelve seconds.', example_ko_2 = '그녀는 마지막 100미터를 12초 안에 전력 질주했어요.', example_en_3 = 'He incorporated sprint intervals into his weekly training.', example_ko_3 = '그는 주간 훈련에 스프린트 인터벌을 포함시켰어요.', example_en_4 = 'Sprint training develops fast-twitch muscle fibres.', example_ko_4 = '스프린트 훈련은 빠른 수축 근육 섬유를 발달시켜요.', example_en_5 = 'The sprint finish left spectators breathless.', example_ko_5 = '스프린트 피니시는 관중들의 숨을 멎게 했어요.' WHERE id = 'w_sports_B2_08';
