UPDATE words SET example_en_2 = 'Her performance improved significantly over the past season.', example_ko_2 = '그녀의 경기력은 지난 시즌에 크게 향상됐어요.', example_en_3 = 'The coach monitors each player''s performance using data.', example_ko_3 = '코치는 데이터를 활용해 각 선수의 경기력을 모니터링해요.', example_en_4 = 'Consistent performance over a season earns a player recognition.', example_ko_4 = '시즌 내내 꾸준한 경기력은 선수에게 인정을 가져다줘요.', example_en_5 = 'High performance requires sacrifice both on and off the field.', example_ko_5 = '높은 경기력을 위해서는 경기장 안팎에서 희생이 필요해요.' WHERE id = 'w_sports_B2_10';
UPDATE words SET example_en_2 = 'He suffered a concussion after a collision with another player.', example_ko_2 = '그는 다른 선수와의 충돌 후 뇌진탕을 겪었어요.', example_en_3 = 'She was removed from the game after showing concussion symptoms.', example_ko_3 = '그녀는 뇌진탕 증상을 보여 경기에서 빠졌어요.', example_en_4 = 'Concussion protocols must be followed strictly in all contact sports.', example_ko_4 = '모든 컨택트 스포츠에서 뇌진탕 프로토콜을 엄격히 따라야 해요.', example_en_5 = 'Returning from a concussion too soon carries serious long-term risks.', example_ko_5 = '뇌진탕에서 너무 빨리 복귀하면 심각한 장기적 위험이 있어요.' WHERE id = 'w_sports_B2_11';
UPDATE words SET example_en_2 = 'Proper hydration maintains energy levels during competition.', example_ko_2 = '적절한 수분 보충은 경기 중 에너지 수준을 유지시켜요.', example_en_3 = 'She monitored her hydration closely in the summer heat.', example_ko_3 = '그녀는 여름 더위 속에서 수분 보충을 꼼꼼히 체크했어요.', example_en_4 = 'Sports drinks can assist with hydration during long events.', example_ko_4 = '스포츠 음료는 긴 경기 중 수분 보충에 도움이 될 수 있어요.', example_en_5 = 'Good hydration is as important as a good warm-up.', example_ko_5 = '수분 보충은 워밍업만큼 중요해요.' WHERE id = 'w_sports_B2_12';
UPDATE words SET example_en_2 = 'Adequate recovery between sessions prevents burnout.', example_ko_2 = '세션 사이에 충분한 회복은 번아웃을 예방해요.', example_en_3 = 'She uses sleep and nutrition to optimise her recovery.', example_ko_3 = '그녀는 회복을 최적화하기 위해 수면과 영양을 활용해요.', example_en_4 = 'He measured his heart rate to track his recovery progress.', example_ko_4 = '그는 회복 진행 상황을 추적하기 위해 심박수를 측정했어요.', example_en_5 = 'Recovery protocols have become highly sophisticated at the elite level.', example_ko_5 = '엘리트 수준에서 회복 프로토콜은 매우 정교해졌어요.' WHERE id = 'w_sports_B2_13';
UPDATE words SET example_en_2 = 'He has explosive power off the starting blocks.', example_ko_2 = '그는 출발 블록에서 폭발적인 힘을 가지고 있어요.', example_en_3 = 'Explosive movements require both strength and speed.', example_ko_3 = '폭발적인 움직임에는 힘과 속도가 모두 필요해요.', example_en_4 = 'She trains with plyometrics to develop explosive leg power.', example_ko_4 = '그녀는 폭발적인 다리 힘을 키우기 위해 플라이오메트릭을 훈련해요.', example_en_5 = 'Explosive acceleration is a key trait of elite sprinters.', example_ko_5 = '폭발적인 가속력은 엘리트 단거리 선수의 핵심적인 자질이에요.' WHERE id = 'w_sports_B2_14';
UPDATE words SET example_en_2 = 'Strength conditioning helps prevent common sports injuries.', example_ko_2 = '근력 컨디셔닝은 일반적인 스포츠 부상을 예방하는 데 도움이 돼요.', example_en_3 = 'Her conditioning routine includes yoga and resistance training.', example_ko_3 = '그녀의 컨디셔닝 루틴에는 요가와 저항 훈련이 포함돼요.', example_en_4 = 'Physical conditioning is tested before every major tournament.', example_ko_4 = '신체 컨디셔닝은 모든 주요 토너먼트 전에 테스트돼요.', example_en_5 = 'Year-round conditioning keeps athletes ready for any competition.', example_ko_5 = '연중 컨디셔닝은 선수들이 어떤 대회에서도 준비된 상태를 유지하게 해요.' WHERE id = 'w_sports_B2_15';
UPDATE words SET example_en_2 = 'Fatigue affects both physical and mental performance.', example_ko_2 = '피로는 신체적, 정신적 경기력 모두에 영향을 미쳐요.', example_en_3 = 'She pushed through fatigue to finish the race.', example_ko_3 = '그녀는 피로를 이겨내고 경주를 완주했어요.', example_en_4 = 'Muscle fatigue set in during the final stages of the match.', example_ko_4 = '경기 막바지에 근육 피로가 찾아왔어요.', example_en_5 = 'Monitoring fatigue levels is key to avoiding overtraining.', example_ko_5 = '과훈련을 피하려면 피로 수준을 모니터링하는 것이 중요해요.' WHERE id = 'w_sports_B2_16';
UPDATE words SET example_en_2 = 'Her resilience after injury impressed the whole coaching team.', example_ko_2 = '부상 후에도 흔들리지 않는 그녀의 강인함이 코칭팀 전체를 감동시켰어요.', example_en_3 = 'Mental resilience separates champions from the rest.', example_ko_3 = '정신적 회복력이 챔피언과 나머지를 구분 짓는 요소예요.', example_en_4 = 'He showed resilience by bouncing back after three defeats.', example_ko_4 = '그는 세 번의 패배 후 다시 일어서며 회복력을 보여 줬어요.', example_en_5 = 'Building resilience takes experience, time, and a supportive environment.', example_ko_5 = '회복력을 키우려면 경험과 시간, 그리고 지지하는 환경이 필요해요.' WHERE id = 'w_sports_B2_17';
UPDATE words SET example_en_2 = 'The turnover in possession led directly to a goal.', example_ko_2 = '볼 점유 상실이 곧바로 실점으로 이어졌어요.', example_en_3 = 'Reducing turnovers is a key priority for the coaching staff.', example_ko_3 = '턴오버를 줄이는 것이 코칭 스태프의 핵심 우선 과제예요.', example_en_4 = 'High-intensity pressing forces opponents into turnovers.', example_ko_4 = '강렬한 압박은 상대방이 볼을 내주게 만들어요.', example_en_5 = 'The team''s turnover rate was the lowest in the league.', example_ko_5 = '팀의 볼 손실률은 리그에서 가장 낮았어요.' WHERE id = 'w_sports_B2_18';
UPDATE words SET example_en_2 = 'She set a new personal benchmark at the championship.', example_ko_2 = '그녀는 선수권 대회에서 새로운 개인 기준치를 세웠어요.', example_en_3 = 'The training programme uses benchmarks to measure progress.', example_ko_3 = '훈련 프로그램은 진도를 측정하기 위해 기준치를 사용해요.', example_en_4 = 'Industry benchmarks help clubs evaluate player performance objectively.', example_ko_4 = '업계 기준치는 클럽들이 선수 경기력을 객관적으로 평가하는 데 도움이 돼요.', example_en_5 = 'His performance this season has set a new benchmark for the club.', example_ko_5 = '이번 시즌 그의 경기력은 클럽에 새로운 기준을 세웠어요.' WHERE id = 'w_sports_B2_19';
UPDATE words SET example_en_2 = 'Signs of overtraining include persistent fatigue and poor sleep.', example_ko_2 = '과훈련의 징후에는 지속적인 피로와 수면 장애가 포함돼요.', example_en_3 = 'She was advised to rest after showing signs of overtraining.', example_ko_3 = '그녀는 과훈련 징후를 보여 휴식을 권고받았어요.', example_en_4 = 'Overtraining can set an athlete back by weeks or even months.', example_ko_4 = '과훈련은 선수를 몇 주 또는 몇 달씩 뒤처지게 만들 수 있어요.', example_en_5 = 'Proper periodization is the best way to avoid overtraining.', example_ko_5 = '과훈련을 피하는 가장 좋은 방법은 적절한 주기화예요.' WHERE id = 'w_sports_B2_20';
UPDATE words SET example_en_2 = 'His cycling cadence averaged ninety revolutions per minute.', example_ko_2 = '그의 사이클링 케이던스는 분당 평균 90회전이었어요.', example_en_3 = 'She adjusted her running cadence to reduce joint impact.', example_ko_3 = '그녀는 관절 충격을 줄이기 위해 달리기 케이던스를 조정했어요.', example_en_4 = 'Cadence is an important metric for both cyclists and runners.', example_ko_4 = '케이던스는 사이클리스트와 러너 모두에게 중요한 지표예요.', example_en_5 = 'Improving cadence is one of the easiest ways to run more efficiently.', example_ko_5 = '케이던스를 향상시키는 것은 더 효율적으로 달리는 가장 쉬운 방법 중 하나예요.' WHERE id = 'w_sports_B2_21';
UPDATE words SET example_en_2 = 'The scouting team attended games across three continents.', example_ko_2 = '스카우트팀은 세 개 대륙의 경기에 참석했어요.', example_en_3 = 'She was discovered through scouting at a local youth tournament.', example_ko_3 = '그녀는 지역 유소년 토너먼트에서의 스카우팅을 통해 발견됐어요.', example_en_4 = 'Modern scouting relies heavily on video analysis and data reports.', example_ko_4 = '현대 스카우팅은 영상 분석과 데이터 보고서에 크게 의존해요.', example_en_5 = 'Good scouting can give a club a competitive advantage in recruitment.', example_ko_5 = '좋은 스카우팅은 클럽에 선수 영입에서 경쟁 우위를 줄 수 있어요.' WHERE id = 'w_sports_B2_22';
UPDATE words SET example_en_2 = 'She trained alongside elite athletes from around the world.', example_ko_2 = '그녀는 전 세계 엘리트 선수들과 함께 훈련했어요.', example_en_3 = 'Reaching elite status requires years of dedicated training.', example_ko_3 = '엘리트 수준에 도달하려면 수년간의 헌신적인 훈련이 필요해요.', example_en_4 = 'He was selected for the elite development programme at sixteen.', example_ko_4 = '그는 열여섯 살에 엘리트 개발 프로그램에 선발됐어요.', example_en_5 = 'Elite performers dedicate every aspect of their lives to their sport.', example_ko_5 = '엘리트 선수들은 삶의 모든 측면을 자신의 스포츠에 바쳐요.' WHERE id = 'w_sports_B2_23';
UPDATE words SET example_en_2 = 'Performance metrics showed her endurance improved by twenty per cent.', example_ko_2 = '경기력 지표는 그녀의 지구력이 20% 향상됐음을 보여 줬어요.', example_en_3 = 'The club uses several key metrics to evaluate player readiness.', example_ko_3 = '클럽은 선수 준비 상태를 평가하기 위해 여러 핵심 지표를 사용해요.', example_en_4 = 'She monitors her training metrics through a wearable device.', example_ko_4 = '그녀는 웨어러블 기기를 통해 훈련 지표를 모니터링해요.', example_en_5 = 'Data metrics have become central to modern sports management.', example_ko_5 = '데이터 지표는 현대 스포츠 관리의 핵심이 됐어요.' WHERE id = 'w_sports_B2_24';
UPDATE words SET example_en_2 = 'She trained at high intensity three times a week.', example_ko_2 = '그녀는 일주일에 세 번 높은 강도로 훈련했어요.', example_en_3 = 'The intensity of the final was unlike anything he had experienced.', example_ko_3 = '그 결승전의 강도는 그가 경험해 본 것과는 달랐어요.', example_en_4 = 'Gradually increasing training intensity reduces the risk of injury.', example_ko_4 = '훈련 강도를 점진적으로 높이면 부상 위험이 줄어요.', example_en_5 = 'High-intensity interval training has transformed her fitness level.', example_ko_5 = '고강도 인터벌 훈련이 그녀의 체력 수준을 완전히 바꿔 놓았어요.' WHERE id = 'w_sports_B2_25';
UPDATE words SET example_en_2 = 'Dehydration reduces both strength and cognitive performance.', example_ko_2 = '탈수는 근력과 인지 능력 모두를 감소시켜요.', example_en_3 = 'She suffered mild dehydration during the marathon in hot weather.', example_ko_3 = '그녀는 더운 날씨에 마라톤을 하다가 가벼운 탈수 증세를 겪었어요.', example_en_4 = 'Even slight dehydration can impair an athlete''s performance.', example_ko_4 = '약간의 탈수만으로도 선수의 경기력이 저하될 수 있어요.', example_en_5 = 'Athletes must drink regularly to prevent dehydration during training.', example_ko_5 = '선수들은 훈련 중 탈수를 예방하기 위해 규칙적으로 수분을 섭취해야 해요.' WHERE id = 'w_sports_B2_26';
UPDATE words SET example_en_2 = 'Good coordination between defenders prevents gaps in the backline.', example_ko_2 = '수비수들 간의 좋은 협응력은 수비 라인의 빈틈을 막아요.', example_en_3 = 'She demonstrated excellent hand-eye coordination in the drill.', example_ko_3 = '그녀는 훈련에서 뛰어난 눈-손 협응력을 보여 줬어요.', example_en_4 = 'Coordination exercises are part of every athlete''s daily warm-up.', example_ko_4 = '협응력 훈련은 모든 선수의 일일 워밍업에 포함돼요.', example_en_5 = 'His coordination allows him to control the ball in tight spaces.', example_ko_5 = '그의 협응력은 좁은 공간에서도 공을 컨트롤할 수 있게 해 줘요.' WHERE id = 'w_sports_B2_27';
UPDATE words SET example_en_2 = 'The team has been dominant in their domestic league for years.', example_ko_2 = '팀은 수년간 자국 리그에서 지배적이었어요.', example_en_3 = 'She played a dominant role in every match this season.', example_ko_3 = '그녀는 이번 시즌 매 경기에서 지배적인 역할을 했어요.', example_en_4 = 'Their dominant display silenced even the most critical fans.', example_ko_4 = '그들의 압도적인 경기력은 가장 비판적인 팬들조차 침묵시켰어요.', example_en_5 = 'A dominant team sets the pace and forces opponents to react.', example_ko_5 = '지배적인 팀은 페이스를 설정하고 상대방이 반응하게 만들어요.' WHERE id = 'w_sports_B2_28';
UPDATE words SET example_en_2 = 'The training load must be carefully managed during a long season.', example_ko_2 = '긴 시즌 동안 훈련 부하를 신중하게 관리해야 해요.', example_en_3 = 'She reduced her load in the week before the final.', example_ko_3 = '그녀는 결승전 전주에 훈련 부하를 줄였어요.', example_en_4 = 'High training load without recovery increases injury risk.', example_ko_4 = '회복 없이 높은 훈련 부하를 유지하면 부상 위험이 높아져요.', example_en_5 = 'Tracking load data helps coaches make informed decisions about rest.', example_ko_5 = '부하 데이터를 추적하면 코치가 휴식에 대한 정보에 기반한 결정을 내리는 데 도움이 돼요.' WHERE id = 'w_sports_B2_29';
UPDATE words SET example_en_2 = 'She used her size to leverage the defender out of position.', example_ko_2 = '그녀는 체격을 이용해 수비수를 제자리에서 밀어냈어요.', example_en_3 = 'Data analytics gives small clubs leverage in player recruitment.', example_ko_3 = '데이터 분석학은 소규모 클럽에게 선수 영입에서 우위를 줘요.', example_en_4 = 'He used his experience as leverage during contract talks.', example_ko_4 = '그는 계약 협상에서 자신의 경험을 협상 카드로 활용했어요.', example_en_5 = 'Understanding leverage in sport means knowing when and where to apply pressure.', example_ko_5 = '스포츠에서의 레버리지는 언제 어디서 압박을 가해야 할지 아는 것이에요.' WHERE id = 'w_sports_B2_30';
UPDATE words SET example_en_2 = 'The team follows a strict concussion protocol.', example_ko_2 = '팀은 엄격한 뇌진탕 프로토콜을 따라요.', example_en_3 = 'She designed a new warm-up protocol for the squad.', example_ko_3 = '그녀는 선수단을 위한 새로운 워밍업 프로토콜을 설계했어요.', example_en_4 = 'All clubs must adhere to the federation''s match-day protocol.', example_ko_4 = '모든 클럽은 연맹의 경기 당일 프로토콜을 준수해야 해요.', example_en_5 = 'A clear return-to-play protocol protects athletes after injury.', example_ko_5 = '명확한 복귀 프로토콜은 부상 후 선수를 보호해요.' WHERE id = 'w_sports_B2_31';
UPDATE words SET example_en_2 = 'The transition from defence to attack was fast and precise.', example_ko_2 = '수비에서 공격으로의 전환이 빠르고 정확했어요.', example_en_3 = 'She excelled in transition situations during the match.', example_ko_3 = '그녀는 경기 중 전환 상황에서 뛰어난 능력을 보였어요.', example_en_4 = 'Winning the transition battle often determines the outcome of a match.', example_ko_4 = '전환 싸움에서 이기는 것이 종종 경기 결과를 결정해요.', example_en_5 = 'Quick transitions from defence to attack catch opponents off guard.', example_ko_5 = '수비에서 공격으로의 빠른 전환은 상대방의 허를 찌를 수 있어요.' WHERE id = 'w_sports_B2_32';
UPDATE words SET example_en_2 = 'Coaches simulate match conditions during training to prepare players.', example_ko_2 = '코치는 선수들을 준비시키기 위해 훈련 중 경기 상황을 시뮬레이션해요.', example_en_3 = 'She simulated race pressure by setting time-based training goals.', example_ko_3 = '그녀는 시간 기반의 훈련 목표를 설정해 경기 압박을 시뮬레이션했어요.', example_en_4 = 'The tactical board was used to simulate the opponent''s expected formation.', example_ko_4 = '전술판을 이용해 상대방의 예상 포메이션을 시뮬레이션했어요.', example_en_5 = 'Simulating fatigue in training helps athletes cope better on match day.', example_ko_5 = '훈련 중 피로를 시뮬레이션하면 선수들이 경기 당일 더 잘 대처하는 데 도움이 돼요.' WHERE id = 'w_sports_B2_33';
UPDATE words SET example_en_2 = 'He underperformed in the crucial final match of the season.', example_ko_2 = '그는 시즌의 중요한 마지막 경기에서 기대에 못 미쳤어요.', example_en_3 = 'She tended to underperform under extreme pressure situations.', example_ko_3 = '그녀는 극심한 압박 상황에서 기대에 미치지 못하는 경향이 있었어요.', example_en_4 = 'Teams that underperform in the early rounds rarely reach the final.', example_ko_4 = '초반 라운드에서 부진한 팀이 결승까지 가는 경우는 드물어요.', example_en_5 = 'Analysing why players underperform can guide better training choices.', example_ko_5 = '선수들이 왜 부진한지 분석하면 더 나은 훈련 방향을 안내할 수 있어요.' WHERE id = 'w_sports_B2_34';
UPDATE words SET example_en_2 = 'The team''s output in the final third improved dramatically.', example_ko_2 = '팀의 최전방 구역에서의 성과가 크게 향상됐어요.', example_en_3 = 'She measures her daily output using a fitness tracker.', example_ko_3 = '그녀는 피트니스 트래커를 사용해 매일의 성과를 측정해요.', example_en_4 = 'High output training sessions require longer recovery windows.', example_ko_4 = '고강도 출력 훈련 세션은 더 긴 회복 시간이 필요해요.', example_en_5 = 'Power output is a critical measurement in sprint and jump sports.', example_ko_5 = '파워 출력은 스프린트와 점프 종목에서 중요한 측정 지표예요.' WHERE id = 'w_sports_B2_35';
UPDATE words SET example_en_2 = 'Kinesiology underpins evidence-based rehabilitation programmes.', example_ko_2 = '운동학은 증거 기반 재활 프로그램의 토대가 돼요.', example_en_3 = 'She studied kinesiology to better understand how muscles work.', example_ko_3 = '그녀는 근육이 어떻게 작동하는지 더 잘 이해하기 위해 운동학을 공부했어요.', example_en_4 = 'Kinesiology applies physics and anatomy to the study of human movement.', example_ko_4 = '운동학은 인체 움직임 연구에 물리학과 해부학을 적용해요.', example_en_5 = 'His degree in kinesiology gave him an advantage in coaching.', example_ko_5 = '운동학 학위는 그에게 코칭에서 유리한 점을 줬어요.' WHERE id = 'w_sports_C1_01';
UPDATE words SET example_en_2 = 'Proprioception training reduces ankle sprain recurrence.', example_ko_2 = '고유수용성 훈련은 발목 염좌 재발을 줄여요.', example_en_3 = 'She relies on proprioception to balance on uneven ground.', example_ko_3 = '그녀는 울퉁불퉁한 땅 위에서 균형을 잡기 위해 고유수용성 감각에 의존해요.', example_en_4 = 'Proprioception is crucial for athletes who change direction frequently.', example_ko_4 = '방향을 자주 바꾸는 선수들에게는 고유수용성 감각이 매우 중요해요.', example_en_5 = 'Balance boards are commonly used to improve proprioception after injury.', example_ko_5 = '부상 후 고유수용성 감각을 향상시키기 위해 밸런스 보드가 일반적으로 사용돼요.' WHERE id = 'w_sports_C1_02';
UPDATE words SET example_en_2 = 'Training near VO2 max builds significant aerobic capacity.', example_ko_2 = 'VO2 최대 근처에서 훈련하면 상당한 유산소 능력이 향상돼요.', example_en_3 = 'Her VO2 max score placed her in the top percentile for her age.', example_ko_3 = '그녀의 VO2 최대 점수는 같은 나이에서 최상위 백분위수에 위치해요.', example_en_4 = 'VO2 max is widely used as a predictor of endurance performance.', example_ko_4 = 'VO2 최대는 지구력 경기력의 예측 지표로 널리 사용돼요.', example_en_5 = 'Altitude training can significantly raise an athlete''s VO2 max.', example_ko_5 = '고지 훈련은 선수의 VO2 최대를 크게 높일 수 있어요.' WHERE id = 'w_sports_C1_03';
UPDATE words SET example_en_2 = 'Training at the lactate threshold improves race-pace endurance.', example_ko_2 = '젖산 역치에서 훈련하면 레이스 페이스 지구력이 향상돼요.', example_en_3 = 'She identified her lactate threshold through a laboratory test.', example_ko_3 = '그녀는 실험실 검사를 통해 젖산 역치를 확인했어요.', example_en_4 = 'Raising the lactate threshold delays fatigue onset during competition.', example_ko_4 = '젖산 역치를 높이면 경기 중 피로 시작을 지연시켜요.', example_en_5 = 'Lactate threshold testing informs how intensely an athlete should train.', example_ko_5 = '젖산 역치 검사는 선수가 얼마나 강도 높게 훈련해야 할지 알려줘요.' WHERE id = 'w_sports_C1_04';
UPDATE words SET example_en_2 = 'The periodization plan divides the season into build, peak, and taper phases.', example_ko_2 = '주기화 계획은 시즌을 빌드, 피크, 테이퍼 단계로 나눠요.', example_en_3 = 'She refined her periodization based on her previous competition results.', example_ko_3 = '그녀는 이전 대회 결과를 바탕으로 주기화를 정교하게 다듬었어요.', example_en_4 = 'Effective periodization balances volume and intensity across the training year.', example_ko_4 = '효과적인 주기화는 훈련 연도 전반에 걸쳐 양과 강도의 균형을 맞춰요.', example_en_5 = 'Without structured periodization, athletes plateau and performance stagnates.', example_ko_5 = '구조화된 주기화 없이는 선수들이 정체기에 머물고 경기력이 정체돼요.' WHERE id = 'w_sports_C1_05';
UPDATE words SET example_en_2 = 'Sport psychology teaches athletes to control anxiety before competition.', example_ko_2 = '스포츠 심리학은 선수들이 경기 전 불안을 조절하는 방법을 가르쳐요.', example_en_3 = 'She worked with a sport psychology consultant throughout the season.', example_ko_3 = '그녀는 시즌 내내 스포츠 심리학 전문가와 함께 작업했어요.', example_en_4 = 'Sport psychology focuses on mental skills like focus, confidence, and composure.', example_ko_4 = '스포츠 심리학은 집중력, 자신감, 침착성 같은 정신적 기술에 초점을 맞춰요.', example_en_5 = 'Many elite athletes now integrate sport psychology into their training routines.', example_ko_5 = '많은 엘리트 선수들이 이제 훈련 루틴에 스포츠 심리학을 통합해요.' WHERE id = 'w_sports_C1_06';
UPDATE words SET example_en_2 = 'The ethics of performance enhancement are widely debated in sport.', example_ko_2 = '경기력 향상의 윤리는 스포츠에서 광범위하게 논의돼요.', example_en_3 = 'She upheld the ethics of clean sport throughout her career.', example_ko_3 = '그녀는 선수 생활 내내 클린 스포츠의 윤리를 지켰어요.', example_en_4 = 'Ethics in coaching involves treating all athletes with equal respect.', example_ko_4 = '코칭 윤리에는 모든 선수를 동등하게 존중하는 것이 포함돼요.', example_en_5 = 'Sports organisations must enforce clear ethics policies to protect athletes.', example_ko_5 = '스포츠 단체는 선수를 보호하기 위해 명확한 윤리 정책을 시행해야 해요.' WHERE id = 'w_sports_C1_07';
UPDATE words SET example_en_2 = 'Weak governance in sports federations allows corruption to go unchecked.', example_ko_2 = '스포츠 연맹의 약한 거버넌스는 부패가 통제되지 않고 진행되도록 해요.', example_en_3 = 'She advocated for stronger governance to protect athletes'' rights.', example_ko_3 = '그녀는 선수들의 권리를 보호하기 위해 더 강력한 거버넌스를 옹호했어요.', example_en_4 = 'Transparent governance builds trust between organisations and the public.', example_ko_4 = '투명한 거버넌스는 기관과 대중 사이의 신뢰를 쌓아요.', example_en_5 = 'Governance reforms have transformed how several major sporting bodies operate.', example_ko_5 = '거버넌스 개혁은 여러 주요 스포츠 기관이 운영되는 방식을 바꿔 놓았어요.' WHERE id = 'w_sports_C1_08';
UPDATE words SET example_en_2 = 'Neuromuscular fatigue impairs both speed and coordination.', example_ko_2 = '신경근 피로는 속도와 협응력 모두를 저하시켜요.', example_en_3 = 'She underwent neuromuscular testing to assess her readiness.', example_ko_3 = '그녀는 준비 상태를 평가하기 위해 신경근 검사를 받았어요.', example_en_4 = 'Neuromuscular control is essential in sports requiring rapid direction change.', example_ko_4 = '빠른 방향 전환이 필요한 스포츠에서 신경근 제어는 필수적이에요.', example_en_5 = 'Strength training enhances neuromuscular efficiency over time.', example_ko_5 = '근력 훈련은 시간이 지남에 따라 신경근 효율성을 향상시켜요.' WHERE id = 'w_sports_C1_09';
UPDATE words SET example_en_2 = 'She began a taper phase three weeks before the major race.', example_ko_2 = '그녀는 주요 경주 3주 전부터 테이퍼 단계를 시작했어요.', example_en_3 = 'A well-executed taper leaves athletes feeling fresh and fast.', example_ko_3 = '잘 실행된 테이퍼는 선수들이 상쾌하고 빠르다고 느끼게 해요.', example_en_4 = 'He reduced mileage significantly during the taper without losing fitness.', example_ko_4 = '그는 체력을 잃지 않으면서 테이퍼 기간에 훈련량을 크게 줄였어요.', example_en_5 = 'Taper timing is a science that experienced coaches study carefully.', example_ko_5 = '테이퍼 타이밍은 경험 많은 코치들이 신중하게 연구하는 과학이에요.' WHERE id = 'w_sports_C1_10';
UPDATE words SET example_en_2 = 'Overreaching for a short period can stimulate adaptation if managed correctly.', example_ko_2 = '올바르게 관리되면 단기간의 과부하는 적응을 자극할 수 있어요.', example_en_3 = 'She showed signs of overreaching after two weeks of intense camp.', example_ko_3 = '그녀는 2주간의 강도 높은 캠프 후 과부하 징후를 보였어요.', example_en_4 = 'The line between productive overreaching and harmful overtraining is thin.', example_ko_4 = '생산적인 과부하와 해로운 과훈련 사이의 경계는 얇아요.', example_en_5 = 'Coaches monitor mood and sleep to detect early overreaching.', example_ko_5 = '코치들은 기분과 수면을 모니터링해 초기 과부하를 감지해요.' WHERE id = 'w_sports_C1_11';
UPDATE words SET example_en_2 = 'Isometric exercises are used during early stages of injury rehabilitation.', example_ko_2 = '등척성 운동은 부상 재활 초기 단계에서 사용돼요.', example_en_3 = 'She added isometric holds to her strength programme.', example_ko_3 = '그녀는 근력 프로그램에 등척성 홀드를 추가했어요.', example_en_4 = 'Isometric contractions build tendon strength without joint movement.', example_ko_4 = '등척성 수축은 관절 움직임 없이 힘줄 강도를 높여요.', example_en_5 = 'An isometric wall sit is a simple but effective lower-body exercise.', example_ko_5 = '등척성 월싯은 간단하지만 효과적인 하체 운동이에요.' WHERE id = 'w_sports_C1_12';
UPDATE words SET example_en_2 = 'Plyometrics develops fast-twitch muscle fibre power.', example_ko_2 = '플라이오메트릭은 속근 근섬유 파워를 발달시켜요.', example_en_3 = 'She incorporated plyometrics into her pre-season training block.', example_ko_3 = '그녀는 시즌 전 훈련 블록에 플라이오메트릭을 포함시켰어요.', example_en_4 = 'Box jumps are a classic plyometrics exercise for power athletes.', example_ko_4 = '박스 점프는 파워 선수들을 위한 전형적인 플라이오메트릭 운동이에요.', example_en_5 = 'Plyometrics must be progressed carefully to avoid tendon overload.', example_ko_5 = '플라이오메트릭은 힘줄 과부하를 피하기 위해 신중하게 진행해야 해요.' WHERE id = 'w_sports_C1_13';
UPDATE words SET example_en_2 = 'Hypertrophy training involves higher volume and moderate load.', example_ko_2 = '근비대 훈련은 더 높은 볼륨과 적당한 부하를 포함해요.', example_en_3 = 'She focused on hypertrophy during the off-season to add muscle mass.', example_ko_3 = '그녀는 근육량을 늘리기 위해 비시즌에 근비대에 집중했어요.', example_en_4 = 'Hypertrophy and strength are distinct but related goals in training.', example_ko_4 = '근비대와 근력은 구별되지만 훈련에서 관련된 목표예요.', example_en_5 = 'Adequate protein intake is essential for muscle hypertrophy.', example_ko_5 = '근육 비대를 위해서는 충분한 단백질 섭취가 필수적이에요.' WHERE id = 'w_sports_C1_14';
UPDATE words SET example_en_2 = 'Anaerobic capacity is crucial for high-intensity sports like sprinting.', example_ko_2 = '무산소 능력은 스프린트와 같은 고강도 스포츠에서 중요해요.', example_en_3 = 'She trained anaerobic pathways through repeated short sprints.', example_ko_3 = '그녀는 반복적인 단거리 스프린트를 통해 무산소 경로를 훈련했어요.', example_en_4 = 'Anaerobic metabolism produces energy rapidly but leads to lactate build-up.', example_ko_4 = '무산소 대사는 에너지를 빠르게 생산하지만 젖산이 축적돼요.', example_en_5 = 'Most ball sports rely on a combination of aerobic and anaerobic systems.', example_ko_5 = '대부분의 구기 스포츠는 유산소와 무산소 시스템의 조합에 의존해요.' WHERE id = 'w_sports_C1_15';
UPDATE words SET example_en_2 = 'Sarcopenia accelerates if older athletes do not maintain strength training.', example_ko_2 = '나이 든 선수들이 근력 훈련을 유지하지 않으면 근육감소증이 가속돼요.', example_en_3 = 'Early sarcopenia onset can shorten an athlete''s career significantly.', example_ko_3 = '근육감소증의 조기 발병은 선수 생활을 크게 단축시킬 수 있어요.', example_en_4 = 'Research links sarcopenia with reduced athletic performance in masters athletes.', example_ko_4 = '연구에 따르면 근육감소증은 마스터스 선수들의 경기력 저하와 관련이 있어요.', example_en_5 = 'Resistance training is the most effective intervention against sarcopenia.', example_ko_5 = '저항 훈련은 근육감소증에 맞서는 가장 효과적인 중재 방법이에요.' WHERE id = 'w_sports_C1_16';
UPDATE words SET example_en_2 = 'Elevated cortisol after training is a normal physiological response.', example_ko_2 = '훈련 후 코르티솔 수치 상승은 정상적인 생리적 반응이에요.', example_en_3 = 'Chronic high cortisol is associated with overtraining syndrome.', example_ko_3 = '만성적인 고코르티솔은 과훈련 증후군과 관련이 있어요.', example_en_4 = 'She measured her morning cortisol levels to track recovery status.', example_ko_4 = '그녀는 회복 상태를 추적하기 위해 아침 코르티솔 수치를 측정했어요.', example_en_5 = 'Sleep quality significantly affects cortisol regulation in athletes.', example_ko_5 = '수면의 질은 선수들의 코르티솔 조절에 크게 영향을 미쳐요.' WHERE id = 'w_sports_C1_17';
UPDATE words SET example_en_2 = 'Tendinopathy often develops from repetitive overuse during training.', example_ko_2 = '건병증은 훈련 중 반복적인 과사용으로 흔히 발생해요.', example_en_3 = 'She managed her tendinopathy with load management and physiotherapy.', example_ko_3 = '그녀는 부하 관리와 물리치료로 건병증을 관리했어요.', example_en_4 = 'Patellar tendinopathy is common in jumping athletes.', example_ko_4 = '슬개건병증은 점프 선수들에게 흔해요.', example_en_5 = 'Early diagnosis of tendinopathy can prevent it from becoming a long-term problem.', example_ko_5 = '건병증을 조기에 진단하면 장기적인 문제가 되는 것을 예방할 수 있어요.' WHERE id = 'w_sports_C1_18';
UPDATE words SET example_en_2 = 'Kinesthesia allows athletes to sense where their limbs are in space.', example_ko_2 = '운동 감각은 선수들이 공간에서 사지의 위치를 감지할 수 있게 해 줘요.', example_en_3 = 'She developed kinesthesia through years of technical gymnastics training.', example_ko_3 = '그녀는 수년간의 기술 체조 훈련을 통해 운동 감각을 발달시켰어요.', example_en_4 = 'Kinesthesia and proprioception work together to produce fluid movement.', example_ko_4 = '운동 감각과 고유수용성 감각이 함께 작용해 유연한 움직임을 만들어요.', example_en_5 = 'Advanced kinesthesia is a hallmark of highly skilled athletes.', example_ko_5 = '뛰어난 운동 감각은 매우 숙련된 선수들의 특징이에요.' WHERE id = 'w_sports_C1_19';
UPDATE words SET example_en_2 = 'Eccentric contractions are known to generate the greatest muscle force.', example_ko_2 = '신장성 수축은 가장 큰 근력을 생성하는 것으로 알려져 있어요.', example_en_3 = 'She added eccentric exercises to strengthen her hamstrings.', example_ko_3 = '그녀는 햄스트링을 강화하기 위해 신장성 운동을 추가했어요.', example_en_4 = 'Eccentric training is particularly useful in tendon rehabilitation.', example_ko_4 = '신장성 훈련은 힘줄 재활에서 특히 유용해요.', example_en_5 = 'Nordic curls are a well-known eccentric hamstring exercise.', example_ko_5 = '노르딕 컬은 잘 알려진 신장성 햄스트링 운동이에요.' WHERE id = 'w_sports_C1_20';
UPDATE words SET example_en_2 = 'Metabolic conditioning improves the body''s ability to sustain effort.', example_ko_2 = '대사 컨디셔닝은 신체가 지속적인 노력을 유지하는 능력을 향상시켜요.', example_en_3 = 'She underwent metabolic testing to personalise her training zones.', example_ko_3 = '그녀는 훈련 구역을 개인화하기 위해 대사 검사를 받았어요.', example_en_4 = 'Metabolic adaptations from aerobic training take weeks to accumulate.', example_ko_4 = '유산소 훈련을 통한 대사 적응은 누적되는 데 몇 주가 걸려요.', example_en_5 = 'Understanding metabolic processes helps athletes optimise fuelling strategies.', example_ko_5 = '대사 과정을 이해하면 선수들이 에너지 보충 전략을 최적화하는 데 도움이 돼요.' WHERE id = 'w_sports_C1_21';
UPDATE words SET example_en_2 = 'Myofascial release techniques reduce tension in overworked muscles.', example_ko_2 = '근막 이완 기술은 과로한 근육의 긴장을 줄여요.', example_en_3 = 'She used a foam roller to address tightness in her fascia.', example_ko_3 = '그녀는 근막의 긴장을 풀기 위해 폼 롤러를 사용했어요.', example_en_4 = 'Healthy fascia ensures smooth and unrestricted movement patterns.', example_ko_4 = '건강한 근막은 부드럽고 자유로운 움직임 패턴을 보장해요.', example_en_5 = 'Fascial restrictions can contribute to chronic pain in athletes.', example_ko_5 = '근막 제한은 선수들의 만성 통증에 기여할 수 있어요.' WHERE id = 'w_sports_C1_22';
UPDATE words SET example_en_2 = 'Athletes exercising in heat rely on thermoregulation to prevent overheating.', example_ko_2 = '더위 속에서 운동하는 선수들은 과열을 막기 위해 체온 조절에 의존해요.', example_en_3 = 'She trained in hot conditions to improve her thermoregulation.', example_ko_3 = '그녀는 체온 조절 능력을 향상시키기 위해 더운 환경에서 훈련했어요.', example_en_4 = 'Efficient thermoregulation allows athletes to sustain output in warm weather.', example_ko_4 = '효율적인 체온 조절은 선수들이 따뜻한 날씨에도 성과를 유지하게 해 줘요.', example_en_5 = 'Cooling vests are used to assist thermoregulation during warm-up.', example_ko_5 = '쿨링 조끼는 워밍업 중 체온 조절을 돕기 위해 사용돼요.' WHERE id = 'w_sports_C1_23';
UPDATE words SET example_en_2 = 'Sodium and potassium are key electrolytes lost during intense exercise.', example_ko_2 = '나트륨과 칼륨은 격렬한 운동 중에 손실되는 주요 전해질이에요.', example_en_3 = 'She drinks electrolyte solution rather than plain water during long runs.', example_ko_3 = '그녀는 장거리 달리기 중에 맹물 대신 전해질 음료를 마셔요.', example_en_4 = 'Electrolyte imbalance leads to cramp and impaired muscle function.', example_ko_4 = '전해질 불균형은 경련과 근육 기능 저하로 이어져요.', example_en_5 = 'Replenishing electrolytes post-exercise is vital for fast recovery.', example_ko_5 = '운동 후 전해질을 보충하는 것은 빠른 회복에 매우 중요해요.' WHERE id = 'w_sports_C1_24';
UPDATE words SET example_en_2 = 'Gait analysis revealed that she over-pronated during running.', example_ko_2 = '보행 분석을 통해 그녀가 달릴 때 과도하게 내전된다는 것이 드러났어요.', example_en_3 = 'He had his gait assessed before selecting new running shoes.', example_ko_3 = '그는 새 러닝화를 고르기 전에 보행 분석을 받았어요.', example_en_4 = 'Abnormal gait patterns can cause chronic knee and hip pain.', example_ko_4 = '비정상적인 보행 패턴은 만성 무릎 및 고관절 통증을 유발할 수 있어요.', example_en_5 = 'Improving gait efficiency reduces energy expenditure over long distances.', example_ko_5 = '보행 효율성을 향상시키면 장거리에서 에너지 소비가 줄어요.' WHERE id = 'w_sports_C1_25';
UPDATE words SET example_en_2 = 'Creatine supplementation is one of the most researched ergogenic aids.', example_ko_2 = '크레아틴 보충제는 가장 많이 연구된 경기력 향상 보조제 중 하나예요.', example_en_3 = 'She used creatine to support her strength and power training.', example_ko_3 = '그녀는 근력 및 파워 훈련을 지원하기 위해 크레아틴을 사용했어요.', example_en_4 = 'Creatine loading increases phosphocreatine stores in muscle tissue.', example_ko_4 = '크레아틴 로딩은 근육 조직의 인산크레아틴 저장량을 늘려요.', example_en_5 = 'Short-duration high-intensity efforts benefit most from creatine supplementation.', example_ko_5 = '짧은 시간의 고강도 노력은 크레아틴 보충으로 가장 큰 혜택을 받아요.' WHERE id = 'w_sports_C1_26';
UPDATE words SET example_en_2 = 'Inflammation after training is a normal part of the recovery process.', example_ko_2 = '훈련 후 염증은 회복 과정의 정상적인 부분이에요.', example_en_3 = 'She managed chronic inflammation through diet and targeted therapy.', example_ko_3 = '그녀는 식이요법과 집중 치료를 통해 만성 염증을 관리했어요.', example_en_4 = 'Excessive inflammation can delay return to sport after injury.', example_ko_4 = '과도한 염증은 부상 후 스포츠 복귀를 지연시킬 수 있어요.', example_en_5 = 'Omega-3 fatty acids help modulate inflammation in active individuals.', example_ko_5 = '오메가-3 지방산은 활동적인 사람들의 염증을 조절하는 데 도움이 돼요.' WHERE id = 'w_sports_C1_27';
UPDATE words SET example_en_2 = 'Oxidative stress from intensive training can be countered with antioxidants.', example_ko_2 = '집중 훈련으로 인한 산화 스트레스는 항산화제로 대응할 수 있어요.', example_en_3 = 'She monitored biomarkers of oxidative damage to guide her recovery.', example_ko_3 = '그녀는 회복을 안내하기 위해 산화 손상의 생체 지표를 모니터링했어요.', example_en_4 = 'Oxidative phosphorylation underpins aerobic energy production in muscle cells.', example_ko_4 = '산화적 인산화는 근육 세포에서 유산소 에너지 생산의 근거가 돼요.', example_en_5 = 'Chronic oxidative stress impairs mitochondrial function in athletes.', example_ko_5 = '만성 산화 스트레스는 선수들의 미토콘드리아 기능을 손상시켜요.' WHERE id = 'w_sports_C1_28';
UPDATE words SET example_en_2 = 'She planned a structured deload week after every training block.', example_ko_2 = '그녀는 매 훈련 블록 후에 구조화된 디로드 주간을 계획했어요.', example_en_3 = 'A deload allows accumulated fatigue to dissipate without losing fitness.', example_ko_3 = '디로드는 체력을 잃지 않으면서 누적된 피로를 해소할 수 있게 해줘요.', example_en_4 = 'He ignored the deload and ended up with a stress fracture.', example_ko_4 = '그는 디로드를 무시하다가 결국 피로 골절을 당했어요.', example_en_5 = 'Many athletes underestimate how important a proper deload period is.', example_ko_5 = '많은 선수들이 적절한 디로드 기간이 얼마나 중요한지 과소평가해요.' WHERE id = 'w_sports_C1_29';
UPDATE words SET example_en_2 = 'A musculoskeletal assessment was done before the season began.', example_ko_2 = '시즌이 시작되기 전에 근골격계 평가가 실시됐어요.', example_en_3 = 'She suffered a musculoskeletal injury that kept her out for six weeks.', example_ko_3 = '그녀는 근골격계 부상으로 6주간 출전하지 못했어요.', example_en_4 = 'Musculoskeletal health is foundational to long-term athletic performance.', example_ko_4 = '근골격계 건강은 장기적인 운동 능력의 기초가 돼요.', example_en_5 = 'The physiotherapist specialises in musculoskeletal sports injuries.', example_ko_5 = '그 물리치료사는 근골격계 스포츠 부상을 전문으로 해요.' WHERE id = 'w_sports_C1_30';
UPDATE words SET example_en_2 = 'Catecholamine release during competition heightens alertness and performance.', example_ko_2 = '경기 중 카테콜아민 분비는 각성도와 경기력을 높여요.', example_en_3 = 'She studied how catecholamine responses vary with training status.', example_ko_3 = '그녀는 카테콜아민 반응이 훈련 상태에 따라 어떻게 달라지는지 연구했어요.', example_en_4 = 'Adrenaline is the most well-known catecholamine in sport contexts.', example_ko_4 = '아드레날린은 스포츠 맥락에서 가장 잘 알려진 카테콜아민이에요.', example_en_5 = 'Excessive catecholamine response may indicate overtraining or chronic stress.', example_ko_5 = '과도한 카테콜아민 반응은 과훈련이나 만성 스트레스를 나타낼 수 있어요.' WHERE id = 'w_sports_C1_31';
UPDATE words SET example_en_2 = 'Ergodynamics studies how athletes can sustain work output efficiently.', example_ko_2 = '에르고다이나믹스는 선수들이 효율적으로 작업 출력을 유지하는 방법을 연구해요.', example_en_3 = 'She applied ergodynamic principles to her pedalling stroke.', example_ko_3 = '그녀는 페달링 스트로크에 에르고다이나믹 원리를 적용했어요.', example_en_4 = 'Ergodynamics informs equipment design for greater energy economy.', example_ko_4 = '에르고다이나믹스는 더 큰 에너지 절감을 위한 장비 설계에 정보를 제공해요.', example_en_5 = 'Understanding ergodynamics helps coaches structure training for peak output.', example_ko_5 = '에르고다이나믹스를 이해하면 코치들이 최고 성과를 위한 훈련을 구성하는 데 도움이 돼요.' WHERE id = 'w_sports_C1_32';
UPDATE words SET example_en_2 = 'Anthropometry data guides position-specific training programmes.', example_ko_2 = '인체측정 데이터는 포지션별 훈련 프로그램을 안내해요.', example_en_3 = 'She was measured across twenty anthropometry markers at the pre-season screening.', example_ko_3 = '그녀는 시즌 전 검진에서 20개의 인체측정 지표를 측정받았어요.', example_en_4 = 'Anthropometry helps identify whether an athlete has the profile for a specific sport.', example_ko_4 = '인체측정은 선수가 특정 스포츠에 맞는 체형인지 파악하는 데 도움이 돼요.', example_en_5 = 'Talent identification programmes rely heavily on anthropometry assessments.', example_ko_5 = '재능 발굴 프로그램은 인체측정 평가에 크게 의존해요.' WHERE id = 'w_sports_C1_33';
UPDATE words SET example_en_2 = 'Spinal decompression therapy is used to treat disc-related back injuries.', example_ko_2 = '척추 감압 치료는 디스크 관련 허리 부상을 치료하는 데 사용돼요.', example_en_3 = 'She incorporated spinal decompression exercises into her daily routine.', example_ko_3 = '그녀는 척추 감압 운동을 일상 루틴에 포함시켰어요.', example_en_4 = 'Decompression time between sets allows the spine to recover.', example_ko_4 = '세트 사이의 감압 시간은 척추가 회복할 수 있게 해 줘요.', example_en_5 = 'Aquatic therapy can offer gentle spinal decompression for injured athletes.', example_ko_5 = '수중 치료는 부상당한 선수들에게 부드러운 척추 감압을 제공할 수 있어요.' WHERE id = 'w_sports_C1_34';
UPDATE words SET example_en_2 = 'Psychomotor speed is a key predictor of performance in racquet sports.', example_ko_2 = '정신운동 속도는 라켓 스포츠에서 경기력의 중요한 예측 지표예요.', example_en_3 = 'She improved her psychomotor reaction time through sport-specific drills.', example_ko_3 = '그녀는 스포츠별 드릴을 통해 정신운동 반응 시간을 향상시켰어요.', example_en_4 = 'Psychomotor fatigue under prolonged competition impairs decision-making.', example_ko_4 = '장시간 경기 중 정신운동 피로는 의사결정 능력을 저하시켜요.', example_en_5 = 'Training psychomotor precision is as important as physical conditioning.', example_ko_5 = '정신운동 정밀도를 훈련하는 것은 신체 컨디셔닝만큼 중요해요.' WHERE id = 'w_sports_C1_35';
UPDATE words SET example_en_2 = 'Biomechanical modelling predicts the forces acting on joints during sport.', example_ko_2 = '생체역학 모델링은 스포츠 중 관절에 작용하는 힘을 예측해요.', example_en_3 = 'She underwent biomechanical assessment to correct her rowing technique.', example_ko_3 = '그녀는 조정 기술을 교정하기 위해 생체역학 평가를 받았어요.', example_en_4 = 'Biomechanical efficiency determines how much energy an athlete expends per stride.', example_ko_4 = '생체역학적 효율성은 선수가 보폭당 소비하는 에너지량을 결정해요.', example_en_5 = 'Advances in biomechanical analysis have revolutionised sports performance research.', example_ko_5 = '생체역학 분석의 발전은 스포츠 경기력 연구에 혁명을 가져왔어요.' WHERE id = 'w_sports_C2_01';
UPDATE words SET example_en_2 = 'Neuromotor control deteriorates rapidly under extreme fatigue.', example_ko_2 = '신경운동 제어는 극도의 피로 상태에서 급격히 저하돼요.', example_en_3 = 'She trained neuromotor pathways through reactive agility exercises.', example_ko_3 = '그녀는 반응형 민첩성 운동을 통해 신경운동 경로를 훈련했어요.', example_en_4 = 'Neuromotor adaptations are central to mastering complex sport skills.', example_ko_4 = '신경운동 적응은 복잡한 스포츠 기술을 마스터하는 데 핵심이에요.', example_en_5 = 'Research in neuromotor function has informed new approaches to stroke rehabilitation.', example_ko_5 = '신경운동 기능에 대한 연구는 뇌졸중 재활의 새로운 접근 방식에 정보를 제공했어요.' WHERE id = 'w_sports_C2_02';
UPDATE words SET example_en_2 = 'Chronobiology reveals that peak athletic performance often occurs in late afternoon.', example_ko_2 = '생체시간학은 최고 운동 능력이 종종 늦은 오후에 나타난다는 것을 보여줘요.', example_en_3 = 'She aligned her training schedule with chronobiological principles.', example_ko_3 = '그녀는 생체시간학 원리에 맞춰 훈련 일정을 조정했어요.', example_en_4 = 'Chronobiology research has changed how sports scientists schedule high-intensity sessions.', example_ko_4 = '생체시간학 연구는 스포츠 과학자들이 고강도 세션을 계획하는 방식을 바꿨어요.', example_en_5 = 'Jet lag disrupts circadian rhythms, which is a core concern of chronobiology in sport.', example_ko_5 = '시차는 일주기 리듬을 교란시키며, 이것이 스포츠에서 생체시간학의 핵심 문제예요.' WHERE id = 'w_sports_C2_03';
UPDATE words SET example_en_2 = 'Caffeine is the most widely used ergogenic substance in competitive sport.', example_ko_2 = '카페인은 경쟁 스포츠에서 가장 널리 사용되는 에르고제닉 물질이에요.', example_en_3 = 'She reviewed the ergogenic evidence before deciding on supplementation.', example_ko_3 = '그녀는 보충제를 결정하기 전에 에르고제닉 증거를 검토했어요.', example_en_4 = 'Some ergogenic strategies are legal; others violate anti-doping regulations.', example_ko_4 = '일부 에르고제닉 전략은 합법적이지만, 다른 것들은 도핑 방지 규정을 위반해요.', example_en_5 = 'The ergogenic benefits of beetroot juice are supported by multiple peer-reviewed studies.', example_ko_5 = '비트 주스의 에르고제닉 효과는 여러 동료 심사 연구로 뒷받침돼요.' WHERE id = 'w_sports_C2_04';
UPDATE words SET example_en_2 = 'Myofascial tightness in the hip flexors can impair running mechanics.', example_ko_2 = '고관절 굴근의 근막 긴장은 달리기 역학을 손상시킬 수 있어요.', example_en_3 = 'She received myofascial release therapy after every long training session.', example_ko_3 = '그녀는 매 장시간 훈련 세션 후에 근막 이완 치료를 받았어요.', example_en_4 = 'Myofascial dysfunction can be a hidden cause of recurring soft-tissue injuries.', example_ko_4 = '근막 기능 장애는 반복되는 연부 조직 부상의 숨겨진 원인이 될 수 있어요.', example_en_5 = 'Understanding myofascial chains helps practitioners address the root cause of pain.', example_ko_5 = '근막 체인을 이해하면 시술자들이 통증의 근본 원인을 다루는 데 도움이 돼요.' WHERE id = 'w_sports_C2_05';
UPDATE words SET example_en_2 = 'Tensiomyography detects differences in muscle tone between the left and right sides.', example_ko_2 = '텐시오마이오그라피는 좌우 근육 긴장도의 차이를 감지해요.', example_en_3 = 'She used tensiomyography to monitor muscle readiness before competition.', example_ko_3 = '그녀는 경기 전 근육 준비 상태를 모니터링하기 위해 텐시오마이오그라피를 사용했어요.', example_en_4 = 'Tensiomyography is valued for its ability to assess muscle contractile properties non-invasively.', example_ko_4 = '텐시오마이오그라피는 비침습적으로 근육 수축 특성을 평가하는 능력으로 높이 평가돼요.', example_en_5 = 'Regular tensiomyography screening helps coaches detect overloaded muscle groups early.', example_ko_5 = '정기적인 텐시오마이오그라피 검사는 코치들이 과부하된 근육군을 조기에 발견하는 데 도움이 돼요.' WHERE id = 'w_sports_C2_06';
UPDATE words SET example_en_2 = 'Advanced plyometrics includes depth jumps and reactive bounding exercises.', example_ko_2 = '고급 플라이오메트릭에는 뎁스 점프와 반응형 바운딩 운동이 포함돼요.', example_en_3 = 'She built up to advanced plyometrics over a twelve-week progression.', example_ko_3 = '그녀는 12주 점진적 과정을 통해 고급 플라이오메트릭까지 발전했어요.', example_en_4 = 'Plyometrics requires a solid strength base before more advanced variations are introduced.', example_ko_4 = '플라이오메트릭은 더 고급 변형을 도입하기 전에 탄탄한 근력 기반이 필요해요.', example_en_5 = 'Plyometrics has become a staple component of athletic development programmes worldwide.', example_ko_5 = '플라이오메트릭은 전 세계 운동 개발 프로그램의 주요 구성 요소가 됐어요.' WHERE id = 'w_sports_C2_07';
UPDATE words SET example_en_2 = 'Psychomotor assessments measure reaction speed and movement accuracy simultaneously.', example_ko_2 = '정신운동 평가는 반응 속도와 움직임 정확도를 동시에 측정해요.', example_en_3 = 'She scored highly on the psychomotor tests conducted before the tournament.', example_ko_3 = '그녀는 토너먼트 전에 실시된 정신운동 테스트에서 높은 점수를 받았어요.', example_en_4 = 'Psychomotor precision declines with age but can be preserved through targeted training.', example_ko_4 = '정신운동 정밀도는 나이가 들면서 감소하지만 목표 훈련을 통해 유지될 수 있어요.', example_en_5 = 'Sports that demand rapid decision-making place great emphasis on psychomotor fitness.', example_ko_5 = '빠른 의사결정을 요구하는 스포츠는 정신운동 체력에 큰 비중을 두어요.' WHERE id = 'w_sports_C2_08';
UPDATE words SET example_en_2 = 'Glycolysis is the primary energy pathway during maximal short-duration efforts.', example_ko_2 = '해당과정은 최대 단기 노력 중 주요 에너지 경로예요.', example_en_3 = 'She understood glycolysis to better explain why lactate accumulates.', example_ko_3 = '그녀는 젖산이 왜 축적되는지 더 잘 설명하기 위해 해당과정을 이해했어요.', example_en_4 = 'Anaerobic glycolysis powers bursts of speed lasting six to thirty seconds.', example_ko_4 = '무산소 해당과정은 6~30초간 지속되는 속도 폭발을 가능하게 해요.', example_en_5 = 'Training can shift reliance away from glycolysis toward more efficient aerobic pathways.', example_ko_5 = '훈련은 해당과정에 대한 의존도를 더 효율적인 유산소 경로 쪽으로 이동시킬 수 있어요.' WHERE id = 'w_sports_C2_09';
UPDATE words SET example_en_2 = 'The ectomorph somatotype is often associated with endurance sports.', example_ko_2 = '외배엽형 체형은 종종 지구력 스포츠와 연관돼요.', example_en_3 = 'She studied somatotype to understand athlete selection in different sports.', example_ko_3 = '그녀는 다양한 스포츠에서 선수 선발을 이해하기 위해 체형을 공부했어요.', example_en_4 = 'Somatotype classification has limitations but provides a useful starting framework.', example_ko_4 = '체형 분류는 한계가 있지만 유용한 출발점 틀을 제공해요.', example_en_5 = 'Modern sports science has moved beyond rigid somatotype thinking.', example_ko_5 = '현대 스포츠 과학은 경직된 체형 분류 방식을 넘어섰어요.' WHERE id = 'w_sports_C2_10';
UPDATE words SET example_en_2 = 'Mitochondrial density increases with sustained aerobic training.', example_ko_2 = '미토콘드리아 밀도는 지속적인 유산소 훈련으로 증가해요.', example_en_3 = 'She improved her mitochondrial function through altitude training camps.', example_ko_3 = '그녀는 고지 훈련 캠프를 통해 미토콘드리아 기능을 향상시켰어요.', example_en_4 = 'Mitochondrial adaptations underpin the aerobic capacity of elite endurance athletes.', example_ko_4 = '미토콘드리아 적응은 엘리트 지구력 선수들의 유산소 능력의 기반이 돼요.', example_en_5 = 'Researchers are studying how mitochondrial biogenesis responds to interval training.', example_ko_5 = '연구자들은 미토콘드리아 생성이 인터벌 훈련에 어떻게 반응하는지 연구하고 있어요.' WHERE id = 'w_sports_C2_11';
UPDATE words SET example_en_2 = 'Electromyography records the electrical activity of muscles during contraction.', example_ko_2 = '근전도 검사는 수축 중 근육의 전기적 활동을 기록해요.', example_en_3 = 'She wore electromyography sensors during her sprint trials.', example_ko_3 = '그녀는 스프린트 시험 중에 근전도 검사 센서를 착용했어요.', example_en_4 = 'Electromyography helps identify which muscles are most active in a given exercise.', example_ko_4 = '근전도 검사는 특정 운동에서 가장 활성화된 근육을 파악하는 데 도움이 돼요.', example_en_5 = 'Surface electromyography is a non-invasive tool used widely in sports research.', example_ko_5 = '표면 근전도 검사는 스포츠 연구에서 널리 사용되는 비침습적 도구예요.' WHERE id = 'w_sports_C2_12';
UPDATE words SET example_en_2 = 'Phosphocreatine replenishment occurs rapidly during rest periods.', example_ko_2 = '인산크레아틴은 휴식 시간 동안 빠르게 보충돼요.', example_en_3 = 'She supplemented with creatine to maximise phosphocreatine stores.', example_ko_3 = '그녀는 인산크레아틴 저장량을 최대화하기 위해 크레아틴을 보충했어요.', example_en_4 = 'Phosphocreatine is the immediate energy source for very short explosive efforts.', example_ko_4 = '인산크레아틴은 매우 짧은 폭발적 노력을 위한 즉각적인 에너지원이에요.', example_en_5 = 'Understanding the phosphocreatine system helps coaches design optimal sprint recovery intervals.', example_ko_5 = '인산크레아틴 시스템을 이해하면 코치들이 최적의 스프린트 회복 인터벌을 설계하는 데 도움이 돼요.' WHERE id = 'w_sports_C2_13';
UPDATE words SET example_en_2 = 'Hemodynamics describes how blood flows through the cardiovascular system.', example_ko_2 = '혈역학은 혈액이 심혈관계를 통해 어떻게 흐르는지 설명해요.', example_en_3 = 'She studied hemodynamics to understand cardiac output during maximal exercise.', example_ko_3 = '그녀는 최대 운동 중 심박출량을 이해하기 위해 혈역학을 공부했어요.', example_en_4 = 'Hemodynamic responses to exercise training improve with sustained aerobic conditioning.', example_ko_4 = '운동 훈련에 대한 혈역학적 반응은 지속적인 유산소 컨디셔닝으로 향상돼요.', example_en_5 = 'Altitude reduces blood oxygen, altering hemodynamics and demanding cardiovascular adaptation.', example_ko_5 = '고도는 혈중 산소를 감소시켜 혈역학을 변화시키고 심혈관 적응을 요구해요.' WHERE id = 'w_sports_C2_14';
UPDATE words SET example_en_2 = 'Mechanoreceptors in ligaments signal joint position to the nervous system.', example_ko_2 = '인대의 기계수용체는 관절 위치를 신경계에 신호로 전달해요.', example_en_3 = 'She trained on unstable surfaces to stimulate mechanoreceptor activity.', example_ko_3 = '그녀는 기계수용체 활동을 자극하기 위해 불안정한 표면에서 훈련했어요.', example_en_4 = 'Mechanoreceptor damage following sprains can impair long-term joint stability.', example_ko_4 = '염좌 후 기계수용체 손상은 장기적인 관절 안정성을 손상시킬 수 있어요.', example_en_5 = 'Balance training restores mechanoreceptor sensitivity after lower limb injuries.', example_ko_5 = '균형 훈련은 하지 부상 후 기계수용체 민감도를 회복시켜요.' WHERE id = 'w_sports_C2_15';
UPDATE words SET example_en_2 = 'Bioenergetics examines how the body converts food into athletic output.', example_ko_2 = '생체에너지학은 신체가 음식을 운동 능력으로 변환하는 방법을 연구해요.', example_en_3 = 'She studied bioenergetics to optimise her nutrition around training.', example_ko_3 = '그녀는 훈련에 맞춰 영양을 최적화하기 위해 생체에너지학을 공부했어요.', example_en_4 = 'Understanding bioenergetics allows coaches to tailor training intensities more precisely.', example_ko_4 = '생체에너지학을 이해하면 코치들이 훈련 강도를 더 정밀하게 조정할 수 있어요.', example_en_5 = 'Bioenergetics research informs how long athletes can sustain different intensity levels.', example_ko_5 = '생체에너지학 연구는 선수들이 다양한 강도 수준을 얼마나 오래 유지할 수 있는지 알려줘요.' WHERE id = 'w_sports_C2_16';
UPDATE words SET example_en_2 = 'Catabolism of muscle protein increases when caloric intake is insufficient.', example_ko_2 = '칼로리 섭취가 불충분할 때 근육 단백질의 이화 작용이 증가해요.', example_en_3 = 'She managed catabolism by timing protein intake around training sessions.', example_ko_3 = '그녀는 훈련 세션 주변으로 단백질 섭취 시간을 조정해 이화 작용을 관리했어요.', example_en_4 = 'Catabolism during illness can lead to significant muscle loss in athletes.', example_ko_4 = '병중의 이화 작용은 선수들에게 상당한 근육 손실을 가져올 수 있어요.', example_en_5 = 'Balancing catabolism and anabolism is fundamental to athletic body composition management.', example_ko_5 = '이화 작용과 동화 작용의 균형은 운동선수의 체성분 관리의 기본이에요.' WHERE id = 'w_sports_C2_17';
UPDATE words SET example_en_2 = 'Anabolism is stimulated by resistance training and adequate protein intake.', example_ko_2 = '동화 작용은 저항 훈련과 충분한 단백질 섭취에 의해 자극돼요.', example_en_3 = 'She maximised anabolism by consuming protein within thirty minutes of training.', example_ko_3 = '그녀는 훈련 30분 이내에 단백질을 섭취해 동화 작용을 최대화했어요.', example_en_4 = 'Anabolism supports muscle repair and growth following intense exercise.', example_ko_4 = '동화 작용은 격렬한 운동 후 근육 회복과 성장을 지원해요.', example_en_5 = 'Sleep is a critically anabolic period during which growth hormone is released.', example_ko_5 = '수면은 성장 호르몬이 분비되는 매우 중요한 동화 시간이에요.' WHERE id = 'w_sports_C2_18';
UPDATE words SET example_en_2 = 'The periodicity of the training plan matched the competition calendar.', example_ko_2 = '훈련 계획의 주기성은 대회 일정과 맞았어요.', example_en_3 = 'She adjusted the periodicity of her loading cycles based on race dates.', example_ko_3 = '그녀는 경주 날짜에 맞춰 부하 사이클의 주기성을 조정했어요.', example_en_4 = 'Periodicity in training ensures athletes peak at the right moments.', example_ko_4 = '훈련의 주기성은 선수들이 적절한 시기에 최고 상태에 도달하게 해요.', example_en_5 = 'Understanding the periodicity of hormonal fluctuations can improve training outcomes.', example_ko_5 = '호르몬 변동의 주기성을 이해하면 훈련 결과를 향상시킬 수 있어요.' WHERE id = 'w_sports_C2_19';
UPDATE words SET example_en_2 = 'Dopamine is a neurotransmitter associated with motivation and reward in athletes.', example_ko_2 = '도파민은 선수들의 동기와 보상과 관련된 신경전달물질이에요.', example_en_3 = 'She studied how neurotransmitter levels change with overtraining.', example_ko_3 = '그녀는 과훈련으로 신경전달물질 수준이 어떻게 변화하는지 연구했어요.', example_en_4 = 'Neurotransmitter balance affects mood, focus, and competitive drive.', example_ko_4 = '신경전달물질 균형은 기분, 집중력, 그리고 경쟁 의욕에 영향을 미쳐요.', example_en_5 = 'Research links serotonin neurotransmitter activity to perceived effort during endurance exercise.', example_ko_5 = '연구에 따르면 세로토닌 신경전달물질 활동은 지구력 운동 중 인지된 노력과 연관돼요.' WHERE id = 'w_sports_C2_20';
UPDATE words SET example_en_2 = 'Proprioceptive training restores balance after ligament reconstruction.', example_ko_2 = '고유수용성 훈련은 인대 재건 후 균형을 회복시켜요.', example_en_3 = 'She designed a proprioceptive circuit to reduce re-injury risk.', example_ko_3 = '그녀는 재부상 위험을 줄이기 위해 고유수용성 회로를 설계했어요.', example_en_4 = 'Proprioceptive feedback is essential for coordinated multi-joint movements.', example_ko_4 = '고유수용성 피드백은 협응된 다관절 움직임에 필수적이에요.', example_en_5 = 'Proprioceptive deficits following injury must be addressed before return to full training.', example_ko_5 = '부상 후 고유수용성 결핍은 완전 훈련 복귀 전에 해결돼야 해요.' WHERE id = 'w_sports_C2_21';
UPDATE words SET example_en_2 = 'Viscoelastic properties of tendons allow them to store and release energy.', example_ko_2 = '힘줄의 점탄성 특성은 에너지를 저장하고 방출할 수 있게 해줘요.', example_en_3 = 'She studied viscoelastic behaviour to understand how tendons adapt to load.', example_ko_3 = '그녀는 힘줄이 부하에 어떻게 적응하는지 이해하기 위해 점탄성 거동을 연구했어요.', example_en_4 = 'Viscoelastic materials in shoe soles help absorb impact during running.', example_ko_4 = '신발 밑창의 점탄성 재료는 달리기 중 충격을 흡수하는 데 도움이 돼요.', example_en_5 = 'The viscoelastic nature of muscle-tendon units enables efficient energy recycling during locomotion.', example_ko_5 = '근육-힘줄 유닛의 점탄성 특성은 운동 중 효율적인 에너지 재활용을 가능하게 해요.' WHERE id = 'w_sports_C2_22';
UPDATE words SET example_en_2 = 'Mechanotransduction converts mechanical loading into cellular growth signals.', example_ko_2 = '기계신호전달은 기계적 부하를 세포 성장 신호로 변환해요.', example_en_3 = 'She studied mechanotransduction to understand how bone density increases with training.', example_ko_3 = '그녀는 훈련으로 골밀도가 어떻게 증가하는지 이해하기 위해 기계신호전달을 연구했어요.', example_en_4 = 'Mechanotransduction pathways are activated when muscles are exposed to tensile loading.', example_ko_4 = '근육이 장력 부하에 노출될 때 기계신호전달 경로가 활성화돼요.', example_en_5 = 'Understanding mechanotransduction helps explain how progressive overload drives muscle adaptation.', example_ko_5 = '기계신호전달을 이해하면 점진적 과부하가 어떻게 근육 적응을 이끄는지 설명하는 데 도움이 돼요.' WHERE id = 'w_sports_C2_23';
UPDATE words SET example_en_2 = 'Allostasis refers to the body''s ability to maintain stability through change.', example_ko_2 = '알로스타시스는 변화를 통해 안정성을 유지하는 신체의 능력을 말해요.', example_en_3 = 'She studied allostasis to understand how elite athletes cope with prolonged stress.', example_ko_3 = '그녀는 엘리트 선수들이 장기간의 스트레스에 어떻게 대처하는지 이해하기 위해 알로스타시스를 공부했어요.', example_en_4 = 'Allostasis explains why athletes who train consistently develop better stress tolerance.', example_ko_4 = '알로스타시스는 꾸준히 훈련하는 선수들이 왜 더 나은 스트레스 내성을 갖게 되는지 설명해요.', example_en_5 = 'Disrupting allostasis through overtraining leads to a breakdown in performance.', example_ko_5 = '과훈련을 통해 알로스타시스가 무너지면 경기력이 저하돼요.' WHERE id = 'w_sports_C2_24';
UPDATE words SET example_en_2 = 'Proteolysis breaks down damaged muscle proteins after intense exercise.', example_ko_2 = '단백질 분해는 격렬한 운동 후 손상된 근육 단백질을 분해해요.', example_en_3 = 'She monitored proteolysis markers to track muscle breakdown during heavy training.', example_ko_3 = '그녀는 고강도 훈련 중 근육 분해를 추적하기 위해 단백질 분해 지표를 모니터링했어요.', example_en_4 = 'Proteolysis is a natural process essential for muscle remodelling and repair.', example_ko_4 = '단백질 분해는 근육 재형성과 회복에 필수적인 자연적 과정이에요.', example_en_5 = 'Elevated proteolysis in response to caloric restriction can impair muscle mass retention.', example_ko_5 = '칼로리 제한에 반응하는 상승된 단백질 분해는 근육량 유지를 손상시킬 수 있어요.' WHERE id = 'w_sports_C2_25';
UPDATE words SET example_en_2 = 'Morphology describes the form and structure of the body.', example_ko_2 = '형태학은 신체의 형태와 구조를 설명해요.', example_en_3 = 'She studied morphology to understand why certain body types excel in specific sports.', example_ko_3 = '그녀는 왜 특정 체형이 특정 스포츠에서 뛰어난지 이해하기 위해 형태학을 공부했어요.', example_en_4 = 'Muscle morphology changes in response to different types of training stimuli.', example_ko_4 = '근육 형태학은 다양한 유형의 훈련 자극에 반응해 변화해요.', example_en_5 = 'Morphological analysis informs talent identification in youth sport development.', example_ko_5 = '형태학 분석은 유소년 스포츠 개발에서 재능 발굴에 정보를 제공해요.' WHERE id = 'w_sports_C2_26';
UPDATE words SET example_en_2 = 'Fascicle architecture determines a muscle''s force and velocity potential.', example_ko_2 = '근속 구조는 근육의 힘과 속도 잠재력을 결정해요.', example_en_3 = 'She measured fascicle length using ultrasound imaging.', example_ko_3 = '그녀는 초음파 이미징을 사용해 근속 길이를 측정했어요.', example_en_4 = 'Fascicle pennation angle influences how much force a muscle can produce.', example_ko_4 = '근속 우상각은 근육이 얼마나 많은 힘을 생산할 수 있는지에 영향을 미쳐요.', example_en_5 = 'Sprinters typically have longer fascicles than distance runners.', example_ko_5 = '단거리 선수들은 일반적으로 장거리 선수들보다 근속이 더 길어요.' WHERE id = 'w_sports_C2_27';
UPDATE words SET example_en_2 = 'She tested her maximal power on a cycling ergometer.', example_ko_2 = '그녀는 사이클링 에르고미터에서 최대 파워를 테스트했어요.', example_en_3 = 'The ergometer test provides reproducible data for monitoring fitness.', example_ko_3 = '에르고미터 테스트는 체력을 모니터링하기 위한 재현 가능한 데이터를 제공해요.', example_en_4 = 'He used a rowing ergometer to measure anaerobic power output.', example_ko_4 = '그는 무산소 파워 출력을 측정하기 위해 조정 에르고미터를 사용했어요.', example_en_5 = 'Ergometer assessments are widely used in talent screening for endurance sports.', example_ko_5 = '에르고미터 평가는 지구력 스포츠의 재능 심사에서 널리 사용돼요.' WHERE id = 'w_sports_C2_28';
UPDATE words SET example_en_2 = 'Allometric scaling adjusts performance data to account for body size differences.', example_ko_2 = '이형성장 척도 조정은 신체 크기 차이를 고려하기 위해 경기력 데이터를 조정해요.', example_en_3 = 'She applied allometric equations to compare strength outputs across athletes.', example_ko_3 = '그녀는 선수들 간의 근력 출력을 비교하기 위해 이형성장 방정식을 적용했어요.', example_en_4 = 'Allometric scaling reveals that lighter athletes are relatively stronger than their heavier counterparts.', example_ko_4 = '이형성장 척도 조정은 가벼운 선수들이 상대적으로 무거운 선수들보다 더 강하다는 것을 보여줘요.', example_en_5 = 'Without allometric correction, cross-athlete performance comparisons can be misleading.', example_ko_5 = '이형성장 보정 없이는 선수 간 경기력 비교가 오해를 불러일으킬 수 있어요.' WHERE id = 'w_sports_C2_29';
UPDATE words SET example_en_2 = 'Anaerobiosis occurs when oxygen supply cannot meet the demands of intense exercise.', example_ko_2 = '무산소 상태는 산소 공급이 격렬한 운동의 요구를 충족할 수 없을 때 발생해요.', example_en_3 = 'She trained in a low-oxygen environment to simulate anaerobiosis.', example_ko_3 = '그녀는 무산소 상태를 시뮬레이션하기 위해 저산소 환경에서 훈련했어요.', example_en_4 = 'Anaerobiosis leads to rapid lactate accumulation and a burning sensation in muscles.', example_ko_4 = '무산소 상태는 빠른 젖산 축적과 근육의 작열감을 유발해요.', example_en_5 = 'Understanding anaerobiosis helps athletes push their thresholds without crossing into early fatigue.', example_ko_5 = '무산소 상태를 이해하면 선수들이 이른 피로에 빠지지 않으면서 한계를 밀어붙이는 데 도움이 돼요.' WHERE id = 'w_sports_C2_30';
UPDATE words SET example_en_2 = 'Sarcoplasmic hypertrophy increases muscle size without proportional strength gains.', example_ko_2 = '근세포질 비대는 비례적인 근력 향상 없이 근육 크기를 증가시켜요.', example_en_3 = 'She focused on myofibrillar rather than sarcoplasmic hypertrophy to maximise strength.', example_ko_3 = '그녀는 근력을 최대화하기 위해 근세포질 비대보다 근원섬유 비대에 집중했어요.', example_en_4 = 'Sarcoplasmic adaptations are common in bodybuilders using high volume training.', example_ko_4 = '근세포질 적응은 고볼륨 훈련을 사용하는 보디빌더들에게 흔해요.', example_en_5 = 'Understanding sarcoplasmic versus myofibrillar adaptations guides sport-specific training design.', example_ko_5 = '근세포질 대 근원섬유 적응을 이해하면 스포츠별 훈련 설계를 안내해요.' WHERE id = 'w_sports_C2_31';
UPDATE words SET example_en_2 = 'A polyphasic sleep pattern may benefit athletes with very high training loads.', example_ko_2 = '다상성 수면 패턴은 훈련 부하가 매우 높은 선수들에게 도움이 될 수 있어요.', example_en_3 = 'She experimented with a polyphasic schedule to increase total sleep hours.', example_ko_3 = '그녀는 총 수면 시간을 늘리기 위해 다상성 일정을 실험했어요.', example_en_4 = 'Polyphasic approaches remain controversial in mainstream sleep science.', example_ko_4 = '다상성 접근 방식은 주류 수면 과학에서 여전히 논란이 있어요.', example_en_5 = 'Some elite athletes use polyphasic sleep during multi-day competition formats.', example_ko_5 = '일부 엘리트 선수들은 여러 날에 걸친 대회 형식 중에 다상성 수면을 사용해요.' WHERE id = 'w_sports_C2_32';
UPDATE words SET example_en_2 = 'Tensiometry provides objective data on muscle stiffness and readiness.', example_ko_2 = '텐시오메트리는 근육 경직도와 준비 상태에 대한 객관적인 데이터를 제공해요.', example_en_3 = 'She underwent tensiometry testing after each competition to guide recovery.', example_ko_3 = '그녀는 회복을 안내하기 위해 매 대회 후 텐시오메트리 테스트를 받았어요.', example_en_4 = 'Tensiometry is valued for its sensitivity to acute changes in muscle tone.', example_ko_4 = '텐시오메트리는 근육 긴장도의 급성 변화에 대한 민감도로 높이 평가돼요.', example_en_5 = 'Clubs are increasingly adopting tensiometry as a daily monitoring tool for squad readiness.', example_ko_5 = '클럽들은 선수단 준비 상태를 위한 일일 모니터링 도구로 텐시오메트리를 점점 더 채택하고 있어요.' WHERE id = 'w_sports_C2_33';
UPDATE words SET example_en_2 = 'Hemoglobin carries oxygen from the lungs to working muscles.', example_ko_2 = '헤모글로빈은 폐에서 작동하는 근육으로 산소를 운반해요.', example_en_3 = 'She had her hemoglobin levels checked as part of her pre-season health screening.', example_ko_3 = '그녀는 시즌 전 건강 검진의 일환으로 헤모글로빈 수치를 검사받았어요.', example_en_4 = 'Altitude training increases hemoglobin concentration, improving oxygen delivery.', example_ko_4 = '고지 훈련은 헤모글로빈 농도를 높여 산소 전달을 향상시켜요.', example_en_5 = 'Low hemoglobin levels are associated with fatigue and reduced exercise capacity.', example_ko_5 = '낮은 헤모글로빈 수치는 피로와 감소된 운동 능력과 관련이 있어요.' WHERE id = 'w_sports_C2_34';
UPDATE words SET example_en_2 = 'Neuroplasticity allows the brain to adapt to the demands of skill acquisition.', example_ko_2 = '신경가소성은 뇌가 기술 습득의 요구에 적응할 수 있게 해줘요.', example_en_3 = 'She trained consistently to harness neuroplasticity for technical improvement.', example_ko_3 = '그녀는 기술적 향상을 위해 신경가소성을 활용하기 위해 꾸준히 훈련했어요.', example_en_4 = 'Neuroplasticity research has transformed how coaches approach motor skill learning.', example_ko_4 = '신경가소성 연구는 코치들이 운동 기술 학습에 접근하는 방식을 변화시켰어요.', example_en_5 = 'Early sport specialisation exploits neuroplasticity to build deep technical skills.', example_ko_5 = '조기 스포츠 전문화는 깊은 기술 능력을 쌓기 위해 신경가소성을 활용해요.' WHERE id = 'w_sports_C2_35';

-- ── technology ──
-- EngCat Technology Topic — words example sentences (examples 2–5)
