UPDATE words SET example_en_2 = 'I use my computer every day for work.', example_ko_2 = '저는 매일 업무에 컴퓨터를 사용해요.', example_en_3 = 'The computer crashed and I lost my work.', example_ko_3 = '컴퓨터가 다운돼서 작업 내용을 잃어버렸어요.', example_en_4 = 'Can you show me how to use this computer program?', example_ko_4 = '이 컴퓨터 프로그램 사용법을 알려 주실 수 있나요?', example_en_5 = 'She bought a new computer for her studies.', example_ko_5 = '그녀는 공부를 위해 새 컴퓨터를 샀어요.' WHERE id = 'w_technology_A1_01';
