UPDATE words SET example_en_2 = 'Cloud computing allows businesses to scale resources up or down as needed.', example_ko_2 = '클라우드 컴퓨팅은 기업이 필요에 따라 자원을 확장하거나 축소할 수 있게 해줘요.', example_en_3 = 'She migrated the company''s infrastructure to cloud computing to cut costs.', example_ko_3 = '그녀는 비용 절감을 위해 회사 인프라를 클라우드 컴퓨팅으로 이전했어요.', example_en_4 = 'Cloud computing has made it easier for small businesses to access enterprise-level tools.', example_ko_4 = '클라우드 컴퓨팅은 소규모 기업도 엔터프라이즈급 도구에 쉽게 접근할 수 있게 해줬어요.', example_en_5 = 'The main benefit of cloud computing is that you only pay for what you use.', example_ko_5 = '클라우드 컴퓨팅의 주요 장점은 사용한 만큼만 비용을 지불한다는 거예요.' WHERE id = 'w_technology_B2_14';
