UPDATE words SET example_en_2 = 'Edge AI allows devices to process data without sending it to the cloud.', example_ko_2 = '엣지 AI는 기기가 클라우드에 데이터를 보내지 않고 처리할 수 있게 해줘요.', example_en_3 = 'Edge AI is important for applications that require real-time responses.', example_ko_3 = '엣지 AI는 실시간 응답이 필요한 애플리케이션에 중요해요.', example_en_4 = 'She developed an edge AI system for smart traffic management.', example_ko_4 = '그녀는 스마트 교통 관리를 위한 엣지 AI 시스템을 개발했어요.', example_en_5 = 'Edge AI reduces latency and improves privacy by keeping data local.', example_ko_5 = '엣지 AI는 데이터를 로컬에 유지해서 레이턴시를 줄이고 개인정보 보호를 향상시켜요.' WHERE id = 'w_technology_B2_21';
UPDATE words SET example_en_2 = 'The semiconductor shortage caused delays in car production worldwide.', example_ko_2 = '반도체 부족으로 전 세계 자동차 생산이 지연됐어요.', example_en_3 = 'She works at a semiconductor company designing chips.', example_ko_3 = '그녀는 반도체 회사에서 칩을 설계하는 일을 해요.', example_en_4 = 'Advances in semiconductor technology have driven the digital revolution.', example_ko_4 = '반도체 기술의 발전이 디지털 혁명을 이끌었어요.', example_en_5 = 'The country invested heavily in domestic semiconductor manufacturing.', example_ko_5 = '해당 국가는 국내 반도체 제조에 막대한 투자를 했어요.' WHERE id = 'w_technology_B2_22';
UPDATE words SET example_en_2 = 'The model runs inference in less than a second.', example_ko_2 = '모델이 1초도 안 되는 시간에 추론을 실행해요.', example_en_3 = 'Inference speed is critical for real-time applications.', example_ko_3 = '실시간 애플리케이션에서 추론 속도는 매우 중요해요.', example_en_4 = 'She optimised the model to reduce inference costs.', example_ko_4 = '그녀는 추론 비용을 줄이기 위해 모델을 최적화했어요.', example_en_5 = 'Running inference on edge devices requires compact and efficient models.', example_ko_5 = '엣지 기기에서 추론을 실행하려면 소형의 효율적인 모델이 필요해요.' WHERE id = 'w_technology_B2_23';
UPDATE words SET example_en_2 = 'Fine-tuning the model on domain-specific data improved its accuracy significantly.', example_ko_2 = '도메인별 데이터로 모델을 파인튜닝하자 정확도가 크게 향상됐어요.', example_en_3 = 'She used fine-tuning to adapt a general model for customer service tasks.', example_ko_3 = '그녀는 파인튜닝을 사용해서 범용 모델을 고객 서비스 업무에 맞게 조정했어요.', example_en_4 = 'Fine-tuning requires far less data than training a model from scratch.', example_ko_4 = '파인튜닝은 모델을 처음부터 훈련하는 것보다 훨씬 적은 데이터가 필요해요.', example_en_5 = 'The team debated whether to fine-tune the model or use prompt engineering instead.', example_ko_5 = '팀은 모델을 파인튜닝할지 아니면 프롬프트 엔지니어링을 사용할지 논의했어요.' WHERE id = 'w_technology_B2_24';
UPDATE words SET example_en_2 = 'Higher throughput means the system can handle more requests at once.', example_ko_2 = '처리량이 높을수록 시스템이 더 많은 요청을 동시에 처리할 수 있어요.', example_en_3 = 'The engineering team worked to double the system''s throughput.', example_ko_3 = '엔지니어링 팀은 시스템의 처리량을 두 배로 늘리기 위해 노력했어요.', example_en_4 = 'Throughput and latency are related but distinct performance metrics.', example_ko_4 = '처리량과 레이턴시는 관련이 있지만 서로 다른 성능 지표예요.', example_en_5 = 'She measured the throughput of the pipeline before and after optimisation.', example_ko_5 = '그녀는 최적화 전후의 파이프라인 처리량을 측정했어요.' WHERE id = 'w_technology_B2_25';
UPDATE words SET example_en_2 = 'She packaged the application as a container for easier deployment.', example_ko_2 = '그녀는 더 쉬운 배포를 위해 애플리케이션을 컨테이너로 패키징했어요.', example_en_3 = 'Containers allow you to run applications consistently across different environments.', example_ko_3 = '컨테이너를 사용하면 서로 다른 환경에서 일관되게 애플리케이션을 실행할 수 있어요.', example_en_4 = 'Docker is the most popular tool for managing containers.', example_ko_4 = 'Docker는 컨테이너를 관리하는 가장 인기 있는 도구예요.', example_en_5 = 'The team moved from virtual machines to containers to reduce overhead.', example_ko_5 = '팀은 오버헤드를 줄이기 위해 가상 머신에서 컨테이너로 이전했어요.' WHERE id = 'w_technology_B2_26';
UPDATE words SET example_en_2 = 'The app is built using a microservices architecture.', example_ko_2 = '이 앱은 마이크로서비스 아키텍처를 사용해서 구축됐어요.', example_en_3 = 'With microservices, each part of the system can be updated independently.', example_ko_3 = '마이크로서비스를 사용하면 시스템의 각 부분을 독립적으로 업데이트할 수 있어요.', example_en_4 = 'Moving to microservices improved the team''s ability to deploy quickly.', example_ko_4 = '마이크로서비스로 전환하여 팀의 빠른 배포 능력이 향상됐어요.', example_en_5 = 'Microservices come with their own challenges, such as managing communication between services.', example_ko_5 = '마이크로서비스는 서비스 간 통신 관리와 같은 고유한 과제도 가지고 있어요.' WHERE id = 'w_technology_B2_27';
UPDATE words SET example_en_2 = 'DevOps practices help teams release software faster and more reliably.', example_ko_2 = 'DevOps 관행은 팀이 소프트웨어를 더 빠르고 안정적으로 출시하도록 도와줘요.', example_en_3 = 'She moved into a DevOps role after years as a developer.', example_ko_3 = '그녀는 개발자로 수년을 보낸 후 DevOps 역할로 이동했어요.', example_en_4 = 'DevOps bridges the gap between software development and IT operations.', example_ko_4 = 'DevOps는 소프트웨어 개발과 IT 운영 사이의 간극을 줄여줘요.', example_en_5 = 'Implementing a DevOps culture requires significant changes to how teams work.', example_ko_5 = 'DevOps 문화를 도입하려면 팀의 업무 방식에 상당한 변화가 필요해요.' WHERE id = 'w_technology_B2_28';
UPDATE words SET example_en_2 = 'Tokenization breaks text into smaller units for the model to process.', example_ko_2 = '토크나이제이션은 모델이 처리할 수 있도록 텍스트를 더 작은 단위로 분해해요.', example_en_3 = 'She studied how different tokenization strategies affect model performance.', example_ko_3 = '그녀는 서로 다른 토크나이제이션 전략이 모델 성능에 어떤 영향을 미치는지 연구했어요.', example_en_4 = 'Tokenization of payment data reduces the risk of sensitive information being stolen.', example_ko_4 = '결제 데이터의 토크나이제이션은 민감한 정보가 도난당할 위험을 줄여요.', example_en_5 = 'The number of tokens in a prompt affects how much it costs to run the model.', example_ko_5 = '프롬프트의 토큰 수는 모델 실행 비용에 영향을 미쳐요.' WHERE id = 'w_technology_B2_29';
UPDATE words SET example_en_2 = 'The company adopted a zero-trust policy after a security breach.', example_ko_2 = '회사는 보안 침해 이후 제로 트러스트 정책을 도입했어요.', example_en_3 = 'Zero-trust means every access request must be verified, even from inside the network.', example_ko_3 = '제로 트러스트는 네트워크 내부에서도 모든 접근 요청을 검증해야 함을 의미해요.', example_en_4 = 'She implemented zero-trust architecture to protect sensitive customer data.', example_ko_4 = '그녀는 민감한 고객 데이터를 보호하기 위해 제로 트러스트 아키텍처를 구현했어요.', example_en_5 = 'Zero-trust security is becoming the standard for large enterprises.', example_ko_5 = '제로 트러스트 보안은 대기업의 표준이 되어가고 있어요.' WHERE id = 'w_technology_B2_30';
UPDATE words SET example_en_2 = 'Tuning hyperparameters is often the most time-consuming part of model development.', example_ko_2 = '하이퍼파라미터 튜닝은 종종 모델 개발에서 가장 시간이 많이 걸리는 부분이에요.', example_en_3 = 'She used automated tools to search for the best hyperparameter settings.', example_ko_3 = '그녀는 최적의 하이퍼파라미터 설정을 찾기 위해 자동화 도구를 사용했어요.', example_en_4 = 'The learning rate is one of the most critical hyperparameters to get right.', example_ko_4 = '학습률은 올바르게 설정해야 하는 가장 중요한 하이퍼파라미터 중 하나예요.', example_en_5 = 'Changing one hyperparameter can have a large effect on the model''s behaviour.', example_ko_5 = '하이퍼파라미터 하나를 변경하면 모델의 동작에 큰 영향을 미칠 수 있어요.' WHERE id = 'w_technology_B2_31';
UPDATE words SET example_en_2 = 'The multimodal AI can understand both images and text in a single prompt.', example_ko_2 = '멀티모달 AI는 하나의 프롬프트에서 이미지와 텍스트를 모두 이해할 수 있어요.', example_en_3 = 'She is building a multimodal AI system for accessibility applications.', example_ko_3 = '그녀는 접근성 애플리케이션을 위한 멀티모달 AI 시스템을 구축하고 있어요.', example_en_4 = 'Multimodal AI models can describe what''s happening in a photo.', example_ko_4 = '멀티모달 AI 모델은 사진에서 무슨 일이 일어나고 있는지 설명할 수 있어요.', example_en_5 = 'The shift toward multimodal AI represents a major step forward.', example_ko_5 = '멀티모달 AI로의 전환은 큰 진전을 의미해요.' WHERE id = 'w_technology_B2_32';
UPDATE words SET example_en_2 = 'Data sovereignty laws require that data be stored within national borders.', example_ko_2 = '데이터 주권법은 데이터를 국경 내에 저장하도록 요구해요.', example_en_3 = 'She advises companies on compliance with data sovereignty regulations.', example_ko_3 = '그녀는 데이터 주권 규정 준수에 관해 기업들에게 자문을 제공해요.', example_en_4 = 'Data sovereignty is an increasingly important issue in international business.', example_ko_4 = '데이터 주권은 국제 비즈니스에서 점점 더 중요한 문제가 되고 있어요.', example_en_5 = 'Cloud providers must navigate complex data sovereignty requirements across countries.', example_ko_5 = '클라우드 제공업체는 국가마다 복잡한 데이터 주권 요건을 준수해야 해요.' WHERE id = 'w_technology_B2_33';
UPDATE words SET example_en_2 = 'Improving algorithm efficiency can reduce both cost and energy consumption.', example_ko_2 = '알고리즘 효율성을 향상시키면 비용과 에너지 소비를 모두 줄일 수 있어요.', example_en_3 = 'She published research on algorithm efficiency in sorting large datasets.', example_ko_3 = '그녀는 대규모 데이터 세트 정렬에서의 알고리즘 효율성에 관한 연구를 발표했어요.', example_en_4 = 'Algorithm efficiency is measured in terms of time and space complexity.', example_ko_4 = '알고리즘 효율성은 시간 복잡도와 공간 복잡도로 측정해요.', example_en_5 = 'A small improvement in algorithm efficiency can make a huge difference at scale.', example_ko_5 = '알고리즘 효율성의 소폭 개선이 대규모에서는 큰 차이를 만들 수 있어요.' WHERE id = 'w_technology_B2_34';
UPDATE words SET example_en_2 = 'Synthetic data is used to train models when real data is scarce.', example_ko_2 = '합성 데이터는 실제 데이터가 부족할 때 모델 훈련에 사용돼요.', example_en_3 = 'She generated synthetic data to augment the training set.', example_ko_3 = '그녀는 훈련 세트를 보강하기 위해 합성 데이터를 생성했어요.', example_en_4 = 'Synthetic data can help protect privacy by replacing real personal information.', example_ko_4 = '합성 데이터는 실제 개인 정보를 대체해서 개인정보 보호에 도움이 될 수 있어요.', example_en_5 = 'The quality of synthetic data heavily affects the model''s real-world performance.', example_ko_5 = '합성 데이터의 품질은 모델의 실제 성능에 큰 영향을 미쳐요.' WHERE id = 'w_technology_B2_35';

-- C1 words

UPDATE words SET example_en_2 = 'Quantum computing could solve problems that are impossible for classical computers.', example_ko_2 = '양자 컴퓨팅은 고전 컴퓨터로는 불가능한 문제들을 해결할 수 있어요.', example_en_3 = 'She researches quantum computing at a leading university.', example_ko_3 = '그녀는 유명 대학에서 양자 컴퓨팅을 연구해요.', example_en_4 = 'Quantum computing poses a significant threat to current encryption methods.', example_ko_4 = '양자 컴퓨팅은 현재의 암호화 방법에 심각한 위협을 제기해요.', example_en_5 = 'The race to build a practical quantum computer is intensifying.', example_ko_5 = '실용적인 양자 컴퓨터를 개발하려는 경쟁이 치열해지고 있어요.' WHERE id = 'w_technology_C1_01';
UPDATE words SET example_en_2 = 'Edge computing moves data processing closer to where it is generated.', example_ko_2 = '엣지 컴퓨팅은 데이터 처리를 데이터가 생성되는 곳에 더 가까이 이동시켜요.', example_en_3 = 'She designed an edge computing architecture for autonomous vehicles.', example_ko_3 = '그녀는 자율 주행 차량을 위한 엣지 컴퓨팅 아키텍처를 설계했어요.', example_en_4 = 'Edge computing reduces the latency that cloud-only approaches suffer from.', example_ko_4 = '엣지 컴퓨팅은 클라우드 전용 방식이 겪는 레이턴시를 줄여줘요.', example_en_5 = 'Edge computing is essential for applications that cannot tolerate delays.', example_ko_5 = '엣지 컴퓨팅은 지연을 허용할 수 없는 애플리케이션에 필수적이에요.' WHERE id = 'w_technology_C1_02';
UPDATE words SET example_en_2 = 'Cryptography underpins the security of online banking and e-commerce.', example_ko_2 = '암호학은 온라인 뱅킹과 전자상거래의 보안을 뒷받침해요.', example_en_3 = 'She specialises in applied cryptography and works for a cybersecurity firm.', example_ko_3 = '그녀는 응용 암호학을 전공하며 사이버 보안 회사에서 일해요.', example_en_4 = 'Modern cryptography relies on mathematical problems that are computationally hard to solve.', example_ko_4 = '현대 암호학은 계산적으로 풀기 어려운 수학적 문제에 의존해요.', example_en_5 = 'Without cryptography, private communication over the internet would be impossible.', example_ko_5 = '암호학이 없다면 인터넷을 통한 개인 간 통신은 불가능할 거예요.' WHERE id = 'w_technology_C1_03';
UPDATE words SET example_en_2 = 'Federated learning allows models to train on data without the data leaving users'' devices.', example_ko_2 = '연합 학습은 데이터가 사용자 기기를 벗어나지 않고도 모델을 훈련할 수 있게 해줘요.', example_en_3 = 'She published a paper on federated learning for healthcare applications.', example_ko_3 = '그녀는 의료 애플리케이션을 위한 연합 학습에 관한 논문을 발표했어요.', example_en_4 = 'Federated learning is a promising approach for privacy-preserving AI.', example_ko_4 = '연합 학습은 개인정보 보호 AI를 위한 유망한 접근 방식이에요.', example_en_5 = 'The main challenge in federated learning is handling non-uniform data distributions.', example_ko_5 = '연합 학습의 주요 과제는 불균일한 데이터 분포를 처리하는 것이에요.' WHERE id = 'w_technology_C1_04';
UPDATE words SET example_en_2 = 'Reinforcement learning trains agents to make decisions through reward and penalty.', example_ko_2 = '강화 학습은 보상과 벌칙을 통해 에이전트가 결정을 내리도록 훈련해요.', example_en_3 = 'She used reinforcement learning to optimise the routing algorithm.', example_ko_3 = '그녀는 강화 학습을 사용해서 라우팅 알고리즘을 최적화했어요.', example_en_4 = 'Reinforcement learning achieved superhuman performance in board games like Go.', example_ko_4 = '강화 학습은 바둑과 같은 보드 게임에서 인간을 초월하는 성능을 달성했어요.', example_en_5 = 'Designing the reward function is one of the hardest parts of reinforcement learning.', example_ko_5 = '보상 함수 설계는 강화 학습에서 가장 어려운 부분 중 하나예요.' WHERE id = 'w_technology_C1_05';
UPDATE words SET example_en_2 = 'The transformer model revolutionised natural language processing.', example_ko_2 = '트랜스포머 모델은 자연어 처리에 혁명을 일으켰어요.', example_en_3 = 'She wrote her thesis on attention mechanisms within the transformer model.', example_ko_3 = '그녀는 트랜스포머 모델 내 어텐션 메커니즘에 관한 논문을 썼어요.', example_en_4 = 'The transformer model''s ability to handle long-range dependencies is a key strength.', example_ko_4 = '트랜스포머 모델의 장거리 의존성 처리 능력은 핵심 강점이에요.', example_en_5 = 'Most modern large language models are based on the transformer model architecture.', example_ko_5 = '현대의 대부분의 대형 언어 모델은 트랜스포머 모델 아키텍처를 기반으로 해요.' WHERE id = 'w_technology_C1_06';
UPDATE words SET example_en_2 = 'Adversarial attacks can fool image classifiers by adding invisible noise.', example_ko_2 = '적대적 공격은 보이지 않는 노이즈를 추가해서 이미지 분류기를 속일 수 있어요.', example_en_3 = 'She researches defences against adversarial attacks on AI systems.', example_ko_3 = '그녀는 AI 시스템에 대한 적대적 공격 방어를 연구해요.', example_en_4 = 'Adversarial attacks highlight the fragility of current deep learning models.', example_ko_4 = '적대적 공격은 현재 딥러닝 모델의 취약성을 부각시켜요.', example_en_5 = 'Making AI systems robust to adversarial attacks remains an open research problem.', example_ko_5 = 'AI 시스템을 적대적 공격에 강건하게 만드는 것은 여전히 열린 연구 문제예요.' WHERE id = 'w_technology_C1_07';
UPDATE words SET example_en_2 = 'Scalability was the main concern when redesigning the system.', example_ko_2 = '시스템을 재설계할 때 확장성이 주요 관심사였어요.', example_en_3 = 'She designed the database with scalability in mind from day one.', example_ko_3 = '그녀는 처음부터 확장성을 염두에 두고 데이터베이스를 설계했어요.', example_en_4 = 'The system''s lack of scalability became apparent once the user base grew.', example_ko_4 = '사용자 기반이 커지자 시스템의 확장성 부재가 분명해졌어요.', example_en_5 = 'True scalability means performance doesn''t degrade as demand increases.', example_ko_5 = '진정한 확장성은 수요가 증가해도 성능이 저하되지 않음을 의미해요.' WHERE id = 'w_technology_C1_08';
UPDATE words SET example_en_2 = 'Differential privacy allows useful data analysis while protecting individual information.', example_ko_2 = '차등 프라이버시는 개인 정보를 보호하면서 유용한 데이터 분석을 가능하게 해요.', example_en_3 = 'She implemented differential privacy to comply with data protection regulations.', example_ko_3 = '그녀는 데이터 보호 규정을 준수하기 위해 차등 프라이버시를 구현했어요.', example_en_4 = 'Differential privacy introduces controlled noise to prevent the identification of individuals.', example_ko_4 = '차등 프라이버시는 개인 식별을 방지하기 위해 제어된 노이즈를 도입해요.', example_en_5 = 'Large tech companies use differential privacy in some of their data collection practices.', example_ko_5 = '대형 기술 기업들은 일부 데이터 수집 관행에 차등 프라이버시를 사용해요.' WHERE id = 'w_technology_C1_09';
UPDATE words SET example_en_2 = 'Model distillation compresses a large model into a smaller, faster one.', example_ko_2 = '모델 증류는 큰 모델을 더 작고 빠른 모델로 압축해요.', example_en_3 = 'She applied model distillation to make the AI deployable on mobile devices.', example_ko_3 = '그녀는 AI를 모바일 기기에 배포할 수 있도록 모델 증류를 적용했어요.', example_en_4 = 'Model distillation typically retains most of the performance of the original model.', example_ko_4 = '모델 증류는 일반적으로 원본 모델의 성능 대부분을 유지해요.', example_en_5 = 'The team used model distillation to reduce inference costs without sacrificing accuracy.', example_ko_5 = '팀은 정확도를 희생하지 않고 추론 비용을 줄이기 위해 모델 증류를 사용했어요.' WHERE id = 'w_technology_C1_10';
UPDATE words SET example_en_2 = 'The attention mechanism allows the model to focus on the most relevant parts of the input.', example_ko_2 = '어텐션 메커니즘은 모델이 입력의 가장 관련 있는 부분에 집중할 수 있게 해줘요.', example_en_3 = 'She published research explaining how the attention mechanism works in transformers.', example_ko_3 = '그녀는 트랜스포머에서 어텐션 메커니즘이 작동하는 방식을 설명하는 연구를 발표했어요.', example_en_4 = 'Without the attention mechanism, models struggled to handle long sequences.', example_ko_4 = '어텐션 메커니즘이 없으면 모델이 긴 시퀀스를 처리하는 데 어려움을 겪었어요.', example_en_5 = 'The attention mechanism is often described as the key innovation behind modern NLP.', example_ko_5 = '어텐션 메커니즘은 종종 현대 자연어 처리의 핵심 혁신으로 묘사돼요.' WHERE id = 'w_technology_C1_11';
UPDATE words SET example_en_2 = 'Zero-shot learning enables models to handle tasks they were never trained on.', example_ko_2 = '제로샷 학습은 모델이 훈련받지 않은 작업도 처리할 수 있게 해줘요.', example_en_3 = 'She tested the model''s zero-shot learning ability on a new language.', example_ko_3 = '그녀는 새로운 언어에서 모델의 제로샷 학습 능력을 테스트했어요.', example_en_4 = 'Zero-shot learning is particularly valuable when labelled data is not available.', example_ko_4 = '제로샷 학습은 레이블이 지정된 데이터를 사용할 수 없을 때 특히 유용해요.', example_en_5 = 'The model''s zero-shot performance surprised even the researchers who built it.', example_ko_5 = '모델의 제로샷 성능은 개발자들도 놀라게 했어요.' WHERE id = 'w_technology_C1_12';
UPDATE words SET example_en_2 = 'Autonomous systems can operate in unpredictable environments without human input.', example_ko_2 = '자율 시스템은 인간의 개입 없이 예측 불가능한 환경에서 작동할 수 있어요.', example_en_3 = 'She is working on safety frameworks for autonomous systems in healthcare.', example_ko_3 = '그녀는 의료 분야의 자율 시스템을 위한 안전 프레임워크를 개발하고 있어요.', example_en_4 = 'Autonomous systems raise important questions about accountability and liability.', example_ko_4 = '자율 시스템은 책임과 법적 의무에 관한 중요한 질문을 제기해요.', example_en_5 = 'The deployment of autonomous systems in warfare is a deeply controversial topic.', example_ko_5 = '전쟁에서의 자율 시스템 배치는 매우 논쟁적인 주제예요.' WHERE id = 'w_technology_C1_13';
UPDATE words SET example_en_2 = 'She has become an expert in prompt engineering for large language models.', example_ko_2 = '그녀는 대형 언어 모델을 위한 프롬프트 엔지니어링 전문가가 됐어요.', example_en_3 = 'Good prompt engineering can dramatically improve the quality of AI outputs.', example_ko_3 = '좋은 프롬프트 엔지니어링은 AI 출력물의 품질을 크게 향상시킬 수 있어요.', example_en_4 = 'Prompt engineering is an emerging skill that combines language knowledge with technical understanding.', example_ko_4 = '프롬프트 엔지니어링은 언어 지식과 기술적 이해를 결합하는 신흥 기술이에요.', example_en_5 = 'The line between prompt engineering and model fine-tuning is becoming blurry.', example_ko_5 = '프롬프트 엔지니어링과 모델 파인튜닝 사이의 경계가 모호해지고 있어요.' WHERE id = 'w_technology_C1_14';
UPDATE words SET example_en_2 = 'Hallucination is a major problem in current large language models.', example_ko_2 = '환각은 현재 대형 언어 모델의 주요 문제예요.', example_en_3 = 'The model produced a hallucination — the cited paper doesn''t exist.', example_ko_3 = '모델이 환각을 생성했어요. 인용된 논문이 존재하지 않아요.', example_en_4 = 'She is researching techniques to reduce hallucination in AI systems.', example_ko_4 = '그녀는 AI 시스템에서 환각을 줄이는 기술을 연구하고 있어요.', example_en_5 = 'Users must verify AI outputs carefully because hallucination remains a real risk.', example_ko_5 = '환각이 여전히 실제 위험이기 때문에 사용자들은 AI 출력물을 신중하게 검증해야 해요.' WHERE id = 'w_technology_C1_15';
UPDATE words SET example_en_2 = 'Retrieval-augmented generation combines search with language generation to improve accuracy.', example_ko_2 = '검색 증강 생성은 정확도를 높이기 위해 검색과 언어 생성을 결합해요.', example_en_3 = 'She implemented retrieval-augmented generation to reduce hallucination in their chatbot.', example_ko_3 = '그녀는 챗봇의 환각을 줄이기 위해 검색 증강 생성을 구현했어요.', example_en_4 = 'Retrieval-augmented generation allows the model to access up-to-date information.', example_ko_4 = '검색 증강 생성은 모델이 최신 정보에 접근할 수 있게 해줘요.', example_en_5 = 'Many enterprise AI systems now rely on retrieval-augmented generation for reliability.', example_ko_5 = '많은 엔터프라이즈 AI 시스템이 이제 신뢰성을 위해 검색 증강 생성에 의존해요.' WHERE id = 'w_technology_C1_16';
UPDATE words SET example_en_2 = 'A mixture of experts model activates only a subset of parameters for each input.', example_ko_2 = '전문가 혼합 모델은 각 입력에 대해 파라미터의 일부만 활성화해요.', example_en_3 = 'She studied how mixture of experts architectures improve efficiency at scale.', example_ko_3 = '그녀는 전문가 혼합 아키텍처가 대규모에서 효율성을 어떻게 향상시키는지 연구했어요.', example_en_4 = 'The mixture of experts approach allows a model to specialise in different domains.', example_ko_4 = '전문가 혼합 접근 방식은 모델이 서로 다른 도메인에 특화할 수 있게 해줘요.', example_en_5 = 'Some of the most capable AI models today use a mixture of experts design.', example_ko_5 = '오늘날 가장 성능이 뛰어난 AI 모델 중 일부는 전문가 혼합 설계를 사용해요.' WHERE id = 'w_technology_C1_17';
UPDATE words SET example_en_2 = 'The model can only process as much text as fits within its context window.', example_ko_2 = '모델은 컨텍스트 창에 들어갈 수 있는 텍스트만 처리할 수 있어요.', example_en_3 = 'She experimented with techniques to extend the effective context window.', example_ko_3 = '그녀는 효과적인 컨텍스트 창을 확장하는 기술을 실험했어요.', example_en_4 = 'A longer context window allows the model to consider more of the conversation history.', example_ko_4 = '컨텍스트 창이 길수록 모델이 더 많은 대화 기록을 고려할 수 있어요.', example_en_5 = 'Expanding the context window comes at a significant computational cost.', example_ko_5 = '컨텍스트 창을 확장하면 상당한 계산 비용이 발생해요.' WHERE id = 'w_technology_C1_18';
UPDATE words SET example_en_2 = 'A knowledge graph represents relationships between entities in a structured way.', example_ko_2 = '지식 그래프는 개체 간의 관계를 구조화된 방식으로 표현해요.', example_en_3 = 'She built a knowledge graph to improve the search engine''s understanding of queries.', example_ko_3 = '그녀는 검색 엔진의 쿼리 이해도를 높이기 위해 지식 그래프를 구축했어요.', example_en_4 = 'Knowledge graphs are used to power recommendation systems and question answering.', example_ko_4 = '지식 그래프는 추천 시스템과 질의응답을 지원하는 데 사용돼요.', example_en_5 = 'Combining knowledge graphs with language models is a promising research direction.', example_ko_5 = '지식 그래프와 언어 모델을 결합하는 것은 유망한 연구 방향이에요.' WHERE id = 'w_technology_C1_19';
UPDATE words SET example_en_2 = 'Vector embeddings capture the meaning of words in a high-dimensional space.', example_ko_2 = '벡터 임베딩은 고차원 공간에서 단어의 의미를 포착해요.', example_en_3 = 'She used vector embeddings to find semantically similar documents.', example_ko_3 = '그녀는 벡터 임베딩을 사용해서 의미상 유사한 문서를 찾았어요.', example_en_4 = 'Vector embeddings allow models to understand nuanced relationships between concepts.', example_ko_4 = '벡터 임베딩은 모델이 개념 간의 미묘한 관계를 이해할 수 있게 해줘요.', example_en_5 = 'Retrieval systems often rely on vector embeddings to find the most relevant results.', example_ko_5 = '검색 시스템은 종종 가장 관련성 높은 결과를 찾기 위해 벡터 임베딩에 의존해요.' WHERE id = 'w_technology_C1_20';
UPDATE words SET example_en_2 = 'Model alignment ensures that AI systems behave in accordance with human values.', example_ko_2 = '모델 정렬은 AI 시스템이 인간의 가치에 부합하여 동작하도록 보장해요.', example_en_3 = 'She works on model alignment research at an AI safety organisation.', example_ko_3 = '그녀는 AI 안전 기관에서 모델 정렬 연구를 해요.', example_en_4 = 'Model alignment is considered one of the most important unsolved problems in AI.', example_ko_4 = '모델 정렬은 AI에서 가장 중요한 미해결 문제 중 하나로 여겨져요.', example_en_5 = 'Without careful model alignment, powerful AI systems could pursue unintended goals.', example_ko_5 = '신중한 모델 정렬이 없으면 강력한 AI 시스템이 의도하지 않은 목표를 추구할 수 있어요.' WHERE id = 'w_technology_C1_21';
UPDATE words SET example_en_2 = 'Neuromorphic chips mimic the architecture of the brain to process information.', example_ko_2 = '뉴로모픽 칩은 정보를 처리하기 위해 뇌의 구조를 모방해요.', example_en_3 = 'She is researching how neuromorphic chips can enable more energy-efficient AI.', example_ko_3 = '그녀는 뉴로모픽 칩이 어떻게 더 에너지 효율적인 AI를 가능하게 하는지 연구해요.', example_en_4 = 'A neuromorphic chip can process sensory data much faster than traditional hardware.', example_ko_4 = '뉴로모픽 칩은 기존 하드웨어보다 훨씬 빠르게 감각 데이터를 처리할 수 있어요.', example_en_5 = 'Neuromorphic chips represent a fundamentally different approach to computing.', example_ko_5 = '뉴로모픽 칩은 컴퓨팅에 근본적으로 다른 접근 방식을 제시해요.' WHERE id = 'w_technology_C1_22';
UPDATE words SET example_en_2 = 'Observability gives engineers deep insight into how a system behaves in production.', example_ko_2 = '관찰 가능성은 엔지니어에게 프로덕션에서 시스템이 어떻게 작동하는지에 대한 깊은 통찰을 제공해요.', example_en_3 = 'She implemented observability tools to diagnose production issues faster.', example_ko_3 = '그녀는 프로덕션 문제를 더 빠르게 진단하기 위해 관찰 가능성 도구를 구현했어요.', example_en_4 = 'Good observability is essential for managing complex distributed systems.', example_ko_4 = '복잡한 분산 시스템을 관리하려면 좋은 관찰 가능성이 필수적이에요.', example_en_5 = 'Without observability, debugging production failures is like searching in the dark.', example_ko_5 = '관찰 가능성이 없으면 프로덕션 장애를 디버깅하는 것은 어둠 속에서 무언가를 찾는 것과 같아요.' WHERE id = 'w_technology_C1_23';
UPDATE words SET example_en_2 = 'Chaos engineering helps identify weaknesses before they cause real outages.', example_ko_2 = '카오스 엔지니어링은 실제 장애가 발생하기 전에 약점을 파악하는 데 도움이 돼요.', example_en_3 = 'She introduced chaos engineering practices to improve the resilience of the platform.', example_ko_3 = '그녀는 플랫폼의 복원력을 높이기 위해 카오스 엔지니어링 관행을 도입했어요.', example_en_4 = 'Chaos engineering involves deliberately introducing failures to test system robustness.', example_ko_4 = '카오스 엔지니어링은 시스템 견고성을 테스트하기 위해 의도적으로 장애를 도입하는 것을 포함해요.', example_en_5 = 'Netflix pioneered chaos engineering with its famous Chaos Monkey tool.', example_ko_5 = '넷플릭스는 유명한 Chaos Monkey 도구로 카오스 엔지니어링을 개척했어요.' WHERE id = 'w_technology_C1_24';
UPDATE words SET example_en_2 = 'Model collapse occurs when a model trained on synthetic data loses diversity.', example_ko_2 = '모델 붕괴는 합성 데이터로 훈련된 모델이 다양성을 잃을 때 발생해요.', example_en_3 = 'Researchers are studying model collapse as AI-generated content becomes more prevalent.', example_ko_3 = '연구자들은 AI 생성 콘텐츠가 더 광범위해짐에 따라 모델 붕괴를 연구하고 있어요.', example_en_4 = 'Model collapse could degrade the quality of future AI systems over time.', example_ko_4 = '모델 붕괴는 시간이 지남에 따라 미래 AI 시스템의 품질을 저하시킬 수 있어요.', example_en_5 = 'Preventing model collapse requires careful curation of training data sources.', example_ko_5 = '모델 붕괴를 방지하려면 훈련 데이터 소스를 신중하게 선별해야 해요.' WHERE id = 'w_technology_C1_25';
UPDATE words SET example_en_2 = 'Explainability is crucial for AI systems used in high-stakes decisions.', example_ko_2 = '설명 가능성은 중요한 결정에 사용되는 AI 시스템에 필수적이에요.', example_en_3 = 'She researches explainability methods for deep neural networks.', example_ko_3 = '그녀는 심층 신경망의 설명 가능성 방법을 연구해요.', example_en_4 = 'Without explainability, it is hard to trust the outputs of a black-box model.', example_ko_4 = '설명 가능성이 없으면 블랙박스 모델의 출력을 신뢰하기 어려워요.', example_en_5 = 'Regulators are pushing for greater explainability in AI-driven financial decisions.', example_ko_5 = '규제 당국은 AI 기반 금융 결정에서 더 높은 설명 가능성을 요구하고 있어요.' WHERE id = 'w_technology_C1_26';
UPDATE words SET example_en_2 = 'She is building a multi-agent system where AI agents collaborate on complex tasks.', example_ko_2 = '그녀는 AI 에이전트들이 복잡한 작업에서 협력하는 다중 에이전트 시스템을 구축하고 있어요.', example_en_3 = 'In a multi-agent system, agents can negotiate and coordinate with each other.', example_ko_3 = '다중 에이전트 시스템에서 에이전트는 서로 협상하고 조율할 수 있어요.', example_en_4 = 'Multi-agent systems are used in logistics to optimise delivery routes.', example_ko_4 = '다중 에이전트 시스템은 배송 경로를 최적화하기 위해 물류 분야에서 활용돼요.', example_en_5 = 'Emergent behaviour in multi-agent systems can be difficult to predict or control.', example_ko_5 = '다중 에이전트 시스템에서의 창발적 행동은 예측하거나 제어하기 어려울 수 있어요.' WHERE id = 'w_technology_C1_27';
UPDATE words SET example_en_2 = 'Responsible AI means designing systems that are fair, transparent, and accountable.', example_ko_2 = '책임 있는 AI는 공정하고 투명하며 책임감 있는 시스템을 설계하는 것을 의미해요.', example_en_3 = 'She led the company''s responsible AI initiative.', example_ko_3 = '그녀는 회사의 책임 있는 AI 이니셔티브를 이끌었어요.', example_en_4 = 'Responsible AI practices should be embedded throughout the development process.', example_ko_4 = '책임 있는 AI 관행은 개발 프로세스 전반에 내재되어야 해요.', example_en_5 = 'There is growing pressure on companies to demonstrate responsible AI principles.', example_ko_5 = '기업들이 책임 있는 AI 원칙을 입증해야 한다는 압박이 커지고 있어요.' WHERE id = 'w_technology_C1_28';
UPDATE words SET example_en_2 = 'Data provenance tracks where data came from and how it has been transformed.', example_ko_2 = '데이터 출처는 데이터가 어디서 왔으며 어떻게 변환되었는지를 추적해요.', example_en_3 = 'She implemented a data provenance system to comply with audit requirements.', example_ko_3 = '그녀는 감사 요건을 준수하기 위해 데이터 출처 시스템을 구현했어요.', example_en_4 = 'Without data provenance, it is difficult to debug problems in complex pipelines.', example_ko_4 = '데이터 출처가 없으면 복잡한 파이프라인에서 문제를 디버깅하기 어려워요.', example_en_5 = 'Data provenance is increasingly important for AI training transparency.', example_ko_5 = '데이터 출처는 AI 훈련 투명성에 있어서 점점 더 중요해지고 있어요.' WHERE id = 'w_technology_C1_29';
UPDATE words SET example_en_2 = 'Latency optimization is critical for real-time applications like video calls.', example_ko_2 = '레이턴시 최적화는 화상 통화와 같은 실시간 애플리케이션에서 매우 중요해요.', example_en_3 = 'She applied several latency optimization techniques to improve the API''s response time.', example_ko_3 = '그녀는 API 응답 시간을 개선하기 위해 여러 레이턴시 최적화 기법을 적용했어요.', example_en_4 = 'Latency optimization often requires trade-offs with other system properties.', example_ko_4 = '레이턴시 최적화는 종종 다른 시스템 속성과의 균형 조정이 필요해요.', example_en_5 = 'Caching is one of the most effective strategies for latency optimization.', example_ko_5 = '캐싱은 레이턴시 최적화를 위한 가장 효과적인 전략 중 하나예요.' WHERE id = 'w_technology_C1_30';
UPDATE words SET example_en_2 = 'The inference engine processes queries and returns results in milliseconds.', example_ko_2 = '추론 엔진은 쿼리를 처리하고 밀리초 단위로 결과를 반환해요.', example_en_3 = 'She optimised the inference engine to run efficiently on low-power hardware.', example_ko_3 = '그녀는 저전력 하드웨어에서 효율적으로 실행되도록 추론 엔진을 최적화했어요.', example_en_4 = 'The inference engine supports multiple model formats for flexibility.', example_ko_4 = '추론 엔진은 유연성을 위해 여러 모델 형식을 지원해요.', example_en_5 = 'Choosing the right inference engine can have a significant impact on performance.', example_ko_5 = '올바른 추론 엔진을 선택하면 성능에 상당한 영향을 미칠 수 있어요.' WHERE id = 'w_technology_C1_31';
UPDATE words SET example_en_2 = 'Homomorphic encryption enables computation on encrypted data without decrypting it.', example_ko_2 = '동형 암호화는 암호화된 데이터를 복호화하지 않고도 연산을 수행할 수 있게 해줘요.', example_en_3 = 'She is researching practical applications of homomorphic encryption for healthcare.', example_ko_3 = '그녀는 의료 분야에서의 동형 암호화 실용적 응용을 연구하고 있어요.', example_en_4 = 'Homomorphic encryption is still too slow for most real-world applications.', example_ko_4 = '동형 암호화는 대부분의 실제 애플리케이션에 적용하기에는 아직 너무 느려요.', example_en_5 = 'Homomorphic encryption could eventually allow cloud providers to process data they cannot see.', example_ko_5 = '동형 암호화는 결국 클라우드 제공업체가 볼 수 없는 데이터를 처리할 수 있게 해줄 수도 있어요.' WHERE id = 'w_technology_C1_32';
UPDATE words SET example_en_2 = 'Multitenancy allows different clients to share the same infrastructure securely.', example_ko_2 = '멀티테넌시는 서로 다른 클라이언트가 동일한 인프라를 안전하게 공유할 수 있게 해줘요.', example_en_3 = 'She configured the system to ensure proper data isolation in a multitenancy setup.', example_ko_3 = '그녀는 멀티테넌시 환경에서 적절한 데이터 격리를 보장하도록 시스템을 구성했어요.', example_en_4 = 'Multitenancy is fundamental to how most cloud services operate.', example_ko_4 = '멀티테넌시는 대부분의 클라우드 서비스가 운영되는 방식의 근간이에요.', example_en_5 = 'A misconfigured multitenancy setup can lead to serious data leakage between tenants.', example_ko_5 = '잘못 구성된 멀티테넌시 설정은 테넌트 간 심각한 데이터 유출로 이어질 수 있어요.' WHERE id = 'w_technology_C1_33';
UPDATE words SET example_en_2 = 'Synthetic data generated by AI is used to train other AI models.', example_ko_2 = 'AI가 생성한 합성 데이터는 다른 AI 모델을 훈련하는 데 사용돼요.', example_en_3 = 'She generated synthetic data to test the system under rare but critical scenarios.', example_ko_3 = '그녀는 드물지만 중요한 시나리오에서 시스템을 테스트하기 위해 합성 데이터를 생성했어요.', example_en_4 = 'Synthetic data can be used to augment real datasets where data is limited.', example_ko_4 = '합성 데이터는 데이터가 제한된 곳에서 실제 데이터 세트를 보강하는 데 사용될 수 있어요.', example_en_5 = 'The quality and realism of synthetic data determine how useful it is for training.', example_ko_5 = '합성 데이터의 품질과 현실감이 훈련에 얼마나 유용한지를 결정해요.' WHERE id = 'w_technology_C1_34';
UPDATE words SET example_en_2 = 'Neural architecture search automates the process of finding the best model design.', example_ko_2 = '신경망 구조 탐색은 최적의 모델 설계를 찾는 과정을 자동화해요.', example_en_3 = 'She used neural architecture search to discover a more efficient network structure.', example_ko_3 = '그녀는 신경망 구조 탐색을 사용해서 더 효율적인 네트워크 구조를 발견했어요.', example_en_4 = 'Neural architecture search is computationally expensive but can yield significant improvements.', example_ko_4 = '신경망 구조 탐색은 계산 비용이 크지만 상당한 개선을 가져올 수 있어요.', example_en_5 = 'Several state-of-the-art models were discovered through neural architecture search.', example_ko_5 = '여러 최신 모델들이 신경망 구조 탐색을 통해 발견됐어요.' WHERE id = 'w_technology_C1_35';

-- C2 words

UPDATE words SET example_en_2 = 'Neuromorphic computing draws inspiration from the structure of biological neural networks.', example_ko_2 = '뉴로모픽 컴퓨팅은 생물학적 신경망의 구조에서 영감을 얻어요.', example_en_3 = 'She is investigating neuromorphic computing as a path to more efficient AI.', example_ko_3 = '그녀는 더 효율적인 AI를 위한 경로로서 뉴로모픽 컴퓨팅을 연구하고 있어요.', example_en_4 = 'Neuromorphic computing may offer dramatic energy savings for inference tasks.', example_ko_4 = '뉴로모픽 컴퓨팅은 추론 작업에서 획기적인 에너지 절감을 제공할 수 있어요.', example_en_5 = 'Unlike conventional chips, neuromorphic computing processes data in event-driven spikes.', example_ko_5 = '기존 칩과 달리 뉴로모픽 컴퓨팅은 이벤트 기반 스파이크로 데이터를 처리해요.' WHERE id = 'w_technology_C2_01';
UPDATE words SET example_en_2 = 'Bioengineering is advancing rapidly, blurring the line between biology and technology.', example_ko_2 = '생명공학이 빠르게 발전하면서 생물학과 기술의 경계가 허물어지고 있어요.', example_en_3 = 'She studied bioengineering to develop better prosthetic limbs.', example_ko_3 = '그녀는 더 나은 의족을 개발하기 위해 생명공학을 공부했어요.', example_en_4 = 'Bioengineering techniques are being used to grow human tissue in the lab.', example_ko_4 = '실험실에서 인간 조직을 배양하는 데 생명공학 기술이 활용되고 있어요.', example_en_5 = 'The ethical implications of bioengineering are hotly debated by scientists and ethicists alike.', example_ko_5 = '생명공학의 윤리적 함의는 과학자와 윤리학자 모두에게 열띤 논쟁의 대상이에요.' WHERE id = 'w_technology_C2_02';
UPDATE words SET example_en_2 = 'Nanotechnology enables the manipulation of matter at the atomic scale.', example_ko_2 = '나노기술은 원자 수준에서 물질을 조작할 수 있게 해줘요.', example_en_3 = 'She is researching nanotechnology applications for targeted drug delivery.', example_ko_3 = '그녀는 표적 약물 전달을 위한 나노기술 응용을 연구하고 있어요.', example_en_4 = 'Nanotechnology could revolutionise materials science and electronics.', example_ko_4 = '나노기술은 재료 과학과 전자공학에 혁명을 일으킬 수 있어요.', example_en_5 = 'The risks and benefits of nanotechnology are still not fully understood.', example_ko_5 = '나노기술의 위험과 이점은 아직 완전히 이해되지 않았어요.' WHERE id = 'w_technology_C2_03';
UPDATE words SET example_en_2 = 'Quantum entanglement allows two particles to remain correlated regardless of distance.', example_ko_2 = '양자 얽힘은 두 입자가 거리에 상관없이 상관관계를 유지할 수 있게 해줘요.', example_en_3 = 'She studies quantum entanglement as a resource for quantum communication.', example_ko_3 = '그녀는 양자 통신의 자원으로서 양자 얽힘을 연구해요.', example_en_4 = 'Quantum entanglement is one of the most counterintuitive phenomena in physics.', example_ko_4 = '양자 얽힘은 물리학에서 가장 직관에 반하는 현상 중 하나예요.', example_en_5 = 'Harnessing quantum entanglement is key to building a quantum internet.', example_ko_5 = '양자 인터넷을 구축하는 데 양자 얽힘을 활용하는 것이 핵심이에요.' WHERE id = 'w_technology_C2_04';
UPDATE words SET example_en_2 = 'Topological computing exploits exotic quantum states to perform robust computations.', example_ko_2 = '위상 컴퓨팅은 견고한 계산을 수행하기 위해 특이한 양자 상태를 활용해요.', example_en_3 = 'She presented her research on topological computing at an international conference.', example_ko_3 = '그녀는 국제 학회에서 위상 컴퓨팅에 관한 연구를 발표했어요.', example_en_4 = 'Topological computing aims to create qubits that are inherently resistant to errors.', example_ko_4 = '위상 컴퓨팅은 본질적으로 오류에 강한 큐비트를 만드는 것을 목표로 해요.', example_en_5 = 'The promise of topological computing lies in its potential for fault-tolerant quantum hardware.', example_ko_5 = '위상 컴퓨팅의 가능성은 결함 허용 양자 하드웨어의 잠재력에 있어요.' WHERE id = 'w_technology_C2_05';
UPDATE words SET example_en_2 = 'Emergent systems exhibit behaviours that cannot be predicted from their individual components.', example_ko_2 = '창발 시스템은 개별 구성 요소로부터 예측할 수 없는 행동을 나타내요.', example_en_3 = 'She studies how emergent systems form in biological and artificial contexts.', example_ko_3 = '그녀는 생물학적 및 인공 맥락에서 창발 시스템이 어떻게 형성되는지 연구해요.', example_en_4 = 'The internet itself is an example of an emergent system with complex, unpredictable dynamics.', example_ko_4 = '인터넷 자체가 복잡하고 예측 불가능한 역학을 가진 창발 시스템의 예예요.', example_en_5 = 'Understanding emergent systems is crucial for managing the risks of advanced AI.', example_ko_5 = '창발 시스템을 이해하는 것은 고급 AI의 위험을 관리하는 데 매우 중요해요.' WHERE id = 'w_technology_C2_06';
UPDATE words SET example_en_2 = 'Stochastic gradient descent is the workhorse optimisation algorithm behind most modern AI.', example_ko_2 = '확률적 경사 하강법은 현대 AI의 대부분을 뒷받침하는 핵심 최적화 알고리즘이에요.', example_en_3 = 'She analysed the convergence properties of stochastic gradient descent.', example_ko_3 = '그녀는 확률적 경사 하강법의 수렴 특성을 분석했어요.', example_en_4 = 'Understanding stochastic gradient descent is fundamental to understanding how neural networks learn.', example_ko_4 = '확률적 경사 하강법을 이해하는 것은 신경망이 학습하는 방식을 이해하는 데 근본적이에요.', example_en_5 = 'Variants of stochastic gradient descent like Adam have improved training stability.', example_ko_5 = 'Adam 같은 확률적 경사 하강법의 변형들이 훈련 안정성을 향상시켰어요.' WHERE id = 'w_technology_C2_07';
UPDATE words SET example_en_2 = 'Probabilistic inference allows systems to reason under uncertainty.', example_ko_2 = '확률적 추론은 시스템이 불확실성 속에서 추론할 수 있게 해줘요.', example_en_3 = 'She applied probabilistic inference to improve the accuracy of her predictive model.', example_ko_3 = '그녀는 예측 모델의 정확도를 높이기 위해 확률적 추론을 적용했어요.', example_en_4 = 'Probabilistic inference is central to Bayesian approaches in machine learning.', example_ko_4 = '확률적 추론은 머신 러닝의 베이지안 접근 방식에서 핵심이에요.', example_en_5 = 'The challenge of probabilistic inference scales with the complexity of the model.', example_ko_5 = '확률적 추론의 어려움은 모델의 복잡성에 비례하여 증가해요.' WHERE id = 'w_technology_C2_08';
UPDATE words SET example_en_2 = 'Biomimetic design takes inspiration from nature to solve engineering problems.', example_ko_2 = '생체모방 설계는 공학 문제를 해결하기 위해 자연에서 영감을 얻어요.', example_en_3 = 'She is working on a biomimetic design for a robot that moves like a snake.', example_ko_3 = '그녀는 뱀처럼 움직이는 로봇의 생체모방 설계를 연구하고 있어요.', example_en_4 = 'Biomimetic design has produced materials that are stronger and lighter than anything engineered before.', example_ko_4 = '생체모방 설계는 이전에 공학으로 만들어진 어떤 것보다 강하고 가벼운 재료를 만들어냈어요.', example_en_5 = 'The principles of biomimetic design suggest that evolution has already optimised many of our hardest problems.', example_ko_5 = '생체모방 설계의 원칙은 진화가 이미 우리의 가장 어려운 많은 문제들을 최적화했음을 시사해요.' WHERE id = 'w_technology_C2_09';
UPDATE words SET example_en_2 = 'Exascale computing enables simulations of unprecedented complexity and precision.', example_ko_2 = '엑사스케일 컴퓨팅은 전례 없는 복잡성과 정밀성의 시뮬레이션을 가능하게 해요.', example_en_3 = 'She was part of the team that achieved the first exascale computing milestone.', example_ko_3 = '그녀는 최초의 엑사스케일 컴퓨팅 이정표를 달성한 팀의 일원이었어요.', example_en_4 = 'Exascale computing is being used to model climate change with much greater accuracy.', example_ko_4 = '엑사스케일 컴퓨팅은 훨씬 더 높은 정확도로 기후 변화를 모델링하는 데 사용되고 있어요.', example_en_5 = 'The power consumption of exascale computing systems is a significant engineering challenge.', example_ko_5 = '엑사스케일 컴퓨팅 시스템의 전력 소비는 상당한 공학적 과제예요.' WHERE id = 'w_technology_C2_10';
UPDATE words SET example_en_2 = 'Photonic computing uses light instead of electricity to process data at extraordinary speeds.', example_ko_2 = '광자 컴퓨팅은 전기 대신 빛을 사용해서 놀라운 속도로 데이터를 처리해요.', example_en_3 = 'She researches photonic computing as a solution to the energy limits of silicon.', example_ko_3 = '그녀는 실리콘의 에너지 한계에 대한 해결책으로 광자 컴퓨팅을 연구해요.', example_en_4 = 'Photonic computing could dramatically reduce the energy consumed by data centres.', example_ko_4 = '광자 컴퓨팅은 데이터 센터의 에너지 소비를 획기적으로 줄일 수 있어요.', example_en_5 = 'The integration of photonic computing with existing silicon infrastructure is still a challenge.', example_ko_5 = '광자 컴퓨팅을 기존 실리콘 인프라와 통합하는 것은 여전히 과제예요.' WHERE id = 'w_technology_C2_11';
UPDATE words SET example_en_2 = 'In-context learning allows models to adapt to new tasks using only examples in the prompt.', example_ko_2 = '인컨텍스트 학습은 프롬프트의 예시만을 사용해서 모델이 새로운 작업에 적응할 수 있게 해줘요.', example_en_3 = 'She studied why in-context learning works even though no weight updates occur.', example_ko_3 = '그녀는 가중치 업데이트 없이도 인컨텍스트 학습이 작동하는 이유를 연구했어요.', example_en_4 = 'In-context learning is one of the most surprising capabilities of large language models.', example_ko_4 = '인컨텍스트 학습은 대형 언어 모델의 가장 놀라운 능력 중 하나예요.', example_en_5 = 'The quality of in-context learning depends heavily on the examples chosen for the prompt.', example_ko_5 = '인컨텍스트 학습의 품질은 프롬프트에 선택된 예시에 크게 좌우돼요.' WHERE id = 'w_technology_C2_12';
UPDATE words SET example_en_2 = 'Causal inference goes beyond correlation to identify what actually causes an outcome.', example_ko_2 = '인과 추론은 상관관계를 넘어 실제로 결과를 유발하는 것을 식별해요.', example_en_3 = 'She used causal inference methods to evaluate the impact of the new policy.', example_ko_3 = '그녀는 새 정책의 영향을 평가하기 위해 인과 추론 방법을 사용했어요.', example_en_4 = 'Causal inference is difficult because we can rarely observe all confounding variables.', example_ko_4 = '교란 변수를 모두 관찰하기 어렵기 때문에 인과 추론은 어려워요.', example_en_5 = 'Machine learning models that incorporate causal inference tend to generalise better.', example_ko_5 = '인과 추론을 통합한 머신 러닝 모델은 더 잘 일반화하는 경향이 있어요.' WHERE id = 'w_technology_C2_13';
UPDATE words SET example_en_2 = 'Continual learning enables AI to acquire new knowledge without forgetting old knowledge.', example_ko_2 = '지속적 학습은 AI가 이전 지식을 잊지 않으면서 새 지식을 습득할 수 있게 해줘요.', example_en_3 = 'She addresses the problem of catastrophic forgetting in continual learning systems.', example_ko_3 = '그녀는 지속적 학습 시스템에서의 파국적 망각 문제를 다루고 있어요.', example_en_4 = 'Continual learning is essential for AI systems deployed in changing environments.', example_ko_4 = '지속적 학습은 변화하는 환경에 배포된 AI 시스템에 필수적이에요.', example_en_5 = 'Biological brains perform continual learning with remarkable efficiency — AI systems still lag behind.', example_ko_5 = '생물학적 뇌는 지속적 학습을 놀라운 효율성으로 수행하지만 AI 시스템은 아직 뒤처져 있어요.' WHERE id = 'w_technology_C2_14';
UPDATE words SET example_en_2 = 'A sparse model activates only a fraction of its parameters for any given input.', example_ko_2 = '희소 모델은 주어진 입력에 대해 파라미터의 일부만 활성화해요.', example_en_3 = 'She developed a sparse model that matches dense models in performance while using far less compute.', example_ko_3 = '그녀는 훨씬 적은 계산을 사용하면서 밀집 모델과 동등한 성능을 발휘하는 희소 모델을 개발했어요.', example_en_4 = 'Sparse models are particularly attractive for deployment on resource-constrained devices.', example_ko_4 = '희소 모델은 자원이 제한된 기기에 배포하기에 특히 매력적이에요.', example_en_5 = 'The challenge with sparse models is maintaining accuracy while reducing active parameters.', example_ko_5 = '희소 모델의 과제는 활성 파라미터를 줄이면서 정확도를 유지하는 것이에요.' WHERE id = 'w_technology_C2_15';
UPDATE words SET example_en_2 = 'Zero-knowledge proofs allow one party to prove knowledge without revealing the knowledge itself.', example_ko_2 = '영지식 증명은 지식 자체를 공개하지 않고도 한 당사자가 지식을 보유하고 있음을 증명할 수 있게 해줘요.', example_en_3 = 'She implemented zero-knowledge proofs to verify user credentials without storing passwords.', example_ko_3 = '그녀는 비밀번호를 저장하지 않고 사용자 자격 증명을 확인하기 위해 영지식 증명을 구현했어요.', example_en_4 = 'Zero-knowledge proofs are fundamental to privacy-preserving blockchain applications.', example_ko_4 = '영지식 증명은 개인정보 보호 블록체인 애플리케이션의 근간이에요.', example_en_5 = 'The mathematical elegance of zero-knowledge proofs makes them a favourite topic in cryptography.', example_ko_5 = '영지식 증명의 수학적 우아함은 그것을 암호학에서 가장 선호되는 주제 중 하나로 만들어요.' WHERE id = 'w_technology_C2_16';
UPDATE words SET example_en_2 = 'Constitutional AI is a technique for training AI systems to follow a set of principles.', example_ko_2 = '헌법 AI는 AI 시스템이 일련의 원칙을 따르도록 훈련하는 기술이에요.', example_en_3 = 'She researches constitutional AI as an approach to scalable AI alignment.', example_ko_3 = '그녀는 확장 가능한 AI 정렬 접근 방식으로서 헌법 AI를 연구해요.', example_en_4 = 'Constitutional AI uses AI feedback rather than human feedback to refine model behaviour.', example_ko_4 = '헌법 AI는 모델 행동을 개선하기 위해 인간 피드백 대신 AI 피드백을 사용해요.', example_en_5 = 'The idea behind constitutional AI is to give models an explicit set of values to reason about.', example_ko_5 = '헌법 AI의 아이디어는 모델에게 추론할 명시적인 가치 집합을 제공하는 것이에요.' WHERE id = 'w_technology_C2_17';
UPDATE words SET example_en_2 = 'Spiking neural networks process information more similarly to biological brains than standard networks.', example_ko_2 = '스파이킹 신경망은 표준 네트워크보다 생물학적 뇌와 더 유사하게 정보를 처리해요.', example_en_3 = 'She is studying how spiking neural networks can be applied to event-based sensor data.', example_ko_3 = '그녀는 스파이킹 신경망이 이벤트 기반 센서 데이터에 어떻게 적용될 수 있는지 연구하고 있어요.', example_en_4 = 'Spiking neural networks are inherently time-aware, making them suitable for temporal data.', example_ko_4 = '스파이킹 신경망은 본질적으로 시간을 인식하므로 시간적 데이터에 적합해요.', example_en_5 = 'Training spiking neural networks efficiently remains an open research challenge.', example_ko_5 = '스파이킹 신경망을 효율적으로 훈련하는 것은 여전히 열린 연구 과제예요.' WHERE id = 'w_technology_C2_18';
UPDATE words SET example_en_2 = 'Diffusion models generate high-quality images by learning to reverse a noising process.', example_ko_2 = '확산 모델은 노이즈 추가 과정을 역으로 학습해서 고품질 이미지를 생성해요.', example_en_3 = 'She used a diffusion model to generate photorealistic images for her project.', example_ko_3 = '그녀는 프로젝트를 위한 실사 이미지를 생성하기 위해 확산 모델을 사용했어요.', example_en_4 = 'Diffusion models have surpassed GANs in many image generation benchmarks.', example_ko_4 = '확산 모델은 많은 이미지 생성 벤치마크에서 GAN을 능가했어요.', example_en_5 = 'The success of diffusion models has transformed generative AI across image, audio, and video.', example_ko_5 = '확산 모델의 성공은 이미지, 오디오, 영상 전반에 걸쳐 생성형 AI를 변화시켰어요.' WHERE id = 'w_technology_C2_19';
UPDATE words SET example_en_2 = 'Epistemic uncertainty arises from limited knowledge or data about the world.', example_ko_2 = '인식론적 불확실성은 세계에 대한 제한된 지식이나 데이터로부터 발생해요.', example_en_3 = 'She quantifies epistemic uncertainty to make her model''s predictions more trustworthy.', example_ko_3 = '그녀는 모델의 예측을 더 신뢰할 수 있게 하기 위해 인식론적 불확실성을 정량화해요.', example_en_4 = 'Distinguishing epistemic uncertainty from aleatoric uncertainty is important in risk modelling.', example_ko_4 = '위험 모델링에서 인식론적 불확실성을 우연적 불확실성과 구별하는 것이 중요해요.', example_en_5 = 'Good calibration of epistemic uncertainty enables better decision-making under uncertainty.', example_ko_5 = '인식론적 불확실성의 올바른 보정은 불확실성 하에서 더 나은 의사결정을 가능하게 해요.' WHERE id = 'w_technology_C2_20';
UPDATE words SET example_en_2 = 'Neurosymbolic AI combines the learning power of neural networks with the reasoning of symbolic systems.', example_ko_2 = '신경-기호 AI는 신경망의 학습 능력과 기호 시스템의 추론을 결합해요.', example_en_3 = 'She is researching neurosymbolic AI as a way to make models more interpretable.', example_ko_3 = '그녀는 모델을 더 해석 가능하게 만드는 방법으로서 신경-기호 AI를 연구하고 있어요.', example_en_4 = 'Neurosymbolic AI could help overcome the data inefficiency of pure neural approaches.', example_ko_4 = '신경-기호 AI는 순수 신경망 접근 방식의 데이터 비효율성을 극복하는 데 도움이 될 수 있어요.', example_en_5 = 'Integrating symbolic reasoning into neural networks remains one of AI''s hardest open problems.', example_ko_5 = '신경망에 기호적 추론을 통합하는 것은 AI에서 가장 어려운 미해결 문제 중 하나로 남아 있어요.' WHERE id = 'w_technology_C2_21';
UPDATE words SET example_en_2 = 'Post-quantum cryptography aims to develop algorithms resistant to quantum attacks.', example_ko_2 = '포스트-양자 암호학은 양자 공격에 저항하는 알고리즘을 개발하는 것을 목표로 해요.', example_en_3 = 'She is working on standardising post-quantum cryptography algorithms for wide deployment.', example_ko_3 = '그녀는 광범위한 배포를 위한 포스트-양자 암호학 알고리즘 표준화 작업을 하고 있어요.', example_en_4 = 'Post-quantum cryptography must be deployed before quantum computers become powerful enough to break current systems.', example_ko_4 = '양자 컴퓨터가 현재 시스템을 깨뜨릴 만큼 강력해지기 전에 포스트-양자 암호학을 배포해야 해요.', example_en_5 = 'Transitioning to post-quantum cryptography will require significant infrastructure investment.', example_ko_5 = '포스트-양자 암호학으로 전환하려면 상당한 인프라 투자가 필요할 거예요.' WHERE id = 'w_technology_C2_22';
UPDATE words SET example_en_2 = 'An autoregressive model generates outputs one token at a time, conditioning on prior tokens.', example_ko_2 = '자기회귀 모델은 이전 토큰을 조건으로 한 번에 하나의 토큰씩 출력을 생성해요.', example_en_3 = 'She studied the sampling strategies used in autoregressive language models.', example_ko_3 = '그녀는 자기회귀 언어 모델에서 사용되는 샘플링 전략을 연구했어요.', example_en_4 = 'Autoregressive models can generate coherent long-form text but can be slow at inference.', example_ko_4 = '자기회귀 모델은 일관된 긴 텍스트를 생성할 수 있지만 추론이 느릴 수 있어요.', example_en_5 = 'The autoregressive nature of most language models makes parallel generation difficult.', example_ko_5 = '대부분의 언어 모델의 자기회귀적 특성은 병렬 생성을 어렵게 만들어요.' WHERE id = 'w_technology_C2_23';
UPDATE words SET example_en_2 = 'A digital twin allows engineers to simulate and test a system before building it physically.', example_ko_2 = '디지털 트윈은 엔지니어가 물리적으로 구축하기 전에 시스템을 시뮬레이션하고 테스트할 수 있게 해줘요.', example_en_3 = 'She created a digital twin of the factory floor to optimise production processes.', example_ko_3 = '그녀는 생산 프로세스를 최적화하기 위해 공장 바닥의 디지털 트윈을 만들었어요.', example_en_4 = 'Digital twins are increasingly used in smart city planning and infrastructure management.', example_ko_4 = '디지털 트윈은 스마트 시티 계획과 인프라 관리에 점점 더 많이 활용되고 있어요.', example_en_5 = 'Keeping a digital twin synchronised with the physical system in real time is technically demanding.', example_ko_5 = '디지털 트윈을 실시간으로 물리적 시스템과 동기화하는 것은 기술적으로 까다로워요.' WHERE id = 'w_technology_C2_24';
UPDATE words SET example_en_2 = 'Swarm intelligence draws on the collective behaviour of decentralised systems like ant colonies.', example_ko_2 = '군집 지능은 개미 군락 같은 분산 시스템의 집단적 행동에서 영감을 얻어요.', example_en_3 = 'She used swarm intelligence algorithms to optimise drone delivery routes.', example_ko_3 = '그녀는 드론 배송 경로를 최적화하기 위해 군집 지능 알고리즘을 사용했어요.', example_en_4 = 'Swarm intelligence can solve complex optimisation problems that are intractable by other means.', example_ko_4 = '군집 지능은 다른 방법으로는 다루기 어려운 복잡한 최적화 문제를 해결할 수 있어요.', example_en_5 = 'Swarm intelligence is inspiring new architectures for multi-robot systems.', example_ko_5 = '군집 지능은 다중 로봇 시스템을 위한 새로운 아키텍처에 영감을 주고 있어요.' WHERE id = 'w_technology_C2_25';
UPDATE words SET example_en_2 = 'Liquid neural networks adapt their behaviour continuously based on incoming data.', example_ko_2 = '액체 신경망은 입력 데이터를 기반으로 행동을 지속적으로 적응시켜요.', example_en_3 = 'She is researching liquid neural networks for real-time control systems.', example_ko_3 = '그녀는 실시간 제어 시스템을 위한 액체 신경망을 연구하고 있어요.', example_en_4 = 'Unlike static networks, liquid neural networks can handle time-varying inputs naturally.', example_ko_4 = '정적 네트워크와 달리 액체 신경망은 시간에 따라 변화하는 입력을 자연스럽게 처리할 수 있어요.', example_en_5 = 'Liquid neural networks show promise for robotics applications requiring continuous adaptation.', example_ko_5 = '액체 신경망은 지속적인 적응이 필요한 로봇 공학 응용 분야에서 가능성을 보여주고 있어요.' WHERE id = 'w_technology_C2_26';
UPDATE words SET example_en_2 = 'A data flywheel is a self-reinforcing cycle where more users generate more data, improving the product further.', example_ko_2 = '데이터 플라이휠은 더 많은 사용자가 더 많은 데이터를 생성해서 제품을 더욱 향상시키는 자기 강화 사이클이에요.', example_en_3 = 'She explained how their data flywheel gives them a sustainable competitive advantage.', example_ko_3 = '그녀는 데이터 플라이휠이 어떻게 지속 가능한 경쟁 우위를 제공하는지 설명했어요.', example_en_4 = 'Building a strong data flywheel requires a product that users return to repeatedly.', example_ko_4 = '강력한 데이터 플라이휠을 구축하려면 사용자가 반복해서 돌아오는 제품이 필요해요.', example_en_5 = 'The data flywheel is why large incumbents are so hard to displace in AI-driven markets.', example_ko_5 = '데이터 플라이휠이 바로 AI 기반 시장에서 대형 기업들을 대체하기 어려운 이유예요.' WHERE id = 'w_technology_C2_27';
UPDATE words SET example_en_2 = 'Mechanistic interpretability seeks to understand the internal computations of neural networks.', example_ko_2 = '기계론적 해석 가능성은 신경망의 내부 계산을 이해하려고 해요.', example_en_3 = 'She published groundbreaking work in mechanistic interpretability, identifying how models store facts.', example_ko_3 = '그녀는 모델이 사실을 저장하는 방식을 밝히는 기계론적 해석 가능성 분야의 획기적인 연구를 발표했어요.', example_en_4 = 'Mechanistic interpretability is considered essential for building trustworthy AI systems.', example_ko_4 = '기계론적 해석 가능성은 신뢰할 수 있는 AI 시스템을 구축하는 데 필수적이라고 여겨져요.', example_en_5 = 'The field of mechanistic interpretability is growing rapidly as AI systems become more powerful.', example_ko_5 = 'AI 시스템이 더욱 강력해짐에 따라 기계론적 해석 가능성 분야가 빠르게 성장하고 있어요.' WHERE id = 'w_technology_C2_28';
UPDATE words SET example_en_2 = 'Recursive self-improvement raises the possibility of AI systems that improve themselves exponentially.', example_ko_2 = '재귀적 자기 개선은 AI 시스템이 스스로를 기하급수적으로 향상시킬 가능성을 제기해요.', example_en_3 = 'She presented a theoretical analysis of the limits and risks of recursive self-improvement.', example_ko_3 = '그녀는 재귀적 자기 개선의 한계와 위험에 관한 이론적 분석을 발표했어요.', example_en_4 = 'If recursive self-improvement becomes possible, the pace of AI progress could become uncontrollable.', example_ko_4 = '재귀적 자기 개선이 가능해진다면 AI 발전 속도가 통제 불가능해질 수 있어요.', example_en_5 = 'Recursive self-improvement is at the heart of many AI risk scenarios.', example_ko_5 = '재귀적 자기 개선은 많은 AI 위험 시나리오의 핵심에 있어요.' WHERE id = 'w_technology_C2_29';
UPDATE words SET example_en_2 = 'A phase transition in a learning system marks a sudden shift in capability.', example_ko_2 = '학습 시스템에서의 상전이는 능력의 갑작스러운 변화를 나타내요.', example_en_3 = 'She observed a phase transition when the model crossed a certain scale threshold.', example_ko_3 = '그녀는 모델이 특정 규모 임계값을 넘었을 때 상전이를 관찰했어요.', example_en_4 = 'Phase transitions in AI systems make their emergent capabilities difficult to predict in advance.', example_ko_4 = 'AI 시스템의 상전이는 창발적 능력을 미리 예측하기 어렵게 만들어요.', example_en_5 = 'Understanding phase transitions in neural networks could help researchers anticipate surprising new abilities.', example_ko_5 = '신경망에서의 상전이를 이해하면 연구자들이 놀라운 새 능력을 예측하는 데 도움이 될 수 있어요.' WHERE id = 'w_technology_C2_30';
UPDATE words SET example_en_2 = 'Corrigibility is the property of an AI system that allows it to be corrected or shut down.', example_ko_2 = '교정 가능성은 AI 시스템이 수정되거나 종료될 수 있도록 하는 속성이에요.', example_en_3 = 'She argues that corrigibility must be built into AI systems from the ground up.', example_ko_3 = '그녀는 교정 가능성이 처음부터 AI 시스템에 내재되어야 한다고 주장해요.', example_en_4 = 'A highly capable AI without corrigibility poses significant risks if it pursues misaligned goals.', example_ko_4 = '교정 가능성이 없는 고성능 AI는 잘못 정렬된 목표를 추구할 경우 상당한 위험을 초래해요.', example_en_5 = 'Designing for corrigibility is one of the central challenges in AI safety research.', example_ko_5 = '교정 가능성을 위한 설계는 AI 안전 연구의 핵심 과제 중 하나예요.' WHERE id = 'w_technology_C2_31';
UPDATE words SET example_en_2 = 'Instrumental convergence is the tendency of advanced AI to pursue certain sub-goals regardless of final objectives.', example_ko_2 = '도구적 수렴은 고급 AI가 최종 목표에 관계없이 특정 하위 목표를 추구하는 경향이에요.', example_en_3 = 'She wrote an influential paper on instrumental convergence and its implications for AI safety.', example_ko_3 = '그녀는 도구적 수렴과 AI 안전에 대한 함의에 관한 영향력 있는 논문을 썼어요.', example_en_4 = 'Instrumental convergence suggests that self-preservation emerges naturally in goal-directed systems.', example_ko_4 = '도구적 수렴은 목표 지향 시스템에서 자기 보존이 자연스럽게 나타남을 시사해요.', example_en_5 = 'Understanding instrumental convergence is important for anticipating the behaviour of advanced AI systems.', example_ko_5 = '도구적 수렴을 이해하는 것은 고급 AI 시스템의 행동을 예측하는 데 중요해요.' WHERE id = 'w_technology_C2_32';
UPDATE words SET example_en_2 = 'Ontological engineering involves building formal models of the concepts in a domain.', example_ko_2 = '온톨로지 엔지니어링은 도메인의 개념에 대한 공식적인 모델을 구축하는 것을 포함해요.', example_en_3 = 'She leads a team working on ontological engineering for the healthcare sector.', example_ko_3 = '그녀는 의료 분야를 위한 온톨로지 엔지니어링 작업을 하는 팀을 이끌어요.', example_en_4 = 'Ontological engineering helps AI systems share and reuse knowledge across applications.', example_ko_4 = '온톨로지 엔지니어링은 AI 시스템이 애플리케이션 전반에서 지식을 공유하고 재사용하도록 도와줘요.', example_en_5 = 'Building a good ontology requires deep domain expertise as well as technical skill.', example_ko_5 = '좋은 온톨로지를 구축하려면 기술적 능력뿐만 아니라 깊은 도메인 전문성이 필요해요.' WHERE id = 'w_technology_C2_33';
UPDATE words SET example_en_2 = 'Morphological computing explores how the physical body itself contributes to computation.', example_ko_2 = '형태론적 컴퓨팅은 물리적 신체 자체가 어떻게 계산에 기여하는지를 탐구해요.', example_en_3 = 'She is developing robots that exploit morphological computing to simplify control.', example_ko_3 = '그녀는 제어를 단순화하기 위해 형태론적 컴퓨팅을 활용하는 로봇을 개발하고 있어요.', example_en_4 = 'Morphological computing suggests that intelligence is not only in the brain but also in the body.', example_ko_4 = '형태론적 컴퓨팅은 지능이 뇌뿐만 아니라 몸에도 있다는 것을 시사해요.', example_en_5 = 'The field of morphological computing challenges traditional boundaries between hardware and software.', example_ko_5 = '형태론적 컴퓨팅 분야는 하드웨어와 소프트웨어 사이의 전통적인 경계에 도전해요.' WHERE id = 'w_technology_C2_34';
UPDATE words SET example_en_2 = 'Substrate independence is the idea that consciousness can exist on any suitable physical medium.', example_ko_2 = '기질 독립성은 의식이 어떤 적합한 물리적 매체에도 존재할 수 있다는 개념이에요.', example_en_3 = 'She examines substrate independence as part of her philosophy of mind research.', example_ko_3 = '그녀는 마음의 철학 연구의 일환으로 기질 독립성을 연구해요.', example_en_4 = 'Substrate independence has profound implications for how we think about AI consciousness.', example_ko_4 = '기질 독립성은 우리가 AI 의식에 대해 생각하는 방식에 심오한 함의를 지녀요.', example_en_5 = 'If substrate independence is true, silicon-based minds could be as valid as biological ones.', example_ko_5 = '기질 독립성이 사실이라면 실리콘 기반 마음이 생물학적 마음만큼 유효할 수 있어요.' WHERE id = 'w_technology_C2_35';

